INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('zado oficiosa e gratuitamente, na sequência da comunicação ao Instituto dos Registos e do Notariado, I. P., das decisões de inibição e de destituição para efeitos de integração da informação na base de dados de inibições e destituições.
