INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('de 30 de Maio   - Portaria n.º 94/2021, de 29 de Abril
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 1223-A/91, de 30 de Dezembro    - 2ª versão: Portaria n.º 205/93, de 19 de Fevereiro    - 3ª versão: Portaria n.º 175/2005, de 14 de Fevereiro    - 4ª versão: Portaria n.º 116/2014, de 30 de Maio','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:97  
    
  Lei n.º 96/2015, de 17 de Agosto  (versão actualizada) REGULA A DISPONIBILIZAÇÃO E A UTILIZAÇÃO DAS PLATAFORMAS ELETRÓNICAS DE CONTRATAÇÃO PÚBLICA    
    
 
  
                         
                          
SUMÁRIORegula a disponibilização e a utilização das plataformas eletrónicas de contratação pública e transpõe o artigo 29.º da Diretiva 2014/23/UE, o artigo 22.º e o anexo IV da Diretiva 2014/24/UE e o artigo 40.º e o anexo V da Diretiva 2014/25/CE, do Parlamento Europeu e do Conselho, de 26 de fevereiro de 2014, revogando o Decreto-Lei n.º 143-A/2008, de 25 de julho
Lei n.º 96/2015, de 17 de agosto
  Regula a disponibilização e a utilização das plataformas eletrónicas de contratação pública e transpõe o artigo 29.º da Diretiva 2014/23/UE, o artigo 22.º e o anexo IV da Diretiva 2014/24/UE e o artigo 40.º e o anexo V da Diretiva 2014/25/CE, do Parlamento Europeu e do Conselho, de 26 de fevereiro de 2014, revogando o Decreto-Lei n.º 143-A/2008, de 25 de julho.
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:
  
  CAPÍTULO I
  Disposições gerais  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     1 - A presente lei regula a disponibilização e a utilização das plataformas eletrónicas de contratação pública, abreviadamente designadas por plataformas eletrónicas, previstas no Código dos Contratos Públicos (CCP), aprovado pelo Decreto-Lei n.º 18/2008, de 29 de janeiro, estabelecendo os requisitos e as condições a que as mesmas devem obedecer e a obrigação de interoperabilidade com o Portal dos Contratos Públicos e com outros sistemas de entidades públicas.
  2 - A presente lei procede à transposição do artigo 29.º da Diretiva 2014/23/UE, do Parlamento Europeu e do Conselho, de 26 de fevereiro de 2014, do artigo 22.º e do anexo IV da Diretiva 2014/24/UE, do Parlamento Europeu e do Conselho, de 26 de fevereiro de 2014, bem como do artigo 40.º e do anexo V da Diretiva 2014/25/UE, do Parlamento Europeu e do Conselho, de 26 de fevereiro de 2014.            
         
   
     
                         
                          
  Artigo 2.º 
Definições
                            
                           
                             
                               
                             
     Para efeitos da presente lei entende-se por:
  a) Acesso, a obtenção de direitos para visualizar ou processar informação, com base na identificação digital do utilizador, através de um terminal, a um procedimento ou processo a que se refere a informação e o estado ou fase do mesmo;
  b) Empresa gestora, a pessoa coletiva que se encontra apta a exercer, nos termos da presente lei, a atividade de gestão e exploração de plataformas eletrónicas;
  c) Interessados, todos os que manifestam interesse nos procedimentos através da inscrição nos mesmos;
  d','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (') Interoperabilidade, a capacidade das plataformas eletrónicas para permutar informação preservando o seu significado, ou prestar serviços, diretamente e de forma satisfatória, entre os respetivos sistemas e os seus utilizadores, bem como para operar com eles de forma efetiva;
  e) Plataforma eletrónica, a infraestrutura tecnológica constituída por um conjunto de aplicações, meios e serviços informáticos necessários ao funcionamento dos procedimentos eletrónicos de contratação pública nacional, sobre a qual se desenrolam os referidos procedimentos;
  f) Serviços de certificação eletrónica, a disponibilização de certificados qualificados para efeitos de produção de assinaturas eletrónicas qualificadas e de selos temporais de validação cronológica;
  g) Submissão da proposta, submissão da candidatura ou submissão da solução, o momento em que o concorrente ou candidato efetiva a entrega da proposta, da candidatura ou da solução, após o respetivo carregamento em plataforma eletrónica.            
         
   
     
                         
                          
  Artigo 3.º 
Utilização de plataformas electrónicas
                            
                           
                             
                               
                             
     As comunicações, as trocas de dados e de informações processadas através de plataformas eletrónicas nos termos estabelecidos no CCP, bem como o respetivo arquivo, devem obedecer às regras, requisitos e especificações técnicas previstos na presente lei.            
         
   
     
                         
                          
  Artigo 4.º 
Lista das plataformas electrónicas
                            
                           
                             
                               
                             
     A lista atualizada das plataformas eletrónicas licenciadas e das respetivas empresas gestoras é publicitada nos sítios na Internet do Instituto dos Mercados Públicos, do Imobiliário e da Construção, I. P. (IMPIC, I. P.), e do Gabinete Nacional de Segurança (GNS) e no Portal dos Contratos Públicos.            
         
   
     
                         
                          
  Artigo 5.º 
Liberdade de escolha das plataformas electrónicas
                            
                           
                             
                               
                             
     1 - As entidades adjudicantes devem adquirir os serviços de plataformas eletrónicas, de acordo com os procedimentos de formação de contratos estabelecidos no CCP, de entre as plataformas eletrónicas constantes da lista referida no artigo anterior.
  2 - Os operadores económicos escolhem livremente a plataforma eletrónica de contratação pública que pretendem utilizar, para efeitos de participação em procedimentos de formação de contratos públicos, de entre as plataformas eletrónicas licenciadas pelo IMPIC, I. P.            
         
   
     
                    ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
                          
  Artigo 6.º 
Liberdade de escolha dos prestadores e dos serviços de certificação electrónica
                            
                           
                             
                               
                             
     1 - As entidades adjudicantes e os operadores económicos escolhem livremente os prestadores e os serviços de certificação eletrónica que pretendem utilizar no âmbito dos procedimentos de formação de contratos públicos.
  2 - As empresas gestoras devem garantir a aplicabilidade do disposto no número anterior.            
         
   
     
                         
                          
  CAPÍTULO II
  Entidade licenciadora, de monitorização e fiscalizadora, entidade credenciadora e auditores de segurança
  SECÇÃO I
  Entidade licenciadora, de monitorização e fiscalizadora e entidade credenciadora  Artigo 7.º 
Entidade licenciadora, de monitorização e fiscalizadora
                            
                           
                             
                               
                             
     1 - A entidade licenciadora, de monitorização e fiscalizadora das plataformas eletrónicas é o IMPIC, I. P.
  2 - Ao IMPIC, I. P., compete, designadamente:
  a) Coadjuvar o membro do Governo da tutela na definição das linhas estratégicas relacionadas com a contratação pública eletrónica, incluindo a emissão de pareceres e a elaboração de projetos de legislação neste domínio;
  b) Emitir as licenças necessárias ao exercício da atividade de gestão de plataformas eletrónicas;
  c) Assegurar a monitorização e o acompanhamento da atividade das plataformas eletrónicas, nomeadamente através da elaboração de relatórios estatísticos;
  d) Assegurar a fiscalização da atividade das plataformas eletrónicas.            
         
   
     
                         
                          
  Artigo 8.º 
Entidade credenciadora
                            
                           
                             
                               
                             
     1 - A entidade credenciadora das plataformas eletrónicas e dos respetivos auditores de segurança é o GNS.
  2 - Ao GNS compete, para além de outras atribuições previstas na presente lei:
  a) Credenciar os auditores de segurança das plataformas eletrónicas;
  b) Credenciar, na marca nacional e grau confidencial, os membros dos órgãos de administração e fiscalização, os empregados e representantes das empresas gestoras com acesso aos atos e instrumentos de gestão das mesmas, os sócios da sociedade e, tratando-se de sociedade anónima, os acionistas com participação igual ou superior a 10 /prct. do capital da sociedade;
  c) Credenciar as plataformas eletrónicas;
  d) Elaborar normas técnicas;
  e) Identificar as normas internacionais aplicáveis, designadamente as previstas no n.º 3 do artigo 43.º e no n.º 5 do artigo 52.º
  3 - Os pedidos de credenciação previstos na alínea c) do número anterior','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' podem ser apresentados diretamente ao GNS ou, em alternativa, ao IMPIC, I. P., conjuntamente com os pedidos de licenciamento previstos no n.º 1 do artigo 14.º, que os reencaminha, de imediato, ao GNS.            
         
   
     
                         
                          
  SECÇÃO II
  Meios humanos e técnicos  Artigo 9.º 
Estrutura organizativa da empresa gestora
                            
                           
                             
                               
                             
     1 - A estrutura organizativa da empresa gestora, a comprovar perante o GNS, deve contemplar, pelo menos, os seguintes cargos e funções necessários à operação dos sistemas:
  a) Administrador de segurança, com a responsabilidade global de implementar as políticas e práticas de segurança;
  b) Administrador de sistemas, autorizado a instalar, configurar e manter os sistemas, mas com acesso limitado às configurações e aspetos relacionadas com a segurança;
  c) Operador de sistemas, sendo responsável por operar diariamente os sistemas, autorizado a realizar cópias de segurança e operações de rotina;
  d) Auditor de sistemas, autorizado a monitorizar os arquivos de atividade dos sistemas e registo de eventos para auditoria.
  2 - Os postos de trabalho ou funções referidos nas alíneas a), b) e d) do número anterior não podem ser assegurados pela mesma pessoa.
  3 - Todos aqueles que desempenhem funções relacionadas com os procedimentos das plataformas eletrónicas, em especial, os cargos definidos no número anterior, devem estar livres de conflitos de interesse que possam prejudicar a sua imparcialidade no exercício das funções.
  4 - A empresa gestora é responsável por todos os serviços incluídos no âmbito da sua plataforma eletrónica, bem como dos meios humanos pertencentes à sua estrutura organizativa, mesmo quando prestados por terceiros por ela contratados.
  5 - A empresa gestora pode contratar a prestação de serviços tecnológicos e o fornecimento dos respetivos componentes e meios humanos assumindo e mantendo a inteira responsabilidade pelo cumprimento de todos os requisitos exigidos na presente lei.
  6 - São obrigatoriamente reduzidos a escrito os contratos celebrados entre a empresa gestora e qualquer prestador de serviços, onde se estabelecem as obrigações das partes e se identificam os serviços e funções prestadas pelo contratado.            
         
   
     
                         
                          
  Artigo 10.º 
Auditores de segurança
                            
                           
                             
                               
                             
     1 - O auditor de segurança é uma pessoa singular ou coletiva, independente da empresa gestora, de reconhecida idoneidade, experiência e qualificações comprovadas na área de sistemas de informação e de segurança de informação, devidamente credenciado pelo GNS, nos termos da alínea a) do n.º 2 do artigo 8.º
  2 - O audit','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('or de segurança deve garantir que os membros da sua equipa não atuam de forma parcial ou discriminatória e está sujeito aos seguintes impedimentos:
  a) Não realizar auditorias à mesma plataforma eletrónica em mais do que três anos consecutivos;
  b) Não realizar auditorias sempre que se verifique qualquer situação que possa comprometer a sua independência;
  c) Não ter prestado serviços de consultoria à empresa gestora nos últimos três anos, nem manter com esta qualquer outro acordo ou vínculo contratual.
  3 - O auditor de segurança, antes de celebrar qualquer contrato com a empresa gestora, deve solicitar previamente ao GNS, a respetiva autorização, tendo este 30 dias para se pronunciar.
  4 - A autorização a que se refere o número anterior depende, designadamente, da inexistência de qualquer situação de impedimento ou incompatibilidade para o exercício da atividade por parte do auditor.
  5 - Se, da aplicação do n.º 2 resultar que não existem auditores de segurança credenciados pelo GNS disponíveis, o GNS garante a realização da auditoria.            
         
   
     
                         
                          
  SECÇÃO III
  Relatórios de segurança  Artigo 11.º 
Relatório inicial de segurança
                            
                           
                             
                               
                             
     1 - O auditor de segurança, indicado pela empresa gestora, é responsável pela elaboração do relatório inicial de segurança, para efeitos de obtenção da credenciação da plataforma eletrónica.
  2 - O relatório inicial de segurança deve ser elaborado de acordo com as Normas ISO/IEC 20000 e 27001 e englobar obrigatoriamente:
  a) A identificação dos perfis dos técnicos que operam as plataformas eletrónicas, com descrição das respetivas funções;
  b) Uma descrição técnica detalhada da arquitetura e dos sistemas da plataforma eletrónica, contendo uma análise e verificação:
  i) Da conformidade dos certificados digitais utilizados e disponibilizados pelas plataformas eletrónicas;
  ii) Do desempenho dos processos de autenticação e validação de utilizadores;
  iii) Da conformidade dos requisitos de assinatura eletrónica utilizados;
  iv) Dos processos de validação cronológica;
  v) Dos níveis de segurança verificados nos processos de encriptação e desencriptação;
  vi) Dos processos de recuperação de chaves privadas de encriptação;
  vii) Dos processos de custódia de chaves privadas;
  viii) Dos mecanismos de controlo de acessos às plataformas eletrónicas e do funcionamento dos registos de acesso;
  ix) Da operabilidade da plataforma eletrónica em múltiplos sistemas operativos e múltiplos navegadores (browsers);
  x) Do formato standard utilizado para os ficheiros carregados nas plataformas eletrónicas;
  xi) Dos processos de carregamento de documentos;
  xii) Do funcionamento dos mecanismos e meios de segurança, garantia da confidencialidade e integridade das propostas, candidaturas e soluções ap','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('resentadas em procedimentos concorrenciais;
  xiii) Da sincronização dos serviços das plataformas eletrónicas com o serviço de tempo de rede (NTP) definido a partir do tempo universal coordenado (UTC);
  xiv) Das funcionalidades utilizadas para o arquivo e preservação digital, bem como para a interoperabilidade das plataformas eletrónicas, nos termos decorrentes do n.º 3 do artigo 36.º            
         
   
     
                         
                          
  Artigo 12.º 
Relatório anual de segurança
                            
                           
                             
                               
                             
     1 - Para efeitos de manutenção da credenciação da plataforma eletrónica e da sua própria credenciação, o respetivo auditor de segurança deve realizar uma auditoria anual à plataforma eletrónica, de acordo com as Normas ISO/IEC 20000 e 27001, e elaborar o respetivo relatório anual de segurança, que deve ser enviado ao GNS até ao fim do mês de fevereiro de cada ano civil.
  2 - O relatório anual de segurança, para além de conter os elementos referidos no n.º 2 do artigo anterior, deve reportar-se a uma análise de procedimentos de formação dos contratos já concluídos e em curso, através de uma amostragem aleatória, considerada suficiente para a elaboração de um relatório rigoroso e com margens de erro mínimas.
  3 - Se do relatório referido no número anterior resultarem desconformidades, deve a entidade gestora, no prazo de 30 dias, corrigir essas situações.
  4 - Findo o prazo referido no número anterior, o auditor realiza nova auditoria para avaliar a correção das anomalias apontadas.
  5 - Se da nova auditoria resultar que as situações identificadas, ou algumas delas, não foram devidamente corrigidas, deve o facto ser comunicado pelo GNS ao IMPIC, I. P., para que este, após a realização da respetiva audiência prévia, promova o cancelamento da licença, sem prejuízo da efetivação da eventual responsabilidade contraordenacional.
  6 - Verificando-se o cancelamento da licença, nos termos do número anterior, a entidade gestora deve transferir, no prazo de 30 dias, para cada entidade adjudicante, toda a informação e documentação atinente aos respetivos procedimentos de formação de contratos públicos em curso, que devem prosseguir, posteriormente, noutra plataforma eletrónica licenciada pelo IMPIC, I. P.            
         
   
     
                         
                          
  CAPÍTULO III
  Licenciamento da atividade de gestão e exploração de plataformas electrónicas  Artigo 13.º 
Licenciamento para o exercício da actividade
                            
                           
                             
                               
                             
     1 - O exercício da atividade de gestão e exploração, em território nacional, de plataformas eletrónicas, depende de licença a conceder pelo IMPIC, I. P.
  2 - As licenças emitidas pelo IMPIC, I. P., têm valid','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ade de 10 anos, sem prejuízo da verificação anual oficiosa da manutenção dos requisitos gerais de licenciamento e do cancelamento da licença em caso de incumprimento destes requisitos.            
         
   
     
                         
                          
  Artigo 14.º 
Pedidos de licenciamento
                            
                           
                             
                               
                             
     1 - Os pedidos de licenciamento da atividade de gestão e exploração das plataformas eletrónicas são submetidos ao IMPIC, I. P., no respetivo sítio na Internet ou no Balcão do Empreendedor, em formulário próprio aprovado pelo conselho diretivo.
  2 - Caso os pedidos contenham omissões ou deficiências suscetíveis de suprimento ou de correção, ou quando se verifiquem irregularidades ou insuficiências relativas aos documentos instrutórios e cuja falta não possa ser oficiosamente suprida, os requerentes são notificados, no prazo de 10 dias a contar da apresentação, para efetuarem as correções necessárias ou apresentarem os documentos em falta, dentro de um prazo fixado pelo IMPIC, I. P., que não pode ser inferior a 15 dias nem superior a 30 dias, sob pena de indeferimento do pedido.
  3 - Para decidir do pedido, o IMPIC, I. P., dispõe do prazo de 60 dias, a contar da data da receção respetiva ou dos elementos solicitados nos termos do número anterior ou, quando estes não forem entregues, a contar do termo do prazo concedido para a respetiva apresentação.
  4 - Quando o pedido de credenciação é submetido diretamente pelo requerente ao IMPIC, I. P., nos termos do n.º 3 do artigo 8.º, o prazo de decisão referido no número anterior inicia-se após a receção efetiva do comprovativo de credenciação da plataforma eletrónica.
  5 - O projeto da decisão referida no n.º 3 deve ser remetido ao requerente, para efeitos de audiência prévia, nos termos previstos no Código do Procedimento Administrativo.
  6 - A decisão final é notificada ao requerente, no prazo máximo de oito dias, com a guia para o pagamento da taxa devida, caso o pedido seja deferido pelo IMPIC, I. P.
  7 - O pagamento da taxa no prazo fixado na respetiva guia, bem como o pagamento das coimas em dívida pelo requerente, são condição de eficácia do licenciamento.            
         
   
     
                         
                          
  Artigo 15.º 
Requisitos gerais de licenciamento
                            
                           
                             
                               
                             
     O licenciamento para o exercício da atividade de prestação de serviços de utilização de plataformas eletrónicas depende do preenchimento cumulativo, pelos requerentes, dos seguintes requisitos:
  a) A respetiva plataforma eletrónica estar credenciada junto do GNS, nos termos do disposto na alínea c) do n.º 2 do artigo 8.º;
  b) Possuir idoneidade comercial, nos termos do artigo seguinte;
  c) Possuir c','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('apital próprio mínimo, nos termos do artigo 17.º;
  d) Ser titular de um seguro de responsabilidade civil, ou de uma garantia financeira ou instrumento equivalente que o substitua, destinado a assegurar a responsabilidade emergente da sua atividade, nos termos do disposto no artigo 18.º;
  e) Apresentar relatório, em modelo próprio do IMPIC, I. P., emitido pelos representantes legais da empresa gestora, declarando, sob compromisso de honra, o cumprimento, por parte desta, dos requisitos previstos nas secções I e II do capítulo VI.            
         
   
     
                         
                          
  Artigo 16.º 
Idoneidade comercial
                            
                           
                             
                               
                             
     1 - Não são consideradas comercialmente idóneas as empresas gestoras e os respetivos representantes legais que tenham sido declarados insolventes, salvo se tiver sido proferida decisão homologatória de plano de insolvência transitada em julgado.
  2 - As pessoas singulares e as pessoas coletivas e os seus representantes legais que tenham sido proibidos do exercício do comércio, são também considerados, durante o período em que a proibição vigore, como comercialmente não idóneos.
  3 - São ainda considerados como comercialmente não idóneos as pessoas singulares e as pessoas coletivas e os seus representantes legais que tenham sido objeto de três decisões condenatórias definitivas pela prática dolosa de ilícitos de mera ordenação social muito graves, previstos na presente lei.
  4 - Para efeitos do número anterior, são consideradas as condenações de pessoa singular, a título individual ou na qualidade de representante legal de pessoa coletiva, e as condenações de pessoa coletiva de que a pessoa singular tenha sido representante legal.
  5 - Não são considerados idóneos:
  a) As pessoas singulares e os representantes legais de pessoas coletivas que se encontrem em qualquer uma das situações indicadas nos n.os 1, 2 e 3;
  b) As pessoas coletivas que se encontrem em qualquer uma das situações indicadas no n.º 3, bem como aquelas cujos representantes legais sejam considerados não idóneos nos termos do presente artigo e não procedam à respetiva substituição no prazo máximo de 30 dias a contar do conhecimento do facto que determinou a perda de idoneidade.
  6 - Não são considerados comercialmente idóneos os representantes legais de empresas gestoras que tenham sido condenados em pena de prisão efetiva, ainda que suspensa na sua execução, transitada em julgado, pela prática de qualquer dos seguintes crimes:
  a) Burla, burla informática e nas comunicações ou burla relativa a trabalho ou emprego;
  b) Insolvência dolosa, insolvência negligente, favorecimento de credores ou perturbação de arrematações;
  c) Falsificação ou contrafação de documento, quando praticado no âmbito da atividade de gestão de plataformas eletrónicas;
  d) Desobediência, quando praticado','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' no âmbito da atividade de gestão de plataformas eletrónicas;
  e) Corrupção ativa;
  f) Fraude na obtenção de subsídio ou subvenção, desvio de subvenção, subsídio ou crédito bonificado, fraude na obtenção de crédito e ofensa à reputação económica;
  g) Contrafação ou imitação e uso ilegal de marca, quando praticado no âmbito da atividade de gestão de plataformas eletrónicas;
  h) Branqueamento de capitais.
  7 - As condenações referidas no n.º 3 não relevam após o decurso do prazo de três anos contados do cumprimento integral das obrigações decorrentes da aplicação da última sanção.
  8 - A condenação pela prática de um dos crimes previstos no n.º 6 não afeta a idoneidade de todos aqueles cujo registo criminal tenha sido cancelado, a título provisório ou definitivamente, ou relativamente aos quais o IMPIC, I. P., venha a considerar, de forma justificada, que estão reunidas as condições de idoneidade, tendo em conta, nomeadamente, o tempo decorrido desde a prática dos factos.
  9 - Sempre que o IMPIC, I. P., considere existir uma situação de inidoneidade, deve justificar de forma fundamentada as circunstâncias de facto e de direito em que baseia esse juízo de inidoneidade.            
         
   
     
                         
                          
  Artigo 17.º 
Capital próprio
                            
                           
                             
                               
                             
     1 - As empresas gestoras devem estar dotadas de capital próprio, no valor mínimo de (euro) 50 000.
  2 - O capital próprio mínimo previsto no número anterior deve estar integralmente realizado à data do pedido de licenciamento e é condição de manutenção da licença.            
         
   
     
                         
                          
  Artigo 18.º 
Seguro de responsabilidade civil
                            
                           
                             
                               
                             
     1 - O montante mínimo do seguro de responsabilidade civil, a que se refere a alínea d) do artigo 15.º, é de (euro) 150 000, por anuidade.
  2 - O seguro previsto no número anterior, tal como a garantia financeira ou instrumento equivalente que o substituam, podem ser contratados em qualquer Estado do Espaço Económico Europeu, nos termos dos n.os 2 e 3 do artigo 13.º do Decreto-Lei n.º 92/2010, de 26 de julho, devendo, quando o risco esteja localizado em Portugal, satisfazer as condições mínimas fixadas no anexo I à presente lei, que dela faz parte integrante.
  3 - O seguro de responsabilidade civil destina-se ao ressarcimento dos danos patrimoniais causados a terceiros, decorrentes de ações ou omissões das empresas, dos seus representantes e dos seus colaboradores.
  4 - Consideram-se terceiros, para efeitos do presente artigo, todos os que, em resultado de um ato ou omissão praticado pela entidade gestora, venham a sofrer danos patrimoniais, ainda que não tenham sido p','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('arte no respetivo contrato de utilização da plataforma eletrónica.            
         
   
     
                         
                          
  Artigo 19.º 
Cancelamento da licença
                            
                           
                             
                               
                             
     1 - A licença para o exercício da atividade de prestação de serviços de utilização de plataformas eletrónicas é cancelada:
  a) Sempre que o IMPIC, I. P., comprove que a empresa gestora deixou de cumprir qualquer dos requisitos gerais de licenciamento previstos no artigo 15.º;
  b) Quando a empresa gestora cessar a sua atividade em território nacional.
  2 - O projeto de decisão de cancelamento da licença pelos motivos constantes da alínea a) do número anterior deve ser comunicado à empresa gestora, para efeitos de audiência prévia.
  3 - A decisão de cancelamento da licença deve ser comunicada pelo IMPIC, I. P., à empresa gestora e ao GNS, e é publicitada nos sítios na Internet do IMPIC, I. P., e do GNS e no Portal dos Contratos Públicos.
  4 - Verificando-se o cancelamento da licença, nos termos do n.º 1, a empresa gestora deve fornecer ao IMPIC, I. P., no prazo de 15 dias a contar da respetiva ocorrência, cópia eletrónica dos arquivos relativos aos procedimentos de formação de contratos públicos realizados na respetiva plataforma eletrónica, sem prejuízo do disposto no n.º 6 do artigo 12.º            
         
   
     
                         
                          
  CAPÍTULO IV
  Deveres das empresas gestoras  Artigo 20.º 
Deveres gerais
                            
                           
                             
                               
                             
     As empresas gestoras estabelecidas em território nacional devem:
  a) Manter o cumprimento dos requisitos gerais de licenciamento previstos no artigo 15.º;
  b) Cumprir os requisitos funcionais, técnicos e de segurança definidos na presente lei;
  c) Implementar um sistema de gestão de sistemas de informação baseado na Norma ISO/IEC 20000, que abranja toda a infraestrutura tecnológica descrita na alínea e) do artigo 2.º, incluindo o serviço de suporte previsto no artigo 22.º;
  d) Implementar um sistema de gestão de segurança da informação baseado na Norma ISO/IEC 27001, com a abrangência prevista na alínea anterior;
  e) Organizar e conservar em arquivo, pelo período mínimo de 10 anos a contar da respetiva assinatura, cópia de todos os contratos de prestação de serviços celebrados no exercício da atividade;
  f) Dispor de um sistema eletrónico de gestão de reclamações que permita a conservação da informação durante um período mínimo de cinco anos.            
         
   
     
                         
                          
  Artigo 21.º 
Deveres perante o Instituto dos Mercados Públicos, do Imobiliário e da Construção, I. P., e o Gabinete Nacional de Segurança
                            
              ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('             
                             
                               
                             
     1 - As empresas gestoras estabelecidas em território nacional são obrigadas a facultar ao IMPIC, I. P., e ao GNS o acesso às respetivas instalações e aos equipamentos e sistemas conexos com a atividade de gestão da plataforma eletrónica, a prestar-lhes todas as informações, documentação e demais elementos relacionados com a sua atividade que o IMPIC, I. P., ou o GNS lhes solicite, bem como a comunicar-lhes, no prazo de 15 dias a contar da respetiva ocorrência:
  a) Qualquer alteração verificada nos requisitos gerais de licenciamento previstos no artigo 15.º;
  b) A cessação da respetiva atividade em território nacional;
  c) A criação de sucursais, agências, estabelecimentos, locais de atendimento e outras formas de representação comercial da empresa relacionadas com a atividade de gestão de plataformas eletrónicas em território nacional.
  2 - As empresas gestoras estabelecidas em território nacional são também obrigadas a informar o IMPIC, I. P., e o GNS, no prazo de 30 dias a contar de cada uma das respetivas ocorrências, de todas as alterações que impliquem atualização de dados identificativos da empresa, bem como, quando se tratar de sociedades com sede em território nacional ou constituídas ao abrigo da lei portuguesa, de quaisquer modificações introduzidas no respetivo contrato de sociedade.
  3 - As comunicações e informações referidas nos números anteriores são efetuadas pelos meios indicados no n.º 1 do artigo 14.º, sendo a prestação de falsas declarações ou falsas informações punível nos termos da lei.            
         
   
     
                         
                          
  Artigo 22.º 
Deveres perante os utilizadores
                            
                           
                             
                               
                             
     1 - A empresa gestora está obrigada, desde o início do procedimento de formação dos contratos públicos na plataforma eletrónica até à respetiva conclusão, no que respeita às condições técnicas de utilização pelos seus utilizadores:
  a) A intervir e a prestar auxílio, quando necessário ou lhe seja solicitado, no esclarecimento de eventuais dúvidas na utilização da plataforma eletrónica por parte dos representantes da entidade adjudicante ou dos interessados no procedimento de formação do contrato;
  b) A garantir um canal de comunicação com vista à resolução dos problemas específicos que se coloquem, no âmbito do procedimento de formação do contrato;
  c) A disponibilizar relatórios de anomalias, registos de acessos, submissões ou outra informação relevante, sempre que tecnicamente possível, para efeitos de tomada de decisões que surjam nos procedimentos de formação de um contrato público, quando solicitada pelo respetivo júri;
  d) A manter uma linha de apoio aos utilizadores, que permita, no mínimo:
  i) Disponibilizar uma linha telefónica de núm','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ero único 707 para o efeito;
  ii) Assegurar atendimento entre as 9 e as 19 horas, em dias úteis;
  iii) Garantir um nível de atendimento nos termos do Decreto-Lei n.º 134/2009, de 2 de junho, alterado pelo Decreto-Lei n.º 72-A/2010, de 18 de junho.
  2 - Para cumprimento das obrigações previstas no número anterior, a empresa gestora deve disponibilizar na página de entrada da plataforma eletrónica, os seus contactos de suporte e apoio técnico.
  3 - A empresa gestora é ainda obrigada a comunicar aos respetivos utilizadores, com a antecedência mínima de 90 dias, a sua intenção de cessar a atividade de prestação de serviços de gestão da plataforma eletrónica, bem como a indicar a entidade a quem toda a documentação deve ser transmitida.            
         
   
     
                         
                          
  CAPÍTULO V
  Tipos de serviços prestados pelas plataformas electrónicas  Artigo 23.º 
Remuneração pelos serviços prestados
                            
                           
                             
                               
                             
     1 - As empresas gestoras são remuneradas pelas entidades adjudicantes pelo serviço de disponibilização da plataforma eletrónica, pelo apoio à respetiva utilização e outros serviços avançados, conforme contratado entre as partes, de acordo com os procedimentos estabelecidos no CCP, com pleno respeito pelas regras da concorrência estabelecidas na legislação nacional e europeia.
  2 - As empresas gestoras devem proporcionar a qualquer operador económico, pessoa singular ou coletiva, a título gratuito, um mínimo de três acessos, em simultâneo, aos serviços base da respetiva plataforma eletrónica.
  3 - As empresas gestoras apenas podem cobrar aos operadores económicos pelos serviços de disponibilização de mais do que três acessos aos serviços base ou pela prestação de serviços avançados.
  4 - As empresas gestoras devem manter em local público da plataforma eletrónica a tabela de preços de todos os serviços oferecidos, com indicação expressa da sua entrada em vigor, ou última atualização.
  5 - O modelo de remuneração das empresas gestoras, para efeitos de definição das quantias a pagar entre estas, tendo em conta o volume de procedimentos lançados em cada uma das plataformas eletrónicas e o número de operadores económicos que a eles concorrem acedendo através de outras plataformas, é objeto de portaria do membro do Governo que tutela o IMPIC, I. P.            
         
   
     
                         
                          
  Artigo 24.º 
Serviços base prestados aos operadores económicos
                            
                           
                             
                               
                             
     1 - Os serviços base a disponibilizar aos operadores económicos nos termos dos n.os 2 e 3 do artigo anterior, compreendem o acesso a todas as funcionalidades essenciais, mediante contrato de utilização com a plataforma','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' selecionada, que permitam o desenvolvimento total e completo dos procedimentos pré-contratuais públicos, designadamente:
  a) O acesso aos procedimentos e às peças do procedimento que tenham sido publicadas;
  b) O envio de mensagens através da plataforma eletrónica;
  c) O envio de mensagens de correio eletrónico para todos os intervenientes na fase do procedimento de formação de contratos públicos em curso, sempre que, nos termos do CCP, tal comunicação seja obrigatória;
  d) Os pedidos de esclarecimentos e listas de erros e omissões;
  e) A submissão de candidaturas, de propostas e de soluções;
  f) As pronúncias em audiência prévia;
  g) As reclamações e as impugnações;
  h) A decisão de adjudicação;
  i) A entrega de documentos de habilitação;
  j) A visualização de todas as mensagens e avisos criados pelas entidades adjudicantes a que, nos termos da lei, deva ter acesso.
  2 - O acesso aos serviços base da plataforma eletrónica é concedido aos operadores económicos registados numa plataforma.
  3 - Os serviços a prestar pelas empresas gestoras devem satisfazer todas as exigências e condições estabelecidas no CCP e na presente lei, no âmbito de cada uma das fases do procedimento de formação dos contratos públicos.
  4 - A empresa gestora é responsável pela disponibilização das funcionalidades necessárias à aplicação das disposições do CCP e da presente lei, no que respeita à contratação eletrónica em boas condições de segurança, de registo, de fiabilidade e de sustentabilidade.
  5 - O interface com os utilizadores e todas as comunicações e procedimentos realizados nas plataformas eletrónicas são redigidos em língua portuguesa, podendo ser disponibilizado interface adicional noutras línguas.            
         
   
     
                         
                          
  Artigo 25.º 
Serviços avançados prestados aos operadores económicos
                            
                           
                             
                               
                             
     Para efeitos do disposto no n.º 3 do artigo 23.º, são serviços avançados todos os que não sendo necessários para o desenvolvimento total e completo dos procedimentos pré-contratuais públicos, nos termos do artigo anterior, são facultativos, podendo ser prestados pelas plataformas eletrónicas aos operadores económicos mediante contrato e pagamento de um preço.            
         
   
     
                         
                          
  Artigo 26.º 
Cessação da prestação de serviços de gestão e exploração
                            
                           
                             
                               
                             
     Quando a empresa gestora cesse a prestação de serviços contratada, por decisão sua ou de terceiros, por acordo com as entidades adjudicantes que a tiverem contratado, ou por caducidade dos contratos de prestação de serviços, devem os respetivos responsáveis assegurar, sem quaisquer encargos','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' adicionais, que:
  a) A informação constante da mesma, respeitante a procedimentos de contratação pública já concluídos, bem como todos os arquivos de auditoria, transitam, para efeitos de custódia, para as entidades adjudicantes de cada procedimento, devendo ser asseguradas as condições de leitura de todos os documentos;
  b) Os procedimentos de formação de contratos públicos em curso seguem a sua tramitação até à conclusão, sem qualquer encargo adicional para a entidade adjudicante e para os operadores económicos interessados, candidatos e concorrentes.            
         
   
     
                         
                          
  CAPÍTULO VI
  Requisitos funcionais, técnicos e de segurança das plataformas eletrónicas
  SECÇÃO I
  Requisitos funcionais das plataformas electrónicas  Artigo 27.º 
Requisitos das plataformas electrónicas
                            
                           
                             
                               
                             
     Os serviços a prestar pelas plataformas eletrónicas devem satisfazer integralmente todas as exigências e condições estabelecidas no CCP no âmbito de cada uma das fases dos procedimentos de formação dos contratos.            
         
   
     
                         
                          
  Artigo 28.º 
Disponibilização e livre acesso
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem estar disponíveis, não podendo constituir um fator de restrição no acesso dos interessados aos procedimentos de formação de contratos públicos.
  2 - O acesso às plataformas eletrónicas e aos seus instrumentos deve estar permanentemente disponível a todos os interessados, salvo nos casos em que as limitações de acesso se justifiquem por razões de manutenção ou avaria dos sistemas.
  3 - O processo de registo dos operadores económicos nas plataformas eletrónicas, na modalidade gratuita, não pode exceder três dias úteis.
  4 - A manutenção dos dados dos operadores económicos e dos utilizadores deve ser feita pelos próprios utilizadores de forma autónoma e gratuita, excluindo a designação dos operadores económicos, o respetivo número de identificação fiscal e o endereço de correio eletrónico de cada utilizador.
  5 - As operações de manutenção das plataformas eletrónicas que limitem a disponibilidade de serviço, devem ser realizadas entre as 00h00 e as 8h00, nos dias úteis, ou aos sábados, domingos e feriados nacionais, a qualquer hora, com vista a minorar os constrangimentos causados aos utilizadores.
  6 - Salvo em casos de manutenção urgente devidamente justificados, as operações de manutenção referidas no numero anterior devem ser comunicadas aos utilizadores, na página de entrada da respetiva plataforma, com 72 horas de antecedência, e comunicadas ao IMPIC, I. P., no prazo de 24 horas após a sua ocorrência.            
        ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
   
     
                         
                          
  Artigo 29.º 
Não discriminação
                            
                           
                             
                               
                             
     1 - Os instrumentos a utilizar nas plataformas eletrónicas e disponibilizados aos operadores económicos, nomeadamente os produtos, as aplicações e os programas informáticos, bem como as respetivas especificações técnicas, devem ser compatíveis com os produtos, de uso corrente no domínio das tecnologias da informação e da comunicação, designadamente com o Regulamento Nacional de Interoperabilidade Digital (RNID), de forma a evitar situações discriminatórias.
  2 - As empresas gestoras não podem exigir o cumprimento de requisitos injustificados, não proporcionais ou que de forma alguma consubstanciem um fator de discriminação, designadamente para efeitos de acesso ao sistema de contratação da plataforma eletrónica.
  3 - A plataforma eletrónica deve indicar a forma de obter os programas informáticos utilizados, bem como os respetivos comandos e instruções.
  4 - As aplicações e os programas informáticos utilizados nas plataformas eletrónicas devem ser de fácil instalação e utilização, com manual de instalação e utilização, permitindo o acesso a um utilizador com conhecimentos médios nos domínios das tecnologias da informação e comunicação.            
         
   
     
                         
                          
  Artigo 30.º 
Requisitos funcionais
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem garantir, no mínimo, os seguintes requisitos funcionais:
  a) Basear-se em normas abertas, de acordo com o RNID, que não envolvam custos específicos de licenciamento por parte dos utilizadores, disponibilizando as aplicações que permitam efetuar o carregamento dos documentos na plataforma eletrónica;
  b) Garantir que todas as mensagens entre interessados, candidatos, concorrentes e adjudicatários, relativas a pedidos de esclarecimentos, lista de erros e omissões, pronúncias, incluindo os documentos anexos às mesmas, ficam automaticamente disponíveis para visualização daqueles que tenham acesso à fase do procedimento em curso;
  c) Garantir o envio de mensagens de correio eletrónico para todos os intervenientes na fase do procedimento de formação do contrato público em curso, sempre que, nos termos do CCP, tais comunicações sejam obrigatórias;
  d) Garantir o registo do envio das mensagens de correio eletrónico;
  e) Garantir o registo de qualquer ação efetuada pelos diversos utilizadores registados;
  f) Listar, ordenar e exportar para formato XML (Extensible Markup Language) e ou para folha de cálculo em formato ODF (Open Document Format), em todas as fases do procedimento, a informação relevante para a gestão, o reporte e a monitorização, incluindo os meta','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('dados;
  g) Disponibilizar um relatório para verificação e controlo do fluxo do procedimento de acordo com o artigo seguinte;
  h) Permitir a parametrização de procedimentos com diferentes critérios de adjudicação em cada lote;
  i) Suportar a realização de todos os procedimentos de formação de contratos públicos, nos termos previstos no CCP;
  j) Permitir o descarregamento agregado de todos os documentos anexos a mensagens submetidas pelos operadores económicos;
  k) Permitir o descarregamento agregado de todos os documentos, incluindo peças do procedimento, pedidos de esclarecimento sobre as peças, esclarecimentos prestados sobre as peças, listas de erros e omissões, pronúncias sobre erros e omissões, propostas dos concorrentes, pedidos de esclarecimentos sobre as propostas, esclarecimentos prestados sobre as propostas, relatórios do júri e dos serviços competentes da entidade adjudicante, pronúncias em sede de audiência prévia e todas as notificações da entidade adjudicante, por procedimento;
  l) Permitir a utilização de mecanismos de autenticação e assinatura eletrónica com certificados qualificados emitidos por entidades que constem na Trusted-Service Status List, nomeadamente, o constante do cartão de cidadão;
  m) Facultar o acesso ao registo de atividades realizadas nas diversas etapas do processo de contratação, com possibilidade de definição de notificações automáticas de eventos;
  n) Permitir importar mapas de quantidades com múltiplos requisitos (matriz nm) e múltiplos lotes e exportar para formatos XML e ou para folha de cálculo em formato ODF;
  o) Dispor de um relógio/contador relativo à hora oficial portuguesa indicativo do prazo restante, contado nos termos do CCP, para cada fase do procedimento, designadamente, para efetuar pedidos de esclarecimentos, para identificar erros e omissões, para apresentação de propostas, para audiência prévia, para entrega dos documentos de habilitação e aceitação da minuta do contrato e para prestação da caução;
  p) Suportar a realização de leilões eletrónicos invertidos mono e multivariáveis, com uma ou várias rondas, ocultando a identificação dos concorrentes participantes;
  q) Permitir a integração bidirecional com sistemas de informação de gestão das entidades adquirentes, através da plataforma de interoperabilidade da Administração Pública, permitindo o envio de informação para a plataforma de contratação pública e o envio de informação em sentido contrário;
  r) Garantir a possibilidade de auditoria em qualquer momento do processo;
  s) Garantir processo de verificação das características do certificado qualificado para assinatura eletrónica de documentos;
  t) Possibilitar o acesso, por parte da Autoridade da Concorrência, aos dados que permitam a monitorização dos preços apresentados pelos operadores económicos.
  2 - As entidades adjudicantes são livres de, nos documentos que suportam os procedimentos de contratação de plataformas eletrónicas, exigirem requisitos adicionais, designadam','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ente:
  a) Disponibilizar ambiente de pré-produção para realização de testes e formação inicial;
  b) Permitir disponibilização da plataforma eletrónica em subdomínio, no domínio da entidade gestora, definido pela entidade adjudicante;
  c) Permitir, através da plataforma de interoperabilidade da Administração Pública, a recolha de informação relativa aos procedimentos de aquisição no âmbito do Sistema Nacional de Compras Públicas para monitorização dos preços apresentados pelos operadores económicos, nos termos a definir pela Entidade de Serviços Partilhados da Administração Pública, I. P. (ESPAP, I. P.).            
         
   
     
                         
                          
  Artigo 31.º 
Fluxo do procedimento
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas mantêm em vigor um sistema que documenta as várias fases do procedimento conduzido por meios eletrónicos, permitindo, em cada momento, fornecer informação adequada e fidedigna que se revele necessária.
  2 - As plataformas eletrónicas devem disponibilizar as funcionalidades necessárias para o cumprimento desta obrigação de forma a permitir manter os documentos no seu formato original, devidamente conservados, bem como um registo de todas as incidências do procedimento apto a servir de prova, em caso de litígio.
  3 - O sistema referido no n.º 1 deve permitir identificar, entre outras informações:
  a) A entidade e o utilizador que acedeu às peças do procedimento;
  b) A data e hora exatas da submissão dos documentos;
  c) O documento enviado, bem como a entidade e o utilizador que o enviou; e
  d) A duração da comunicação.
  4 - O sistema previsto no presente artigo deve manter-se atualizado, incluindo a informação cronológica nas peças do concurso, até ao ato de adjudicação, sem prejuízo do disposto no artigo 74.º            
         
   
     
                         
                          
  Artigo 32.º 
Impedimentos de acesso à plataforma electrónica
                            
                           
                             
                               
                             
     1 - A entidade adjudicante e a empresa gestora apenas respondem pelos impedimentos de ordem técnica no acesso à plataforma eletrónica que lhes sejam imputáveis, que sejam imputáveis ao sistema em que a plataforma opera ou à própria plataforma.
  2 - Sempre que ocorram problemas técnicos na rede pública ou na plataforma eletrónica que impossibilitem ou tornem excessivamente demorada a prática de qualquer ato que, nos termos do CCP, deva ser praticado na plataforma eletrónica, deve a entidade adjudicante, por iniciativa própria ou a solicitação dos candidatos e concorrentes, tomar todas as medidas necessárias de forma a que os interessados não sejam prejudicados, podendo, nomeadamente, prorrogar o prazo para a prática desses mesmos atos, ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o qual aproveita a todos os candidatos e concorrentes.
  3 - A entidade gestora deve informar, através de anúncio publicado na página de entrada da plataforma eletrónica, em área de acesso livre a todos os interessados, o período de tempo durante o qual a mesma esteve inoperacional.            
         
   
     
                         
                          
  Artigo 33.º 
Informação aos interessados
                            
                           
                             
                               
                             
     As plataformas eletrónicas devem disponibilizar, em local de acesso livre a todos os potenciais interessados, as especificações necessárias exigidas para a realização dos procedimentos de formação dos contratos, designadamente as respeitantes:
  a) A anúncios publicados no Diário da República ou no Jornal Oficial da União Europeia, quando existam;
  b) Às peças do procedimento;
  c) Ao modo de apresentação das candidaturas, soluções e propostas, tal como definido pela entidade adjudicante;
  d) Ao modo e requisitos a que a encriptação de dados deve obedecer;
  e) A assinaturas eletrónicas exigidas e ao modo de as obter, designadamente através da utilização dos certificados do cartão de cidadão;
  f) Aos selos temporais exigidos e ao modo de os obter;
  g) Aos requisitos a que os ficheiros que contêm os documentos das propostas, das candidaturas e das soluções devem obedecer.            
         
   
     
                         
                          
  SECÇÃO II
  Requisitos técnicos das plataformas electrónicas  Artigo 34.º 
Interoperabilidade e compatibilidade
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem cumprir os requisitos de interoperabilidade e compatibilidade previstos no RNID.
  2 - As plataformas eletrónicas devem ter a capacidade para permitir o intercâmbio generalizado de dados, nomeadamente entre diferentes formatos e aplicações ou entre níveis diferentes de desempenho, respeitando os requisitos fixados e atualizados, sempre que razões de ordem tecnológica tal justifique, mediante portaria dos membros do Governo que tutelam o IMPIC, I. P., a ESPAP, I. P., e a Agência para a Modernização Administrativa, I. P. (AMA, I. P.), e de que depende o GNS, designadamente:
  a) A linguagem de ing para página web;
  b) O nível de acessibilidade para as páginas públicas;
  c) O acesso remoto a sistemas de ficheiros (se aplicável);
  d) O envio seguro de correio eletrónico;
  e) A representação gráfica para a especificação de processos de negócio;
  f) O protocolo para a garantia de entrega de mensagens na integração entre dois ou mais sistemas de informação interorganismos da Administração Pública;
  g) A segurança de integridade e confidencialidade da comunicação na integração entre dois ou mais sistemas de informação interorganismos da Adm','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('inistração Pública;
  h) A segurança de autenticação da comunicação na integração entre dois ou mais sistemas de informação interorganismos da Administração Pública;
  i) A possibilidade de utilização de WS-Addressing na troca de informação entre sistemas de informação;
  j) A definição do standard universal utilizado para todos os ficheiros carregados nas plataformas eletrónicas;
  k) O tipo de assinatura eletrónica que todos os documentos assinados eletronicamente devem utilizar.            
         
   
     
                         
                          
  Artigo 35.º 
Interligação com plataformas públicas
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no artigo anterior, as plataformas eletrónicas devem garantir, sempre que necessário e tecnicamente possível através da plataforma de interoperabilidade da Administração Pública, a sua interligação:
  a) Com o Portal dos Contratos Públicos, quer em termos técnicos quer no que respeita ao cumprimento das regras de sincronismo necessárias à transferência dos dados requeridos entre a plataforma eletrónica e o referido Portal;
  b) Com o portal do Diário da República Eletrónico, nomeadamente para efeitos de envio dos anúncios previstos no CCP;
  c) Com o Catálogo Nacional de Compras Públicas da ESPAP, I. P., quer em termos técnicos quer no que respeita ao cumprimento das regras de sincronismo necessárias à transferência dos dados requeridos entre a plataforma eletrónica e o referido Catálogo;
  d) Com a solução de Gestão de Recursos Financeiros e Orçamentais em modo partilhado (GeRFiP, da ESPAP, I. P.), quer em termos técnicos, quer no que respeita ao cumprimento das regras de sincronismo necessárias à transferência dos dados requeridos entre a plataforma eletrónica e a referida solução;
  e) Com a solução que venha a ser implementada pelo Tribunal de Contas ou pelas entidades do Sistema Nacional de Controlo Interno da Administração Financeira do Estado, no âmbito das suas competências na área da auditoria e controlo dos contratos públicos;
  f) Com a solução de autenticação do cartão de cidadão e com o mecanismo central de autenticação Autenticação.Gov.pt, disponibilizadas pela AMA, I. P.;
  g) Com o Protocolo para a Normalização da Informação Técnica na Construção (ProNIC), gerido pelo IMPIC, I. P.;
  h) Com a plataforma a desenvolver pela Autoridade da Concorrência.
  2 - As interligações previstas no número anterior devem ser estabelecidas através de protocolo a celebrar entre as respetivas entidades envolvidas.
  3 - Não pode ser cobrado pelas entidades gestoras qualquer montante pelo estabelecimento das interligações previstas nos números anteriores.            
         
   
     
                         
                          
  Artigo 36.º 
Interligação entre plataformas electrónicas
                            
                           
    ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                         
                               
                             
     1 - As empresas gestoras devem cumprir as condições de interligação e interoperabilidade entre si, necessárias para que os operadores económicos possam escolher livremente a plataforma eletrónica, independentemente da que for utilizada pela entidade pública com que pretendem interagir.
  2 - A ESPAP, I. P., é responsável pelo sistema de interligação entre as plataformas eletrónicas, cujo desenvolvimento e manutenção são assegurados pela Imprensa Nacional-Casa da Moeda, S. A. (INCM), e que funciona através da plataforma de interoperabilidade da Administração Pública.
  3 - As condições de interligação, interoperabilidade e financiamento são fixadas por portaria dos membros do Governo que tutelam a AMA, I. P., a ESPAP, I. P., e o IMPIC, I. P., de que depende o GNS e responsáveis pela INCM, a publicar no prazo de 90 dias após a publicação da presente lei.
  4 - Quando as fases mais avançadas de interoperabilidade forem alcançadas, cessa a obrigação de prestação dos serviços base definidos no artigo 24.º            
         
   
     
                         
                          
  Artigo 37.º 
Troca de dados entre as plataformas eletrónicas e o Portal dos Contratos Públicos
                            
                           
                             
                               
                             
     1 - A informação transmitida pelas plataformas eletrónicas ao Portal dos Contratos Públicos destina-se, designadamente, a arquivo, ao tratamento estatístico e a monitorização da informação, devendo os dados transmitidos estar devidamente codificados e serem suscetíveis de tratamento automático.
  2 - A codificação a que se refere o número anterior deve estar perfeitamente sincronizada com o Portal dos Contratos Públicos, com vista a que não se verifique qualquer perturbação na correta identificação das entidades e dos processos a que respeita a informação transmitida.
  3 - As condições de interligação das plataformas eletrónicas com o Portal dos Contratos Públicos são fixadas por portaria do membro do Governo que tutela o IMPIC, I. P.
  4 - Sem prejuízo do disposto no número anterior, as plataformas eletrónicas devem prever a realização de procedimentos por agrupamento de entidades adjudicantes, disponibilizando para esse efeito campos para indicação dos dados de cada uma das entidades adjudicantes, nomeadamente designação e número de identificação de pessoa coletiva (NIPC), e demais dados necessários à exportação automática das fichas, a definir nos termos do artigo seguinte.            
         
   
     
                         
                          
  Artigo 38.º 
Dados a transmitir ao Portal dos Contratos Públicos
                            
                           
                             
                               
                             
     As plataformas eletrónicas devem transmitir ao Porta','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('l dos Contratos Públicos dados relativos à formação e à execução dos contratos públicos, nos termos a definir por portaria do membro do Governo que tutela o IMPIC, I. P.            
         
   
     
                         
                          
  SECÇÃO III
  Requisitos de segurança das plataformas electrónicas  Artigo 39.º 
Implementação e gestão da segurança
                            
                           
                             
                               
                             
     1 - No desenvolvimento da sua atividade, as empresas gestoras implementam um sistema de gestão de segurança da informação baseado na Norma ISO/IEC 27001.
  2 - Para efeitos do disposto no número anterior, as empresas gestoras fornecem ao GNS documentação comprovativa, nomeadamente:
  a) Da realização de uma avaliação exaustiva dos riscos que identifique o âmbito de aplicação do sistema e assinale o impacto na atividade em caso de violação da garantia da informação;
  b) Da identificação das ameaças e vulnerabilidades da plataforma eletrónica, e a produção de um documento de análise de riscos onde se enumerem igualmente contramedidas para evitar tais ameaças, e as medidas corretivas a tomar caso a ameaça se concretize, bem como a apresentação de uma lista hierarquizada de melhorias a introduzir;
  c) Da identificação dos riscos residuais por escrito.
  3 - As empresas gestoras selecionam os controlos de segurança adequados com base na análise de riscos prevista na alínea a) do número anterior, e na norma ISO/IEC 27002, nas seguintes áreas da segurança:
  a) Avaliação de risco, adotando-se para o efeito a norma ISO/IEC 27005 ou outra metodologia de avaliação de riscos equivalente;
  b) Segurança física e ambiental;
  c) Segurança dos recursos humanos;
  d) Gestão de comunicações e operações;
  e) Medidas normalizadas de controlo do acesso;
  f) Aquisição, desenvolvimento e manutenção dos sistemas de informação;
  g) Gestão de incidentes no domínio da segurança das informações;
  h) Medidas para corrigir e mitigar violações dos sistemas de informação suscetíveis de causar a destruição, a perda acidental, a alteração, ou a divulgação ou acesso não autorizados dos dados pessoais a tratar;
  i) Conformidade;
  j) Segurança de redes informáticas, recomendando-se para o efeito a norma ISO/IEC 27033.
  4 - A aplicação destas normas pode cingir-se apenas às partes da organização que são relevantes para a atividade das plataformas eletrónicas.            
         
   
     
                         
                          
  Artigo 40.º 
Gestão de utilizadores, perfil de acesso e privilégios
                            
                           
                             
                               
                             
     1 - A plataforma eletrónica deve suportar perfis com diferentes privilégios, incluindo, no mínimo, os seguintes:
  a) Administrador de segurança;
  b) Administrador de sistemas;
  c) Operador de si','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('stemas;
  d) Auditor de sistemas.
  2 - A plataforma eletrónica deve ser capaz de associar e atribuir os utilizadores aos perfis definidos no número anterior.
  3 - A plataforma eletrónica deve garantir que um utilizador não pode ser associado a múltiplos perfis, de acordo com o seguinte critério:
  a) Um utilizador com o perfil de administrador de segurança não é autorizado a assumir o perfil de auditor de sistemas;
  b) Um utilizador com o perfil de administrador de sistemas não é autorizado a assumir o perfil de administrador de segurança ou de auditor de sistemas.            
         
   
     
                         
                          
  Artigo 41.º 
Sistemas e operações
                            
                           
                             
                               
                             
     1 - A empresa gestora garante que a plataforma eletrónica é fiável, nomeadamente:
  a) Os procedimentos de operação e segurança estão definidos;
  b) A plataforma eletrónica foi desenhada e desenvolvida de modo a que o risco de falha dos sistemas seja mínimo;
  c) A plataforma eletrónica está protegida de vírus e software malicioso de modo a assegurar a integridades dos sistemas e da informação nestes incluídos.
  2 - As plataformas eletrónicas devem assegurar a disponibilidade da informação para todos os seus utilizadores, exceto nos períodos de manutenção, de acordo com o disposto nos n.os 5 e 6 do artigo 28.º
  3 - As plataformas eletrónicas devem implementar soluções de modo a inibir e minimizar os efeitos de ataques distribuídos de negação de serviços.
  4 - A ligação da plataforma eletrónica à rede pública deve ser assegurada, no mínimo, por duas origens fisicamente independentes.
  5 - Os vários sistemas que compõem a plataforma eletrónica devem estar atualizados e ser corrigidos (patched), de forma expedita, à medida que são descobertas novas vulnerabilidades.
  6 - Todos os serviços das plataformas eletrónicas devem estar sincronizados com o NTP (Network Time Protocol) definido a partir do UTC (Universal Time Coordinated), devendo ser utilizadas duas fontes de tempo diferentes, em que uma delas é obrigatoriamente a hora legal portuguesa.
  7 - Em caso de desastre, as plataformas eletrónicas devem disponibilizar meios capazes de continuar as operações usando sistemas alternativos e assegurar o backup para garantir a integridade e a possibilidade de recuperação da informação.
  8 - A empresa gestora deve especificar na sua política qual o tempo máximo aceitável, na reposição dos serviços.            
         
   
     
                         
                          
  Artigo 42.º 
Segurança aplicacional
                            
                           
                             
                               
                             
     1 - A empresa gestora deve garantir que o sistema se encontra devidamente protegido contra vulnerabilidades e ataques, impedindo, designadamente:
  ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a) Falhas de injeção, nomeadamente, interrogações SQL (Structured Query Language), LDAP (Lightweight Directory Access Protocol) ou XPath (XML Path Language), comandos do sistema operativo (SO) e alteração de argumentos de programa;
  b) XSS (Cross-Site ing).
  2 - O sistema deve assegurar a autenticação forte e a gestão das sessões, o que exige, no mínimo, que:
  a) As credenciais sejam sempre protegidas quando armazenadas com recurso a técnicas de controlo da integridade dos dados (hashing) ou de cifragem dos dados;
  b) As credenciais não possam ser adivinhadas nem alteradas através de funções de gestão da conta pouco sólidas, nomeadamente, através da criação de conta, alteração da senha, recuperação da senha ou identificadores de sessão frágeis;
  c) Os identificadores de sessão e os dados da sessão não se encontrem expostos no localizador uniforme de recursos (URL);
  d) Os identificadores de sessão não sejam vulneráveis a ataques de fixação de sessão;
  e) Os identificadores de sessão tenham um tempo limite de operação, o que assegura que o utilizador sai do sistema;
  f) As senhas, os identificadores de sessão e outras credenciais sejam enviados apenas através do protocolo TLS (Transport Layer Security).
  3 - O sistema deve possuir uma configuração de segurança adequada, o que exige, no mínimo, que:
  a) Todos os elementos de software sejam atualizados, na medida do necessário para mitigar eventuais vulnerabilidades, nomeadamente o SO, o servidor web e o servidor de aplicações, o sistema de gestão de bases de dados (DBMS), as aplicações, e todas as bibliotecas de códigos;
  b) Os serviços e processos desnecessários do SO, servidor web e servidor de aplicações, sejam desativados, retirados ou não sejam instalados;
  c) As senhas da conta por defeito sejam alteradas ou desativadas.
  4 - O sistema deve limitar o acesso ao URL com base nos níveis e autorizações de acesso do utilizador, exigindo-se, no mínimo, que:
  a) Se forem utilizados mecanismos de segurança externos, para fins de autenticação e verificação das autorizações de acesso às páginas, os mesmos devem estar devidamente configurados para cada página;
  b) Se for utilizada proteção ao nível dos códigos, a mesma deve existir para cada página pretendida.
  5 - O sistema deve utilizar o protocolo TLS de modo a garantir uma proteção suficiente, devendo estar criadas todas as medidas que se seguem ou outras de eficácia equivalente:
  a) O sistema deve exigir a versão mais atualizada do protocolo HTTPS (Hypertext Transfer Protocol Secure) para aceder a quaisquer recursos sensíveis utilizando certificados que sejam válidos, não caducados, não revogados e compatíveis com todos os domínios utilizados pelo sítio;
  b) O sistema deve apor a indicação seguro em todos os s sensíveis;
  c) O servidor deve configurar o fornecedor do TLS de modo a que este apenas aceite algoritmos de cifragem de dados conformes com as melhores práticas;
  d) Os utilizadores devem ser informados de que devem ativa','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('r a funcionalidade TLS no seu navegador.
  6 - O sistema deve impedir reencaminhamentos e reenvios não validados.            
         
   
     
                         
                          
  Artigo 43.º 
Integridade dos dados
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas não devem partilhar hardware e recursos do SO, nem quaisquer dados, nomeadamente, credenciais de acesso e de cifragem, com qualquer outra aplicação ou sistema.
  2 - Cada transação com sucesso que envolva modificação do conteúdo da informação da plataforma eletrónica deve fazer passar a base de dados (BD) de um estado de integridade para outro estado de integridade.
  3 - Deve ser garantido que todos os dados críticos da plataforma eletrónica são seguros e autênticos, devendo para o efeito ser utilizados algoritmos e chaves fortes, de acordo com as normas internacionais.
  4 - Devem ser considerados como dados críticos, no mínimo, todas as configurações de segurança, perfis de utilizador, dados relativos às peças do procedimento e propostas, bem como os respetivos backups.            
         
   
     
                         
                          
  Artigo 44.º 
Segurança de rede
                            
                           
                             
                               
                             
     1 - A ligação da plataforma eletrónica à Internet deve ser protegida por um sistema de proteção de fronteira.
  2 - Todo o tráfego destinado à plataforma eletrónica deve ser inspecionado e registado.
  3 - As regras do sistema de proteção de fronteira devem rejeitar o tráfego que não é necessário à utilização e à administração segura do sistema.
  4 - A plataforma eletrónica deve estar alojada num segmento da rede de produção devidamente protegido, separado de eventuais segmentos utilizados para alojar sistemas que não são de produção, como ambientes de desenvolvimento ou de testes.
  5 - A rede local (LAN) deve cumprir, no mínimo, as seguintes medidas de segurança:
  a) Lista de acesso Layer 2/ segurança dos portos (port switch);
  b) Os portos não utilizados/necessários devem ser desativados;
  c) A DMZ (demilitarized zone) deve encontrar-se numa rede local virtual (VLAN) ou LAN própria;
  d) Não devem estar ativas interligações (trunking) L2 em portas desnecessárias.            
         
   
     
                         
                          
  Artigo 45.º 
Tratamento dos dados pessoais e livre circulação
                            
                           
                             
                               
                             
     O tratamento de informação, pelas plataformas eletrónicas, que contenha dados pessoais, implica a notificação prévia da Comissão Nacional de Proteção de Dados, nos termos previstos na Lei de Proteção de Dados Pessoais.            
    ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
   
     
                         
                          
  Artigo 46.º 
Segurança física
                            
                           
                             
                               
                             
     Sem prejuízo dos controlos de segurança identificados e implementados, com base nos requisitos da ISO/IEC 27001, os sistemas que compõem a plataforma eletrónica devem estar devidamente protegidos em zona segura, com acesso restrito e controlado por sistemas de controlo de acessos e dentro dessa zona, no mínimo, instalado num bastidor seguro.            
         
   
     
                         
                          
  Artigo 47.º 
Identificação e autenticação
                            
                           
                             
                               
                             
     1 - A plataforma eletrónica deve garantir a existência de uma conta individual por utilizador e que os dados de autenticação são únicos.
  2 - Sempre que o utilizador sai da sua conta (logout), para voltar a entrar a plataforma eletrónica deve requerer novamente a apresentação dos dados de autenticação.
  3 - A plataforma eletrónica deve garantir que o utilizador tem capacidade para definir as suas senhas ou códigos de acesso, gerir os seus certificados de autenticação, gerir os seus selos de validação cronológica e autenticar-se de forma segura, designadamente através do cartão do cidadão ou da chave móvel digital.
  4 - Nos casos em que os dados de autenticação são criados pela plataforma eletrónica ou por um sistema exterior, a plataforma eletrónica deve garantir que na primeira utilização o utilizador é obrigado a definir novos dados de autenticação, exceto quando aquela seja feita através da interligação com os mecanismos referidos na alínea f) do n.º 1 do artigo 35.º
  5 - Se for ultrapassado o número máximo de tentativas de autenticação, a plataforma eletrónica deve bloquear a conta do utilizador, que é notificado, por meio fidedigno, do procedimento estabelecido para o desbloqueio.
  6 - A plataforma pode permitir o acesso dos utilizadores por método de autenticação através do nome de utilizador e senha, de acordo com o n.º 3, e deve alertar os utilizadores para o nível de segurança associado a esse método de autenticação.            
         
   
     
                         
                          
  Artigo 48.º 
Controlo de acessos
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem garantir a capacidade de controlar e limitar o acesso aos diversos recursos, identificando os utilizadores, associando o perfil às respetivas permissões e restrições.
  2 - Para o efeito, as entidades gestoras de plataformas devem garantir a identificação correta e fiável dos utilizadores e do operador económico através de processo de verificação.
  ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('3 - O processo de verificação de identidade inicia-se após solicitação do operador económico, devendo a entidade gestora disponibilizar um certificado de autenticação provisório e gratuito em 24 horas, garantindo a sua conclusão com a entrega do certificado de autenticação definitivo no prazo máximo de 30 dias.
  4 - O processo de verificação de identidade é dispensado para procedimentos de formação de contratos celebrados ao abrigo de acordo-quadro.
  5 - As plataformas devem ter mecanismos para garantir o controlo de perfis e acesso restrito às peças concursais para os procedimentos que exigem um nível de proteção elevado e verificação dos utilizadores que podem ter acesso.
  6 - As aplicações devem operar com o menor conjunto de privilégios de que necessitam para esse fim.            
         
   
     
                         
                          
  Artigo 49.º 
Gestão das chaves criptográficas
                            
                           
                             
                               
                             
     1 - Para a cifragem dos dados devem ser utilizados algoritmos correntes fortes e chaves fortes.
  2 - A integridade das senhas deve ser controlada com técnicas hash que utilizam um algoritmo corrente forte e com técnicas salt adequadas.
  3 - Todas as chaves e senhas devem estar protegidas contra qualquer acesso não autorizado.
  4 - Quando as chaves assimétricas sejam emitidas pela plataforma eletrónica e para efeitos de confidencialidade, devem as mesmas ser alvo de mecanismos e procedimentos de retenção da chave privada (key escrow), com controlo multipessoal.            
         
   
     
                         
                          
  Artigo 50.º 
Registos de acesso
                            
                           
                             
                               
                             
     1 - Os registos de acessos devem indicar os dados da máquina de origem, da máquina de destino, do utilizador do sistema, da data e hora do evento e dos ficheiros acedidos, quando aplicável.
  2 - A plataforma eletrónica deve:
  a) Disponibilizar um interface amigável que permita analisar a informação constante dos registos de auditoria, com capacidade para efetuar pesquisas, pelo menos, baseado na data e hora do evento, no tipo de evento e na identidade do utilizador/processo;
  b) Garantir a segurança dos dados de registo, bem como suficiente espaço para guardar esses dados;
  c) Garantir que os dados de registo não podem ser automaticamente reescritos;
  d) Garantir que é vedada a leitura no registo de acessos a todo e qualquer utilizador, com exceção dos que, possuindo perfil de auditores de sistemas, estejam expressamente autorizados para o efeito;
  e) Gerar alarmes, designadamente, por correio eletrónico e por SMS (short message service), sempre que se detete eventual violação de segurança.
  3 - No mínimo, sempre que um utilizador com perfil de administrador d','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e segurança ou administrador de sistemas exceda o número máximo de tentativas de autenticação deve ser gerado o referido alarme para os utilizadores com o perfil de administrador de segurança.
  4 - O período de retenção dos arquivos de auditoria e registo de acessos deve ser de cinco anos.
  5 - As plataformas eletrónicas devem, obrigatoriamente, registar os seguintes eventos:
  a) Ligar e desligar os servidores;
  b) Tentativas com sucesso ou fracassadas de alteração dos parâmetros de segurança do SO;
  c) Tentativas com sucesso ou fracassadas de criar, modificar, apagar contas do sistema;
  d) Ligar e desligar as aplicações e sistemas utilizados pela plataforma eletrónica;
  e) Tentativas com sucesso ou fracassadas de início e fim de sessão;
  f) Tentativas com sucesso ou fracassadas de consulta de dados;
  g) Tentativas com sucesso ou fracassadas de alteração de configurações;
  h) Tentativas com sucesso ou fracassadas de modificação de dados;
  i) Tentativas com sucesso ou fracassadas de criar, modificar ou apagar informação relativa às permissões;
  j) Tentativas com sucesso ou fracassadas de acesso às instalações onde estão alojados os sistemas das plataformas eletrónicas;
  k) Cópias de segurança, recuperação ou arquivo dos dados;
  l) Alterações ou atualizações de software e hardware;
  m) Manutenção do sistema.            
         
   
     
                         
                          
  Artigo 51.º 
Arquivo
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem garantir que conseguem gerar arquivos em suporte lógico adequado.
  2 - As plataformas eletrónicas devem garantir a guarda e o processamento dos arquivos de modo a poderem vir a constituir-se como meio de prova.
  3 - Os registos de acesso e toda a documentação relativa aos procedimentos de formação de contratos públicos devem ser arquivados.
  4 - As plataformas eletrónicas devem garantir a manutenção e o arquivo dos registos de utilização e acesso dos documentos nela carregados.
  5 - O registo dos arquivos de auditoria deve ser realizado de preferência em texto com codificação UTF-8 (unicode transformation format) e exportável.
  6 - Os arquivos devem ser armazenados e organizados de forma sequencial, diariamente, sendo assinados eletronicamente e com aposição de selo temporal emitido por uma entidade certificadora que preste serviços de validação cronológica.
  7 - A plataforma eletrónica deve garantir, do ponto de vista tecnológico, que a destruição de um arquivo só pode ser levado a cabo com a autorização expressa por escrito do administrador de sistema, do administrador de segurança e do auditor de sistemas.            
         
   
     
                         
                          
  Artigo 52.º 
Cópias de segurança e recuperação
                            
                           
                             
    ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                           
                             
     1 - A plataforma eletrónica deve incluir uma função para efetuar cópia de segurança da informação associada aos procedimentos de contratação eletrónica.
  2 - Os dados guardados na cópia de segurança devem ser suficientes para recriar o estado do sistema.
  3 - Um utilizador que pertença a um perfil com suficientes privilégios deve ser capaz de invocar a função de cópia de segurança.
  4 - As cópias de segurança devem estar protegidas contra modificação com recursos a mecanismos de assinatura digital.
  5 - As plataformas eletrónicas devem assegurar que a informação relativa a parâmetros críticos de segurança da plataforma eletrónica não está armazenada em claro, devendo ser cifrada com recurso a algoritmos correntes fortes e chaves fortes, conformes às normas internacionais, sendo a gestão de chaves parte integrante do sistema.
  6 - A plataforma eletrónica deve incluir uma função para recuperação com capacidade para repor o sistema através da cópia de segurança.
  7 - Um utilizador que pertença a um perfil com suficientes privilégios deve ser capaz de invocar a função de recuperação.
  8 - Os registos de auditoria são considerados informação sensível, devendo ser preservados de acordo com o definido no artigo 44.º
  9 - Qualquer período de tempo em que os arquivos de auditoria possam estar desativados deve ser registado no respetivo arquivo de auditoria, com indicação da data e hora de início e o registo do respetivo fim.            
         
   
     
                         
                          
  Artigo 53.º 
Confidencialidade da informação
                            
                           
                             
                               
                             
     1 - Nas diferentes fases do procedimento, o acesso aos documentos que constituem as candidaturas, as soluções e as propostas só deve ser possível na data fixada nos termos das regras do procedimento.
  2 - Os documentos que constituem as candidaturas, as soluções e as propostas carregados nas plataformas eletrónicas devem ser encriptados com recurso a técnicas de criptografia assimétrica.
  3 - Para cada procedimento as plataformas eletrónicas devem emitir um certificado próprio e único que permite a encriptação de documentos.
  4 - A entidade adjudicante pode disponibilizar um certificado próprio para a encriptação no âmbito do seu procedimento.
  5 - A plataforma eletrónica deve garantir que todos os documentos que constituem as candidaturas, as soluções e as propostas são cifrados com recurso ao certificado referido no n.º 3 ou no número anterior.
  6 - Nos casos referidos no n.º 3, quando emitidos, os certificados são alvo de procedimentos de retenção da chave privada (key escrow), com controlo multipessoal de duas das três seguintes funções: administrador de sistemas, administrador de segurança e auditor de segurança.
  7 - As plataformas eletrónicas devem assegurar a custódia de','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' chaves privadas e atribuir acesso às mesmas aos membros do júri ou, caso este não exista, a um utilizador da entidade adjudicante devidamente autorizado, para efeitos da desencriptação dos documentos.
  8 - A plataforma eletrónica deve garantir que o acesso à chave privada referido no número anterior é efetuado de forma automatizada, não podendo ser conhecido o segredo de acesso à chave privada por qualquer pessoa ou entidade, incluindo a entidade gestora, que não os membros do júri ou, caso este não exista, um utilizador da entidade adjudicante devidamente autorizado.
  9 - As plataformas eletrónicas devem disponibilizar aos interessados os programas e aplicações que permitem utilizar certificados digitais para cifrar os documentos.
  10 - A circunstância de os documentos serem encriptados não dispensa os interessados do requerimento de classificação de documentos a que alude o n.º 1 do artigo 66.º do CCP para efeitos de restrição ou de limitação do acesso aos mesmos para salvaguarda de direitos do interessado.
  11 - Nos casos referidos no número anterior, a plataforma eletrónica deve garantir que os documentos cuja classificação tenha sido autorizada pela entidade adjudicante apenas sejam visíveis pelos membros do júri, sem prejuízo do disposto no n.º 4 do artigo 66.º do CCP.            
         
   
     
                         
                          
  Artigo 54.º 
Assinaturas electrónicas
                            
                           
                             
                               
                             
     1 - Os documentos submetidos na plataforma eletrónica, pelas entidades adjudicantes e pelos operadores económicos, devem ser assinados com recurso a assinatura eletrónica qualificada, nos termos dos n.os 2 a 6.
  2 - Os documentos elaborados ou preenchidos pelas entidades adjudicantes ou pelos operadores económicos devem ser assinados com recurso a certificados qualificados de assinatura eletrónica próprios ou dos seus representantes legais.
  3 - Os documentos eletrónicos emitidos por entidades terceiras competentes para a sua emissão, designadamente, certidões, certificados ou atestados, devem ser assinados com recurso a certificados qualificados de assinatura eletrónica das entidades competentes ou dos seus titulares, não carecendo de nova assinatura por parte das entidades adjudicantes ou do operador económico que os submetem.
  4 - Os documentos que sejam cópias eletrónicas de documentos físicos originais emitidos por entidades terceiras, podem ser assinados com recurso a certificados qualificados de assinatura eletrónica da entidade adjudicante ou do operador económico que o submete, atestando a sua conformidade com o documento original.
  5 - Nos documentos eletrónicos cujo conteúdo não seja suscetível de representação como declaração escrita, incluindo os que exijam processamento informático para serem convertidos em representação como declaração escrita, designadamente, processos de compr','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('essão, descompressão, agregação e desagregação, a aposição de uma assinatura eletrónica qualificada deve ocorrer em cada um dos documentos eletrónicos que os constituem, assegurando-lhes dessa forma a força probatória de documento particular assinado, nos termos do artigo 376.º do Código Civil e do n.º 2 do artigo 3.º do Decreto-Lei n.º 290-D/99, de 2 de agosto, alterado e republicado pelo Decreto-Lei n.º 88/2009, de 9 de abril, sob pena de causa de exclusão da proposta nos termos do artigo 146.º do Código dos Contratos Públicos.
  6 - No caso de entidades que devam utilizar assinaturas eletrónicas emitidas por entidades certificadoras integradas no Sistema de Certificação Eletrónica do Estado, o nível de segurança exigido é o que consta do Decreto-Lei n.º 116-A/2006, de 16 de junho, alterado e republicado pelo Decreto-Lei n.º 161/2012, de 31 de julho.
  7 - Nos casos em que o certificado digital não possa relacionar o assinante com a sua função e poder de assinatura, deve a entidade interessada submeter à plataforma eletrónica um documento eletrónico oficial indicando o poder de representação e a assinatura do assinante.
  8 - Sempre que solicitado pelas entidades adjudicantes ou pelos operadores económicos, as plataformas eletrónicas devem garantir, no prazo máximo de cinco dias úteis, a integração de novos fornecedores de certificados digitais qualificados.
  9 - As plataformas eletrónicas devem garantir que a validação dos certificados é feita com recurso à cadeia de certificação completa.            
         
   
     
                         
                          
  Artigo 55.º 
Validação cronológica
                            
                           
                             
                               
                             
     1 - Todos os documentos submetidos nas plataformas eletrónicas, bem como todos os atos que, nos termos do CCP, devem ser praticados dentro de um determinado prazo, são sujeitos à aposição de selos temporais emitidos por uma entidade certificadora credenciada para a prestação de serviços de validação cronológica.
  2 - Para efeitos do disposto no número anterior, os atos sujeitos à aposição de selos temporais são os seguintes:
  a) Os esclarecimentos solicitados pelos interessados, convidados ou candidatos;
  b) Os esclarecimentos prestados pela entidade adjudicante;
  c) As retificações efetuadas pela entidade adjudicante;
  d) A apresentação de lista de erros e omissões;
  e) A aceitação ou rejeição dos erros e omissões pela entidade adjudicante;
  f) A submissão de candidaturas, propostas e soluções;
  g) A notificação para audiência prévia;
  h) A pronúncia de candidato ou concorrente em sede de audiência prévia;
  i) A decisão de adjudicação;
  j) A notificação da minuta do contrato;
  k) A aceitação expressa ou reclamação à minuta do contrato;
  l) A apresentação dos documentos de habilitação;
  m) A apresentação de comprovativo da prestação de caução;
  n) A apresentação de reclam','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ações e impugnações;
  o) A notificação para audiência de contrainteressados.
  3 - As plataformas eletrónicas devem guardar e associar ao procedimento todos os selos temporais originados pelos documentos ou transações.
  4 - Sempre que solicitado pelas entidades adjudicantes ou pelos operadores económicos, as plataformas eletrónicas devem garantir, no prazo máximo de cinco dias úteis, a integração de novos prestadores de serviços de validação cronológica.
  5 - Decorrido o prazo definido no número anterior, a entidade gestora da plataforma eletrónica deve assegurar todos os custos relacionados com a validação cronológica.            
         
   
     
                         
                          
  Artigo 56.º 
Lista de serviços de certificação eletrónica de confiança
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem garantir a compatibilidade com mecanismos para validação da habilitação dos fornecedores de serviços de certificação eletrónica qualificados, requeridos no âmbito da presente lei, nomeadamente, a capacidade de interpretação das Trusted-Status Services List (TSL) de todos os Estados membros e da Comissão Europeia, segundo a norma ETSI TS 119 612, na versão mais recente.
  2 - Nos casos em que através da interpretação da TSL resultar alguma não conformidade sobre a habilitação do prestador de serviços de certificação eletrónica, a plataforma deve apenas fornecer tal informação, não podendo ser feita de forma automática a exclusão de qualquer proposta.            
         
   
     
                         
                          
  Artigo 57.º 
Autenticação de utilizadores na plataforma electrónica
                            
                           
                             
                               
                             
     1 - A identificação dos utilizadores perante as plataformas eletrónicas efetua-se mediante a utilização de nome de utilizador e da palavra-chave, podendo ainda ser utilizados certificados digitais próprios ou certificados disponibilizados pelas plataformas eletrónicas, bem como o cartão de cidadão ou a chave móvel digital referidos na alínea f) do n.º 1 do artigo 35.º
  2 - No caso de entidades que devem utilizar assinaturas eletrónicas emitidas por entidades certificadoras integradas no Sistema de Certificação Eletrónica do Estado, o nível de segurança exigido é o que consta do Decreto-Lei n.º 116-A/2006, de 16 de junho, alterado e republicado pelo Decreto-Lei n.º 161/2012, de 31 de julho.
  3 - O mecanismo de validação de certificados dos utilizadores é efetuado tendo por base o certificado e a respetiva cadeia de certificação completa.
  4 - As plataformas eletrónicas devem garantir a integração com o Sistema de Certificação de Atributos Profissionais.            
         
   
     
                         
                         ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
  Artigo 58.º 
Preservação digital
                            
                           
                             
                               
                             
     As plataformas eletrónicas devem, relativamente aos documentos que estejam sob a sua custódia:
  a) Cumprir as normas, standards e procedimentos de arquivo para garantir a preservação digital e a interoperabilidade;
  b) Garantir a preservação das assinaturas eletrónicas utilizadas nos diversos procedimentos;
  c) Implementar mecanismos tecnológicos para preservação, armazenamento, indexação e recuperação dos arquivos;
  d) Garantir que a informação respeitante a cada procedimento pode ser exportada em formatos normalizados para efeitos de preservação;
  e) Disponibilizar os registos de acessos por parte dos interessados, concorrentes e adjudicatários, bem como todos os outros utilizadores do sistema;
  f) Disponibilizar os seus arquivos de registos de acessos à entidade adjudicante, sempre que esta o solicite, e também para efeito de auditorias externas.            
         
   
     
                         
                          
  Artigo 59.º 
Conservação de documentos electrónicos
                            
                           
                             
                               
                             
     Os documentos que integram os procedimentos de contratação pública devem ser conservados pelas plataformas eletrónicas, nos termos do artigo 107.º do CCP, juntamente com o software e tecnologias que permitam a sua leitura, até ao termo do prazo estabelecido na lei para aquela conservação, sem prejuízo do dever de remessa às entidades adjudicantes de toda a informação e documentação associada aos procedimentos de formação de contrato que lhe digam respeito, em formato digital.            
         
   
     
                         
                          
  CAPÍTULO VII
  Regras gerais de funcionamento das plataformas eletrónicas em procedimentos de formação de contratos públicos  Artigo 60.º 
Condução dos procedimentos nas plataformas electrónicas
                            
                           
                             
                               
                             
     Compete ao representante da entidade adjudicante conduzir o procedimento de formação de contratos públicos, constituindo a plataforma eletrónica apenas a infraestrutura tecnológica na qual aquele procedimento se desenvolve.            
         
   
     
                         
                          
  Artigo 61.º 
Notificações e comunicações
                            
                           
                             
                               
                             
     1 - Todas as notificações e comunicações entre a entidade adjudicante ou o júri do procedimento e os interessados, os concorrentes ou o adjudicatário, relativas à fase de formação do contrato e que, nos termos do CCP, devem s','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('er praticadas num determinado prazo são feitas através das plataformas eletrónicas por via de envio automático de mensagens eletrónicas, devendo as mesmas ficar disponíveis para consulta na área exclusiva respetiva.
  2 - A data e a hora precisas das notificações e comunicações são registadas, de acordo com o artigo 469.º do CCP, devendo os serviços da plataforma eletrónica ser detentores de mecanismos que permitam obter com exatidão a data e a hora fornecidas por uma entidade certificadora que preste serviços de validação cronológica.            
         
   
     
                         
                          
  Artigo 62.º 
Disponibilização de documentos
                            
                           
                             
                               
                             
     1 - No âmbito de cada procedimento de formação de um contrato, a plataforma eletrónica disponibiliza, em área de acesso livre, e de forma completa e gratuita, as peças do procedimento, a partir da data da publicação do anúncio.
  2 - O acesso aos restantes documentos do procedimento, designadamente os relativos aos esclarecimentos e às retificações da autoria da entidade adjudicante, às suas decisões de prorrogação do prazo, às listas dos erros e omissões identificados pelos interessados, à lista dos erros e omissões aceites pela entidade adjudicante e às notificações e comunicações na fase prévia à apresentação das propostas, é reservado aos interessados registados e participantes no mesmo.
  3 - Após a abertura das propostas pelo júri, ou pelo responsável pelo procedimento caso não exista júri, as plataformas eletrónicas devem garantir o acesso exclusivo, por parte das entidades incluídas na lista dos concorrentes, a todas as propostas apresentadas, aos esclarecimentos sobre a proposta da autoria dos respetivos concorrentes, aos documentos de habilitação apresentados pelo adjudicatário, bem como a todos os demais atos ou formalidades procedimentais relativos à fase posterior à apresentação das propostas que, nos termos do disposto no CCP, devam ser publicitados na plataforma eletrónica utilizada pela entidade adjudicante.
  4 - No caso de classificação de determinados documentos que constituem a proposta, nos termos do artigo 66.º do CCP, as plataformas eletrónicas devem estar aptas a disponibilizar para consulta dos restantes concorrentes, nos termos do n.º 2 do artigo 138.º do CCP, apenas os documentos não classificados da mesma.
  5 - A disponibilização referida no número anterior ocorre de forma automática, tendo por base a sinalização feita pelo interessado durante o carregamento do documento classificado, sem prejuízo do disposto no n.º 3 do artigo 66.º do CCP.
  6 - A plataforma eletrónica deve ainda permitir a disponibilização, a qualquer momento, de documentos sinalizados pelos concorrentes que o órgão competente para a decisão de contratar considere não classificados, nos termos do n.º 3 do artigo 66.º do CCP, ou desclassif','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ique, nos termos do n.º 4 do mesmo artigo.
  7 - As listas, previstas no CCP, dos concorrentes e dos candidatos aos procedimentos de formação de contratos públicos devem ser publicitadas junto de todos os interessados.            
         
   
     
                         
                          
  Artigo 63.º 
Disponibilização de informação sobre datas de referência
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas disponibilizam aos interessados a indicação da data e hora do termo do prazo para a apresentação dos pedidos de esclarecimento e das propostas, bem como da data e hora do termo do prazo para a apresentação da lista, prevista no artigo 61.º do CCP, na qual sejam identificados erros e omissões do caderno de encargos.
  2 - A informação a disponibilizar é introduzida pela entidade adjudicante, não dependendo de qualquer automatismo da plataforma eletrónica.            
         
   
     
                         
                          
  Artigo 64.º 
Requisitos para os ficheiros das propostas
                            
                           
                             
                               
                             
     1 - Sem prejuízo do cumprimento dos requisitos de interoperabilidade e compatibilidade previstos no RNID, a entidade adjudicante pode fazer exigências quanto a características dos ficheiros que contêm os documentos que constituem as propostas apresentadas pelos concorrentes nas plataformas eletrónicas, devendo, para o efeito, incluir no programa do procedimento ou no convite as respetivas especificações.
  2 - Sem prejuízo do disposto no número anterior, sempre que, por razões de excessivo volume ou complexidade dos dados a submeter, relativos a elementos da proposta solicitados pela entidade adjudicante, não seja tecnicamente possível aos concorrentes ou candidatos submeter documentos ou ficheiros através de plataforma eletrónica, deve a entidade adjudicante permitir a entrega dos documentos através de suportes físicos de informação, a definir no programa do procedimento ou, no caso do ajuste direto, no convite.
  3 - Para efeitos do disposto no n.º 1, a entidade adjudicante pode, designadamente, estabelecer especificações relativas:
  a) À organização dos ficheiros, através de uma padronização da estrutura em árvore respetiva;
  b) Ao número de ficheiros, documento a documento ou no seu conjunto;
  c) À dimensão dos ficheiros, individualmente, por documento ou globalmente;
  d) Ao título dos ficheiros, que pode incluir secção predefinida relativa ao documento a que respeita, bem como o número de ordem do interessado, ou o número de identificação fiscal respetivo, o código da proposta, nos termos definidos no anexo II à presente lei, que dela faz parte integrante, e ainda os códigos do procedimento ou de outros aspetos a definir;
  e) À apresentação de i','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nformação, constando de um índice ou de uma descrição e explicação da estrutura e do conteúdo dos ficheiros que constituem a proposta;
  f) Ao formato dos documentos;
  g) Ao universo das aplicações informáticas de base cujo uso é aceitável.
  4 - Além da informação referida no número anterior, as propostas podem ainda incluir os seguintes elementos complementares, a inscrever em formulário próprio:
  a) Declaração remetendo para um conjunto de ficheiros de outra proposta do mesmo interessado, tal como descrito no n.º 12 do artigo 68.º, se o programa do procedimento admitir a apresentação de propostas variantes e se o interessado assim o decidir;
  b) Nota explicativa, tal como descrita na alínea e) do número anterior, se o programa do procedimento for omisso quanto às exigências referidas no número anterior mas o concorrente apresentar uma estrutura e conteúdo de ficheiros próprios.
  5 - Os requisitos a incluir no programa do procedimento podem contemplar uma ou várias das características referidas nos números anteriores, bem como outras que a entidade adjudicante entenda relevante solicitar.
  6 - As disposições a que se referem os números anteriores são válidas para as eventuais folhas constituintes de cada ficheiro, quando, com as devidas adaptações, forem aplicáveis.
  7 - A entidade adjudicante pode solicitar que cada documento ou parcela de documento contido em cada ficheiro de uma proposta permita uma leitura sequencial, independentemente da natureza das componentes que o constituem.
  8 - A entidade adjudicante pode solicitar a apresentação de ficheiros consistindo em folhas de cálculo, que repitam informação prestada noutros ficheiros e que contenham fórmulas de cálculo que permitam verificar a formação dos resultados, ou solicitar outros tipos de repetição de informação associada a formatos diversos.
  9 - As solicitações a que se referem os números anteriores devem constar do programa de procedimento.            
         
   
     
                         
                          
  Artigo 65.º 
Data e hora de apresentação da candidatura, solução e proposta
                            
                           
                             
                               
                             
     1 - A data e hora limite para entrega das candidaturas, das soluções e das propostas, devem ser fixadas pela entidade adjudicante nas peças do procedimento.
  2 - Para efeitos de determinação da data e hora referidas no número anterior, deve ter-se em consideração o momento em que o concorrente procede à submissão da totalidade dos documentos que as integram, nos termos do disposto no artigo 70.º
  3 - A plataforma eletrónica deve operacionalizar um sistema de aviso de receção eletrónico que comprove o sucesso do envio dos documentos que constituem as candidaturas, as soluções e as propostas, bem como a data e hora da submissão.
  4 - A plataforma eletrónica deve assegurar a determinação precisa da data e hora da transmissão ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('dos dados referidos no número anterior, devendo aqueles dados ser inscritos na proposta no momento da sua receção.
  5 - O aviso de receção referido no n.º 3 é enviado, de imediato, para o interessado.
  6 - Caso o envio completo não seja bem-sucedido, considera-se não ter existido qualquer apresentação de candidaturas, soluções e propostas, devendo o interessado ser, de imediato, notificado desse facto.            
         
   
     
                         
                          
  Artigo 66.º 
Componentes de cada proposta
                            
                           
                             
                               
                             
     1 - Para efeitos do carregamento de uma proposta, no âmbito de um procedimento de formação de um contrato público, a plataforma eletrónica deve incluir obrigatoriamente:
  a) As áreas específicas para carregamento dos ficheiros correspondentes aos documentos que constituem a proposta, de acordo com o definido pela entidade adjudicante;
  b) O formulário específico para preenchimento, doravante designado por formulário principal, conforme modelo aprovado pela portaria referida no artigo 38.º, a enviar posteriormente ao Portal dos Contratos Públicos;
  c) Os campos para recolha de informação dos preços propostos pelos operadores económicos, sempre que definido pela ESPAP, I. P., nos termos previstos na alínea c) do n.º 2 do artigo 30.º
  2 - O programa do procedimento pode prever a disponibilização, por parte da plataforma eletrónica, de formulários para preenchimento pelos concorrentes que substituam algum ou alguns dos ficheiros a que se refere a alínea a) do número anterior.
  3 - A discriminação do valor da proposta que caiba a cada um dos membros do agrupamento concorrente, incluída no formulário principal, não substitui nem tem o mesmo âmbito que a informação requerida nos termos do n.º 5 do artigo 60.º do CCP.
  4 - Para além dos documentos e do formulário referidos no n.º 1, as propostas podem ainda incluir os elementos complementares previstos no n.º 4 do artigo 64.º, bem como quaisquer outros documentos que os concorrentes considerem indispensáveis nos termos previstos no n.º 3 do artigo 57.º do CCP.
  5 - A plataforma eletrónica deve disponibilizar um recibo eletrónico, que é anexado à proposta.            
         
   
     
                         
                          
  Artigo 67.º 
Codificação das propostas e identificação das empresas concorrentes
                            
                           
                             
                               
                             
     1 - Os dados do formulário principal referido na alínea b) do n.º 1 do artigo anterior, devem ser objeto de codificação quando não se trate de dados numéricos.
  2 - De acordo com o número anterior, cabe ao concorrente codificar as propostas que apresenta, bem como apresentar a sua identificação ou a de cada membro do agrupamento concorrente, no âmbito ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('do preenchimento do formulário principal.
  3 - A codificação de cada proposta é exigível desde o início do respetivo carregamento e é feita de acordo com as regras que constam do anexo II.
  4 - A identificação dos concorrentes referida no n.º 2 apenas deve ter lugar uma vez, através de introdução direta ou por seleção em lista disponibilizada pela plataforma eletrónica, aquando da apresentação da primeira proposta pelo concorrente ou aquando da prévia candidatura, caso exista.
  5 - O sistema de identificação que a plataforma eletrónica disponibiliza aos concorrentes deve respeitar os requisitos previstos no Portal dos Contratos Públicos para efeitos da transmissão da informação relativa a essa identificação da plataforma eletrónica para o Portal.            
         
   
     
                         
                          
  Artigo 68.º 
Carregamento das propostas
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas devem permitir o carregamento progressivo, pelo interessado, da proposta ou propostas, até à data e hora prevista para a submissão das mesmas.
  2 - O carregamento mencionado no número anterior é feito na área reservada em exclusivo ao interessado em causa e relativa ao procedimento em curso.
  3 - A plataforma eletrónica deve disponibilizar ao interessado as aplicações informáticas que permitam automaticamente, no ato de carregamento, encriptar e apor uma assinatura eletrónica nos ficheiros de uma proposta, localmente, no seu próprio computador.
  4 - Sem prejuízo do disposto no número seguinte, quando o interessado realizar o carregamento, na plataforma eletrónica, de um ficheiro de uma proposta, este deve estar já encriptado e assinado, com recurso a assinatura eletrónica qualificada.
  5 - As plataformas eletrónicas podem conceder aos interessados a possibilidade de os ficheiros das propostas serem carregados de forma progressiva na plataforma eletrónica, desde que encriptados, permitindo a permanente alteração dos documentos até ao momento da submissão.
  6 - O formulário principal e outros formulários a preencher no âmbito do procedimento devem ser disponibilizados ao interessado, por descarga de XML, para alojamento local, no respetivo computador, sendo aplicável, neste caso, o disposto nos n.os 3 e 4.
  7 - A plataforma eletrónica só pode permitir o carregamento dos ficheiros que compõem uma proposta após a introdução do respetivo código por parte do interessado, segundo a codificação descrita no anexo II.
  8 - As plataformas eletrónicas devem assegurar que o código referido no número anterior está sempre visível para o utilizador, quando este procede ao carregamento dos ficheiros que compõem a proposta.
  9 - Quando se verifique um erro de identificação, deve ser possível ao interessado corrigir, até à data e à hora fixadas para a submissão das propostas, o código da proposta que está ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('em fase de carregamento ou que foi já submetida.
  10 - As plataformas eletrónicas devem disponibilizar, em permanência, a cada interessado, a lista de códigos das suas propostas que estejam em fase de carregamento e já submetidas.
  11 - As plataformas eletrónicas devem impossibilitar que um interessado inicie o carregamento de uma proposta cujo código coincida com o código de outra proposta sua no âmbito do mesmo procedimento, quer esteja em fase de carregamento ou a proposta tenha já sido submetida.
  12 - Sempre que seja permitida a apresentação de propostas variantes, pode o concorrente deixar de apresentar ficheiros constituintes de uma determinada proposta que sejam iguais aos de outra proposta sua, apresentada no âmbito do mesmo procedimento, substituindo-os por informação aposta no formulário a aprovar pela portaria referida no artigo 38.º, contendo uma declaração que identifique qual a proposta e quais os ficheiros da mesma que são considerados ali reproduzidos.
  13 - Para efeitos do número anterior, na construção de determinada proposta admite-se a remissão para ficheiros de uma única outra proposta, identificada através do código descrito no anexo II.
  14 - O formulário principal não é passível de remissões, devendo, em todo o caso, a plataforma eletrónica garantir que não há introdução de dados de identificação já antes introduzidos.
  15 - Durante o processo de carregamento, as plataformas eletrónicas devem assegurar aos interessados a possibilidade de substituírem ficheiros já carregados por outros novos, no âmbito do processo de construção de cada proposta.
  16 - As plataformas eletrónicas devem disponibilizar aos interessados um sistema que lhes permita sinalizar, durante o carregamento das suas propostas, os ficheiros objeto de classificação, os quais não são disponibilizados aos concorrentes nos termos do n.º 3 do artigo 62.º            
         
   
     
                         
                          
  Artigo 69.º 
Encriptação e classificação de documentos
                            
                           
                             
                               
                             
     1 - Os documentos que constituem a proposta, a candidatura ou a solução são encriptados, sendo-lhes aposta assinaturas eletrónicas qualificadas.
  2 - A circunstância de os documentos serem encriptados não dispensa os interessados do requerimento de classificação de documentos a que alude o n.º 1 do artigo 66.º do CCP para efeitos de restrição ou de limitação do acesso aos mesmos para salvaguarda de direitos do interessado.
  3 - Nos casos referidos no número anterior, a plataforma eletrónica deve garantir que os documentos cuja classificação tenha sido autorizada pela entidade adjudicante apenas sejam visíveis pelos membros do júri, ou pelo responsável pelo procedimento caso não exista júri, sem prejuízo do disposto no n.º 4 do artigo 66.º do CCP.            
         
   
     
                         
       ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                   
  Artigo 70.º 
Submissão das propostas
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no n.º 6 do artigo 65.º, a proposta considera-se apresentada, para efeitos do CCP, quando o concorrente finaliza o processo de submissão.
  2 - Nos casos referidos no n.º 5 do artigo 68.º, o momento da submissão desencadeia o processo de encriptação de todos os ficheiros que compõem a proposta.
  3 - A submissão de uma proposta só deve ter lugar após o completo preenchimento do formulário principal, incluindo, nos casos em que exista, o anexo referido na alínea c) do n.º 1 do artigo 66.º, que é parte integrante da mesma.
  4 - No caso de um concorrente apresentar propostas variantes, o disposto no artigo 137.º do CCP aplica-se a cada uma das propostas e não ao seu conjunto, podendo o concorrente retirar uma proposta em concreto, identificada através do código descrito no anexo II, sem com isso alterar a situação das suas propostas restantes.
  5 - A plataforma eletrónica obriga-se a disponibilizar ao júri do procedimento, ou ao responsável pelo procedimento caso não exista júri, todas as propostas que até à data e à hora fixadas, pela entidade adjudicante, para a sua disponibilização e abertura tenham sido submetidas, independentemente da eventual existência de motivos de exclusão das propostas.            
         
   
     
                         
                          
  Artigo 71.º 
Sequência da submissão das propostas
                            
                           
                             
                               
                             
     1 - Após a submissão, o concorrente deve receber, para efeitos do disposto no n.º 1 do artigo anterior, um recibo eletrónico, com registo da identificação da entidade adjudicante, do procedimento, do lote, se for o caso, do concorrente, da proposta, bem como da data e hora da respetiva submissão.
  2 - O recibo deve ser disponibilizado na área de acesso exclusivo do concorrente e ser enviada cópia do mesmo por correio eletrónico.
  3 - A plataforma eletrónica agrega à proposta submetida o recibo eletrónico referido nos números anteriores, que passa a constituir um anexo indissociável da mesma, e que, enquanto tal, é entregue ao júri do procedimento, nos termos do n.º 2 do artigo 74.º
  4 - As plataformas eletrónicas asseguram que os concorrentes podem consultar as propostas submetidas no âmbito do procedimento de formação do contrato, em qualquer momento a partir da respetiva desencriptação por parte do júri do procedimento, ou pelo responsável pelo procedimento caso não exista júri, e até seis meses após a conclusão do procedimento.            
         
   
     
                         
                          
  Artigo 72.º 
Ordenação dos interessados e dos concorrentes
                            
                           ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
                             
                               
                             
     1 - Após a submissão das propostas, nos termos do disposto no artigo 70.º, a plataforma eletrónica atribui de forma automática e sequencial um número de ordem preliminar aos concorrentes, tomando por base o momento de submissão da proposta por cada concorrente ou, no caso de serem apresentadas propostas variantes, da primeira das suas propostas.
  2 - As plataformas eletrónicas devem garantir o registo e a ordenação sequencial de todos os interessados e concorrentes que se registem na mesma, informação que deve ser prestada às entidades adjudicantes no âmbito de cada procedimento.
  3 - O processo de disponibilização da versão prévia da lista dos concorrentes ao júri do procedimento, ou ao responsável pelo procedimento caso não exista júri, e, posteriormente, da versão validada para publicitação geral consta dos artigos 75.º e 76.º
  4 - O elenco de dados da lista dos concorrentes consta da portaria referida no artigo 38.º
  5 - Para efeitos da disponibilização aos intervenientes, o formato de visualização dos dados a que se refere o número anterior é adotado livremente por cada plataforma eletrónica.            
         
   
     
                         
                          
  Artigo 73.º 
Conhecimento do conteúdo das candidaturas, soluções e propostas
                            
                           
                             
                               
                             
     1 - Os meios eletrónicos utilizados pelas plataformas eletrónicas devem assegurar que as entidades adjudicantes e os restantes concorrentes só tomam conhecimento do conteúdo das candidaturas, das soluções e das propostas, depois de serem abertas pelo júri do procedimento, ou pelo responsável pelo procedimento caso não exista júri.
  2 - A entidade adjudicante comunica à empresa gestora o momento em que devem ser publicitadas na plataforma eletrónica a data limite para a apresentação de candidaturas, de soluções e de propostas, bem como a data e hora de abertura das mesmas.
  3 - As comunicações previstas no número anterior devem sempre ter lugar quando, por motivos de suspensão ou interrupção do prazo para apresentação de candidaturas, de soluções e de propostas, ocorra uma alteração da respetiva data e hora ou da data e hora para abertura das mesmas.            
         
   
     
                         
                          
  Artigo 74.º 
Disponibilização das propostas ao júri do procedimento ou ao responsável pelo procedimento caso não exista júri
                            
                           
                             
                               
                             
     1 - As propostas não podem ser disponibilizadas ao júri, ou ao responsável pelo procedimento caso não exista júri, antes do termo do prazo para a respetiva apresentação.
  2 - A disponibilização e a abertura das propostas pelo júri do ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('procedimento deve ocorrer na sequência da ordem dada pelo mesmo nesse sentido, mediante autenticação de, pelo menos, três dos respetivos membros, salvo quando não exista júri mas apenas um responsável pelo procedimento.
  3 - A disponibilização referida no n.º 1 contempla a totalidade das propostas submetidas na plataforma eletrónica no âmbito do procedimento em causa e inclui a respetiva ficha prévia de abertura de propostas descrita no artigo seguinte.
  4 - A data e hora da disponibilização e abertura das propostas pelo júri, ou pelo responsável pelo procedimento caso não exista júri, é previamente publicitada na plataforma eletrónica.            
         
   
     
                         
                          
  Artigo 75.º 
Ficha prévia de abertura das propostas e lista prévia dos concorrentes
                            
                           
                             
                               
                             
     1 - As plataformas eletrónicas asseguram a construção automática, para cada procedimento, de uma ficha prévia de abertura de propostas, nos termos a definir na portaria referida no artigo 38.º, que se destina a ser disponibilizada exclusivamente ao júri do procedimento, ou ao responsável pelo procedimento, caso não exista júri.
  2 - A construção automática a que se refere o número anterior implica uma agregação dos dados introduzidos pelos concorrentes no formulário principal, relativo a cada proposta.
  3 - As plataformas eletrónicas são livres de estabelecer o formato de visualização da ficha prévia de abertura de propostas a disponibilizar ao júri do procedimento.
  4 - A lista prévia dos concorrentes constitui uma parcela da ficha prévia de abertura de propostas no que respeita aos dados que a integram.            
         
   
     
                         
                          
  Artigo 76.º 
Ficha de abertura das propostas e lista dos concorrentes
                            
                           
                             
                               
                             
     1 - Após ter procedido à abertura das propostas, o júri do procedimento, ou o responsável pelo procedimento caso não exista júri, deve verificar se a ficha prévia de abertura das propostas se mantém válida ou se, pelo contrário, devem ser feitas alterações.
  2 - Caso seja necessária a realização de alterações, a ficha de abertura das propostas é completada sobre a plataforma eletrónica pelo júri do procedimento, ou pelo responsável pelo procedimento caso não exista júri, através de um interface que salvaguarde a natureza codificada dos dados, necessária para o envio de informação a que se refere o n.º 4.
  3 - Após a eventual alteração da ficha de abertura das propostas, a lista dos concorrentes é publicitada no dia imediato ao termo do prazo fixado para a apresentação daquelas.
  4 - No prazo de 10 dias úteis após a disponibilização e abertura das propostas, a plataforma eletrónica ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('deve transmitir para o Portal dos Contratos Públicos a informação contida na ficha de abertura das propostas.            
         
   
     
                         
                          
  Artigo 77.º 
Negociação e leilões electrónicos
                            
                           
                             
                               
                             
     1 - O disposto na presente lei é aplicável, com as devidas adaptações, à negociação por via eletrónica e aos leilões eletrónicos, sem prejuízo do disposto no número seguinte.
  2 - Durante a fase de leilão eletrónico não é exigível a utilização de assinaturas eletrónicas para a apresentação das propostas.
  3 - A plataforma eletrónica deve registar as propostas introduzidas incorretamente, ainda que as mesmas não devam ser consideradas para efeitos do leilão eletrónico.            
         
   
     
                         
                          
  CAPÍTULO VIII
  Fiscalização e sanções  Artigo 78.º 
Competências de fiscalização
                            
                           
                             
                               
                             
     1 - O IMPIC, I. P., e o GNS, no âmbito das suas competências, fiscalizam a atividade de gestão das plataformas eletrónicas, podendo solicitar a quaisquer serviços públicos ou autoridades a colaboração ou auxílio que sejam necessários.
  2 - Todas as entidades e seus agentes utilizadores das plataformas devem participar ao IMPIC, I. P., e ao GNS quaisquer indícios de infração à presente lei de que tenham conhecimento.            
         
   
     
                         
                          
  Artigo 79.º 
Auditorias
                            
                           
                             
                               
                             
     1 - O IMPIC, I. P., e o GNS podem, a todo o tempo e sem aviso prévio, proceder ou mandar proceder a auditorias às plataformas eletrónicas, devendo elaborar relatórios fundamentados, cuja cópia é enviada à empresa gestora.
  2 - As auditorias referidas no número anterior não podem ser realizadas pelos auditores de sistemas das próprias empresas gestoras da plataforma eletrónica auditada.
  3 - Se das auditorias previstas no n.º 1 resultar a deteção de incumprimento de qualquer disposição da presente lei, o IMPIC, I. P., ou o GNS, consoante os casos, ordenam à empresa gestora que proceda, no prazo máximo de 30 dias, à correção das situações detetadas, findo o qual manda proceder a nova auditoria, para avaliação das correções efetuadas.
  4 - Se da nova auditoria resultar que as situações identificadas, ou algumas delas, não foram devidamente corrigidas, decorrido o prazo legal de audiência prévia, deve o facto ser publicitado no Portal dos Contratos Públicos, sem prejuízo da efetivação da responsabilidade contraordenacional a que houver lugar e, nomeadamente, do cancelamento imediato da licença.
  5 - A','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s entidades referidas no n.º 1, por sua iniciativa ou a pedido das entidades gestoras de plataformas, devem ainda, sempre que necessário, fazer recomendações, prestar esclarecimentos e emitir deliberações de orientação, por forma a clarificar dúvidas sobre o alcance de requisitos funcionais e outras obrigações legais previstas na presente lei.            
         
   
     
                         
                          
  Artigo 80.º 
Auto de notícia
                            
                           
                             
                               
                             
     1 - Quando o pessoal do IMPIC, I. P., ou do GNS identificar, no exercício das suas competências, por denúncia ou constatação própria, a prática de uma contraordenação, levanta ou manda levantar auto de notícia, que deve mencionar os factos que constituem a infração, bem como o dia, a hora, o local e as circunstâncias em que a mesma foi cometida e tudo o que tenha averiguado acerca da identificação dos infratores e a indicação, quando possível, de, pelo menos, uma testemunha que possa depor sobre os factos.
  2 - O auto de notícia previsto no número anterior deve ser redigido num prazo máximo de 30 dias, sendo assinado pelo agente que o levantou e pelas testemunhas, quando as houver.
  3 - O auto de notícia levantado nos termos dos números anteriores faz fé, até prova em contrário, sobre os factos presenciados pelo autuante.            
         
   
     
                         
                          
  Artigo 81.º 
Contraordenações
                            
                           
                             
                               
                             
     As infrações ao disposto na presente lei constituem contraordenações, nos termos dos artigos seguintes.            
         
   
     
                         
                          
  Artigo 82.º 
Infrações muito graves
                            
                           
                             
                               
                             
     Constituem infrações muito graves:
  a) O exercício da atividade de gestão e exploração de plataformas eletrónicas por empresa que não disponha de licença emitida pelo IMPIC, I. P., nos termos do n.º 1 do artigo 13.º;
  b) A violação da regra de segurança prevista no n.º 3 do artigo 69.º que impede que os documentos classificados sejam visíveis por outras pessoas além dos membros do júri do procedimento;
  c) A violação da regra de segurança prevista no n.º 1 do artigo 73.º que impede que as entidades adjudicantes e os restantes concorrentes tomem conhecimento do conteúdo das propostas, candidaturas e soluções antes de expirado o prazo previsto para a sua apresentação;
  d) A violação da regra de segurança prevista no n.º 1 do artigo 74.º que impede que as propostas sejam disponibilizadas ao júri antes do termo do prazo para a respetiva apresentação.            
         
   
     
 ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                        
                          
  Artigo 83.º 
Infrações graves
                            
                           
                             
                               
                             
     Constituem infrações graves:
  a) A violação da obrigação prevista no n.º 1 do artigo 6.º que determina que a plataforma eletrónica garanta tecnologicamente a possibilidade de livre escolha dos prestadores e dos serviços de certificação eletrónica, por parte das entidades adjudicantes e por parte dos operadores económicos no âmbito dos procedimentos de formação de contratos públicos;
  b) O incumprimento da obrigação prevista no n.º 5 do artigo 12.º que determina a correção, pela empresa gestora da plataforma, das situações anómalas detetadas em nova auditoria efetuada pelo auditor de segurança;
  c) O incumprimento da obrigação prevista no n.º 6 do artigo 12.º que determina que, verificando-se o cancelamento da licença, nos termos do n.º 5 do mesmo artigo, a entidade gestora da plataforma deve transferir, no prazo de 30 dias, para cada entidade adjudicante, toda a informação e documentação atinente aos respetivos procedimentos de formação de contratos públicos em curso, que devem prosseguir, posteriormente, noutra plataforma eletrónica licenciada pelo IMPIC, I. P.;
  d) O incumprimento da obrigação de entrega ao IMPIC, I. P., de cópia eletrónica dos arquivos relativos aos procedimentos de contratação pública conduzidos na respetiva plataforma eletrónica em caso de cancelamento da licença, no prazo de 15 dias da respetiva ocorrência, prevista no n.º 4 do artigo 19.º;
  e) O incumprimento da obrigação de manter, a todo o tempo, o cumprimento dos requisitos gerais de licenciamento enumerados no artigo 15.º, prevista na alínea a) do artigo 20.º;
  f) O incumprimento da obrigação de implementar um sistema de gestão de sistemas de informação baseado na Norma ISO/IEC 20000 prevista na alínea c) do artigo 20.º;
  g) O incumprimento da obrigação de implementar um sistema de gestão de segurança da informação baseado na Norma ISO/IEC 27001 prevista na alínea d) do artigo 20.º;
  h) O incumprimento da obrigação de dispor e manter um arquivo organizado dos contratos de prestação de serviços celebrados no exercício da atividade, há menos de 10 anos contados desde a respetiva assinatura, prevista na alínea e) do artigo 20.º;
  i) O incumprimento da obrigação de dispor de um sistema eletrónico de gestão de reclamações, prevista na alínea f) do artigo 20.º;
  j) A violação da obrigação de facultar ao IMPIC, I. P., e ao GNS o acesso às instalações, ao equipamento e aos sistemas conexos com a atividade de gestão da plataforma eletrónica, bem como às informações, documentação e demais elementos relacionados com a mesma que lhes sejam solicitados por aquelas entidades, prevista no n.º 1 do artigo 21.º;
  k) O incumprimento da obrigação de comunicar ao IMPIC, I. P., e ao GNS qualquer alteração verificada nos requisitos gerais de lice','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nciamento previstos no artigo 15.º a contar da respetiva ocorrência, prevista na alínea a) do n.º 1 do artigo 21.º;
  l) O incumprimento da obrigação de comunicar ao IMPIC, I. P., a cessação da respetiva atividade em território nacional, prevista na alínea b) do n.º 1 do artigo 21.º;
  m) O incumprimento da obrigação de comunicar aos utilizadores a intenção de cessar a atividade de prestação de serviços de gestão da plataforma eletrónica indicando a entidade a quem a documentação será transmitida com a antecedência mínima de 90 dias, prevista no n.º 3 do artigo 22.º;
  n) O incumprimento da obrigação de disponibilizar a qualquer operador económico, a título gratuito, até três acessos, em simultâneo, aos serviços base da plataforma eletrónica, prevista no n.º 2 do artigo 23.º;
  o) O incumprimento da obrigação de disponibilizar o acesso, a título gratuito, às funcionalidades essenciais referidas nas alíneas a) a j) do n.º 1 do artigo 24.º;
  p) O incumprimento da obrigação de conceder o acesso aos serviços base da plataforma eletrónica aos operadores económicos registados numa plataforma, prevista no n.º 2 do artigo 24.º;
  q) O incumprimento da obrigação de garantir que, em caso de cessação da atividade, a informação constante da plataforma eletrónica, respeitante a procedimentos de contratação pública já concluídos, bem como todos os arquivos de auditoria transitam, para efeitos de custódia, para as entidades adjudicantes de cada procedimento e que são asseguradas as condições de leitura de todos os documentos, prevista na alínea a) do artigo 26.º;
  r) O incumprimento da obrigação de garantir que os procedimentos de contratação pública em curso seguem a sua tramitação até à conclusão, sem qualquer encargo adicional para a entidade adjudicante e para os operadores económicos interessados, candidatos e concorrentes em caso de cessação da atividade contratada, prevista na alínea b) do artigo 26.º;
  s) A violação da obrigação de manter as plataformas eletrónicas disponíveis, sem constituir um fator de restrição no acesso dos potenciais interessados aos procedimentos de formação de contratos públicos, prevista no n.º 1 do artigo 28.º;
  t) O incumprimento da obrigação de manutenção do acesso às plataformas eletrónicas e aos seus instrumentos permanentemente disponível a todos os interessados, salvo nos casos em que as limitações de acesso se justifiquem por razões de manutenção ou avaria dos sistemas, prevista no n.º 2 do artigo 28.º;
  u) O incumprimento da obrigação de utilizar e disponibilizar aos operadores económicos interessados, candidatos ou concorrentes, instrumentos, produtos, aplicações e programas informáticos, bem como as respetivas especificações técnicas, compatíveis com os produtos de uso corrente no domínio das tecnologias da informação e da comunicação, de forma a evitar situações discriminatórias, prevista no n.º 1 do artigo 29.º;
  v) A violação da obrigação de não exigir, para efeitos de acesso ao sistema de contratação da plat','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('aforma eletrónica, o cumprimento de requisitos injustificados, não proporcionais ou que de forma alguma consubstanciem um fator de discriminação, prevista no n.º 2 do artigo 29.º;
  w) O incumprimento dos requisitos funcionais estabelecidos nos artigos 27.º, 30.º, 31.º e 33.º;
  x) O incumprimento dos requisitos técnicos estabelecidos nos artigos 34.º e 35.º, no n.º 1 do artigo 36.º, nos n.os 1 e 2 do artigo 37.º e no artigo 38.º;
  y) O incumprimento dos requisitos de segurança estabelecidos nos artigos 39.º a 53.º, nos n.os 8 e 9 do artigo 54.º, nos n.os 3, 4 e 5 do artigo 55.º e nos artigos 56.º a 59.º;
  z) O incumprimento da obrigação de operacionalização de um sistema de aviso de receção eletrónico que comprove o sucesso do envio dos documentos que constituem a proposta, a candidatura ou as soluções, bem como a data e hora da submissão, prevista no n.º 3 do artigo 65.º;
  aa) O incumprimento da obrigação de garantir a possibilidade de determinação precisa da data e hora da transmissão da proposta, da candidatura ou das soluções e a inscrição daqueles dados na proposta no momento da sua receção, prevista no n.º 4 do artigo 65.º;
  bb) O incumprimento da obrigação de envio do aviso de receção eletrónico para o interessado, prevista no n.º 5 do artigo 65.º;
  cc) O incumprimento da obrigação de disponibilizar recibo eletrónico, o qual é anexado à proposta, prevista no n.º 5 do artigo 66.º;
  dd) O incumprimento da obrigação de disponibilizar um sistema de identificação que respeite os requisitos previstos no Portal dos Contratos Públicos para efeitos da transmissão da informação relativa a essa identificação da plataforma eletrónica para o Portal, prevista no n.º 5 do artigo 67.º;
  ee) O incumprimento da obrigação de carregamento das propostas nas condições previstas nos n.os 1 a 16 do artigo 68.º;
  ff) O incumprimento da obrigação de submissão das propostas nas condições previstas nos n.os 1 a 5 do artigo 70.º;
  gg) O incumprimento da obrigação de garantir que os concorrentes recebem um recibo eletrónico comprovativo da submissão da proposta nas condições previstas nos n.os 1 a 3 do artigo 71.º;
  hh) O incumprimento da obrigação de garantir que os concorrentes podem consultar as propostas submetidas nos termos estabelecidos no n.º 4 do artigo 71.º;
  ii) O incumprimento da obrigação de transmitir para o Portal dos Contratos Públicos, no prazo de 10 dias úteis após a disponibilização e abertura das propostas, a informação contida na ficha de abertura das mesmas, prevista no n.º 4 do artigo 76.º;
  jj) O incumprimento da obrigação prevista no n.º 3 do artigo 79.º que determina a correção, pela empresa gestora da plataforma, das situações anómalas detetadas em auditoria realizada pelo IMPIC, I. P., ou pelo GNS.            
         
   
     
                         
                          
  Artigo 84.º 
Infrações leves
                            
                           
                             
                               ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
                             
     Constituem infrações leves:
  a) O incumprimento da obrigação de comunicar ao IMPIC, I. P., a criação de sucursais, agências, estabelecimentos, locais de atendimento e outras formas de representação comercial da empresa relacionadas com a atividade de gestão de plataformas eletrónicas em território nacional, prevista na alínea c) do n.º 1 do artigo 21.º;
  b) O incumprimento da obrigação, prevista no n.º 2 do artigo 21.º, de informar o IMPIC, I. P., e o GNS, no prazo de 30 dias a contar da respetiva ocorrência, de todas as alterações que impliquem atualização de dados identificativos da empresa pelas empresas gestoras estabelecidas em território nacional e pelas sociedades com sede em território nacional ou constituídas ao abrigo da lei portuguesa;
  c) O incumprimento da obrigação, prevista no n.º 2 do artigo 21.º, de informar o IMPIC, I. P., e o GNS, no prazo de 30 dias a contar da respetiva ocorrência, de quaisquer modificações introduzidas no respetivo contrato de sociedade, pelas sociedades com sede em território nacional ou constituídas ao abrigo da lei portuguesa;
  d) O incumprimento da obrigação de intervir e de prestar auxílio, quando necessário ou seja solicitado pelos clientes, no esclarecimento de eventuais dúvidas na utilização da plataforma eletrónica por parte dos representantes da entidade adjudicante ou dos interessados no procedimento contratual, prevista na alínea a) do n.º 1 do artigo 22.º;
  e) O incumprimento da obrigação de garantir um canal de comunicação entre os vários intervenientes, prevista na alínea b) do n.º 1 do artigo 22.º;
  f) O incumprimento da obrigação de disponibilizar relatórios de anomalias, registos de acesso, submissões ou outra informação relevante para efeitos de tomada de decisões que surjam nos procedimentos de formação de um contrato público, quando solicitada pelo respetivo júri, prevista na alínea c) do n.º 1 do artigo 22.º;
  g) O incumprimento da obrigação de disponibilizar uma linha de apoio aos utilizadores, nas condições previstas nas subalíneas i) a iii) da alínea d) do n.º 1 do artigo 22.º;
  h) O incumprimento da obrigação de disponibilizar na plataforma eletrónica dos contactos de suporte e de apoio técnico prevista no n.º 2 do artigo 22.º;
  i) O incumprimento da obrigação de publicitar em local público da plataforma eletrónica a tabela de preços de todos os serviços oferecidos, com indicação expressa da data da sua entrada em vigor, prevista no n.º 4 do artigo 23.º;
  j) O incumprimento da obrigação de garantir que o processo de registo nas plataformas eletrónicas, na modalidade gratuita, não excede três dias úteis, prevista no n.º 3 do artigo 28.º;
  k) O incumprimento da obrigação de garantir que a manutenção dos dados dos operadores económicos e dos utilizadores é feita pelos próprios utilizadores de forma autónoma e gratuita, prevista no n.º 4 do artigo 28.º;
  l) O incumprimento da obrigação de garantir que as operações de manutenção das platafo','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rmas eletrónicas que limitem a disponibilidade de serviço são realizadas entre as 00h00 e as 8h00, nos dias úteis, ou aos sábados, domingos e feriados, com vista a minorar os constrangimentos causados aos utilizadores, prevista no n.º 5 do artigo 28.º;
  m) O incumprimento da obrigação de garantir que as operações de manutenção são comunicadas aos utilizadores com 72 horas de antecedência e ao IMPIC, I. P., no prazo de 24 horas após a sua ocorrência, prevista no n.º 6 do artigo 28.º;
  n) O incumprimento da obrigação de indicar a forma de obter os programas informáticos utilizados, bem como os respetivos comandos e instruções, prevista no n.º 3 do artigo 29.º;
  o) O incumprimento da obrigação de utilizar aplicações e programas informáticos com manual de instalação e utilização, permitindo o acesso a um utilizador com habilitações adequadas nos domínios das tecnologias da informação e comunicação, prevista no n.º 4 do artigo 29.º;
  p) O incumprimento da obrigação prevista no n.º 1 do artigo 61.º, que consiste em garantir que as notificações sujeitas a determinado prazo nos termos do CCP são feitas através das plataformas eletrónicas por via do envio automático de mensagens eletrónicas, disponíveis para consulta na área exclusiva respetiva;
  q) O incumprimento da obrigação prevista no n.º 2 do artigo 61.º que impõe o registo das datas precisas das notificações e comunicações, de acordo com o artigo 469.º do CCP;
  r) O incumprimento da obrigação de disponibilização dos documentos nas condições estabelecidas nos n.os 1 a 6 do artigo 62.º;
  s) O incumprimento da obrigação de disponibilizar aos interessados a indicação da data e hora de termo do prazo para a apresentação dos pedidos de esclarecimento e das propostas, bem como da data e hora de termo do prazo para a apresentação da lista, prevista no artigo 61.º do CCP, na qual sejam identificados erros e omissões do caderno de encargos, prevista no n.º 1 do artigo 63.º;
  t) O incumprimento da obrigação de incluir as funcionalidades previstas nas alíneas a) a c) do n.º 1 do artigo 66.º para efeitos do carregamento de uma proposta, no âmbito de um procedimento de formação de um contrato público;
  u) O incumprimento da obrigação de dispor das funcionalidades previstas nos n.os 1 a 5 do artigo 72.º relativas à ordenação dos interessados e dos concorrentes;
  v) O incumprimento da obrigação de garantir, para cada procedimento, a construção automática da ficha prévia de abertura de propostas, prevista no n.º 1 do artigo 75.º            
         
   
     
                         
                          
  Artigo 85.º 
Coimas
                            
                           
                             
                               
                             
     Às infrações previstas na presente lei são aplicáveis as seguintes coimas:
  a) Entre (euro) 75 000 e (euro) 100 000, para as infrações muito graves referidas no artigo 82.º;
  b) Entre (euro) 10 000 e (euro) 50 000, para as','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' infrações graves referidas no artigo 83.º;
  c) Entre (euro) 2 500 e (euro) 20 000, para as infrações leves referidas no artigo 84.º            
         
   
     
                         
                          
  Artigo 86.º 
Negligência e tentativa
                            
                           
                             
                               
                             
     1 - A negligência é punível, sendo os limites mínimos e máximos das coimas reduzidos a metade.
  2 - A tentativa é punível com a coima aplicável à contraordenação consumada especialmente atenuada.            
         
   
     
                         
                          
  Artigo 87.º 
Admoestação
                            
                           
                             
                               
                             
     1 - Quando a contraordenação for qualificada como leve e a infração consistir em irregularidade sanável e não haja indício de que a sua prática tenha causado prejuízos a terceiros, pode o IMPIC, I. P., antes da instauração do processo de contraordenação, notificar o infrator para sanar a irregularidade.
  2 - Da notificação deve constar a descrição da infração, as medidas necessárias para a sua regularização, o prazo para o cumprimento das mesmas, a forma de comprovação, junto do IMPIC, I. P., desse cumprimento e a advertência de que o incumprimento, no prazo determinado, dá lugar à instauração de processo de contraordenação.
  3 - O disposto nos números anteriores não se aplica ao infrator que tiver sido admoestado ou sancionado pela prática de infração da mesma natureza, no decurso dos últimos dois anos.            
         
   
     
                         
                          
  Artigo 88.º 
Sanção acessória
                            
                           
                             
                               
                             
     1 - Nos casos em que sejam aplicadas às empresas gestoras as sanções previstas nas alíneas a) a d) do artigo 82.º, pode ser aplicada a sanção acessória de interdição temporária do exercício da atividade prevista na presente lei.
  2 - A sanção referida no número anterior tem a duração máxima de dois anos a contar da decisão condenatória definitiva.            
         
   
     
                         
                          
  Artigo 89.º 
Instrução dos processos de contraordenação e aplicação de sanções
                            
                           
                             
                               
                             
     1 - Compete ao IMPIC, I. P., instruir os processos de contraordenação e ao respetivo conselho diretivo a aplicação das coimas e da sanção acessória.
  2 - A aplicação da sanção acessória é publicitada no Portal dos Contratos Públicos.            
         
   
     
                         
                          
  Artigo 90.º 
Cobrança coerciva das coimas
 ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                           
                           
                             
                               
                             
     As coimas aplicadas em processo de contraordenação por decisão tornada definitiva, quando não pagas, são objeto de cobrança coerciva através de processo de execução fiscal, nos termos do Código de Procedimento e de Processo Tributário.            
         
   
     
                         
                          
  Artigo 91.º 
Produto das coimas
                            
                           
                             
                               
                             
     O produto das coimas reverte em:
  a) 60 /prct. para os cofres do Estado;
  b) 30 /prct. para o IMPIC, I. P.;
  c) 10 /prct. para o GNS.            
         
   
     
                         
                          
  CAPÍTULO IX
  Disposições complementares, transitórias e finais  Artigo 92.º 
Taxas
                            
                           
                             
                               
                             
     1 - As empresas gestoras de plataformas eletrónicas licenciadas pelo IMPIC, I. P., estão sujeitas ao pagamento de taxas destinadas a cobrir os encargos com a gestão do sistema de licenciamento, bem como com a monitorização e a fiscalização da respetiva atividade em território nacional.
  2 - As taxas referidas no número anterior constituem receita do IMPIC, I. P., e são objeto de regulamentação por portaria dos membros do Governo responsáveis pelas áreas das finanças e da economia.
  3 - As taxas relativas aos serviços prestados pelo GNS enquanto entidade credenciadora constituem receita deste serviço e são objeto de regulamentação por portaria dos membros do Governo responsáveis pelas áreas das finanças e da tutela do GNS.            
         
   
     
                         
                          
  Artigo 93.º 
Norma transitória
                            
                           
                             
                               
                             
     1 - O GNS dispõe de:
  a) 60 dias após a entrada em vigor da presente lei para publicação da norma técnica;
  b) 60 dias após o pedido por parte das entidades gestoras das plataformas para concluir o processo de credenciação das respetivas equipas de segurança.
  2 - As empresas gestoras das plataformas eletrónicas dispõem de:
  a) 120 dias após a publicação da norma técnica do GNS para solicitar a auditoria anual de segurança ao auditor de segurança credenciado pelo GNS;
  b) 30 dias após a publicação da norma técnica do GNS para solicitar a credenciação das respetivas equipas de segurança;
  c) 30 dias após entrega do relatório anual de segurança conforme o disposto do n.º 3 do artigo 12.º, para assegurar o pedido de licenciamento da respetiva plataforma eletrónica, nos termos do artigo 14.º;
  d) 60 dias após a entrada em vigor da presente lei para assegu','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rar o cumprimento das obrigações resultantes da aplicação do artigo 6.º;
  e) 10 dias para aceitar a verificação da identidade de utilizadores e operadores económicos, nos termos do n.º 3 do artigo 48.º
  3 - As entidades gestoras podem, no prazo máximo de 180 dias a partir da entrada em vigor da presente lei, denunciar os contratos celebrados com as entidades adjudicantes, desde que da aplicação da presente lei resulte, fundamentadamente, um sobrecusto que não seja passível de ser suportado pelas entidades gestoras ao abrigo do contrato objeto de denúncia.
  4 - A denúncia prevista no número anterior apenas produz efeitos 90 dias após a notificação da entidade gestora à entidade adjudicante.            
         
   
     
                         
                          
  Artigo 94.º 
Norma revogatória
                            
                           
                             
                               
                             
     São revogados:
  a) O  Decreto-Lei n.º 143-A/2008, de 25 de julho;
  b) A  Portaria n.º 701-G/2008, de 29 de julho.            
         
   
     
                         
                          
  Artigo 95.º 
Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor 60 dias após a sua publicação.
  
  Aprovada em 3 de julho de 2015.
  A Presidente da Assembleia da República, Maria da Assunção A. Esteves.
  Promulgada em 10 de agosto de 2015.
  Publique-se.
  O Presidente da República, Aníbal Cavaco Silva.
  Referendada em 11 de agosto de 2015.
  O Primeiro-Ministro, Pedro Passos Coelho.            
         
   
     
                         
                          
  ANEXO I 
Condições mínimas do seguro de responsabilidade civil
                            
                           
                             
                               
                             
     (a que se refere o n.º 2 do artigo 18.º)
  1 - As empresas gestoras estabelecidas em território nacional devem possuir um seguro destinado a garantir a responsabilidade civil por danos patrimoniais causados no exercício da atividade.
  2 - O contrato de seguro assegura, no mínimo, o pagamento de indemnizações para ressarcimento dos danos patrimoniais, causados a terceiros, decorrentes de ações ou omissões das empresas gestoras ou dos seus representantes legais e colaboradores, ou do incumprimento de outras obrigações resultantes do exercício da atividade, ainda que, sem prejuízo do disposto no número seguinte, se verifique:
  a) A cessação da atividade de gestão de plataformas eletrónicas;
  b) A caducidade do certificado para o exercício da atividade de gestão de plataformas eletrónicas, em virtude da sua não revalidação;
  c) A resolução do contrato de seguro de responsabilidade civil.
  3 - Da apólice de seguro deve constar expressamente que, nos casos previsto','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s nas alíneas do número anterior e independentemente da respetiva causa, o seguro responde pelos danos ocorridos no decurso da vigência do contrato e reclamados até um ano após a data da cessação da atividade, da caducidade ou do cancelamento da licença ou da resolução do contrato de seguro.
  4 - Em caso de suspensão da licença, o contrato de seguro caduca às 24 horas do próprio dia da sua verificação.
  5 - Verificada a caducidade do contrato de seguro nos termos do número anterior, procede-se ao estorno do prémio, em montante proporcional ao período de tempo que decorreria até à data do seu vencimento.
  6 - O tomador do seguro deve comunicar ao segurador, no prazo de 48 horas, a suspensão da licença.
  7 - Nos casos previstos nas alíneas a) e b) do n.º 2 do presente anexo, o contrato de seguro caduca às 24 horas do próprio dia da sua verificação, devendo o tomador do seguro comunicar tal ocorrência ao segurador no prazo de 24 horas.
  8 - É obrigação do Instituto dos Mercados Públicos, do Imobiliário e da Construção, I. P., dar conhecimento ao segurador do cancelamento do certificado da empresa gestora.
  9 - O contrato de seguro pode excluir:
  a) A responsabilidade por danos decorrentes da falta de capacidade e legitimidade para contratar das pessoas que intervêm em negócios com empresas gestoras, quando estes factos lhes sejam dolosamente ocultados por aquelas;
  b) A responsabilidade pelos danos decorrentes da impossibilidade de cumprimento de deveres contratuais ou quaisquer obrigações legais por facto de força maior não imputável à empresa gestora;
  c) A responsabilidade pelo pagamento de danos decorrentes de reclamações resultantes ou baseadas, direta ou indiretamente, na aplicação de quaisquer fianças, taxas, multas ou coimas, impostas por autoridades competentes, bem como de outras penalidades de natureza sancionatória ou fiscal e por indemnizações fixadas a título punitivo, de danos exemplares ou outras reclamações de natureza semelhante.
  10 - O contrato de seguro pode prever o direito de regresso do segurador nos seguintes casos:
  a) Responsabilidade por danos decorrentes da atuação dolosa do segurado ou quando o ato por este praticado seja qualificado como crime ou contraordenação;
  b) Quando a responsabilidade do segurado decorrer de perda ou extravio de dinheiro ou quaisquer outros valores ou documentos colocados à sua guarda;
  c) Quando a responsabilidade decorrer de factos praticados pela empresa gestora para obtenção de benefícios e ou redução de custos de natureza fiscal, causando danos a todos os interessados que não conheciam os factos em questão;
  d) Quando a responsabilidade decorrer de atos ou omissões praticados pelo segurado ou por pessoa por quem este seja civilmente responsável sob a influência de embriaguez, uso de estupefacientes ou demência;
  e) Quando o contrato de prestação de serviços de gestão de plataformas eletrónicas for nulo por vício de forma.
  11 - O contrato de seguro pode prever uma franquia ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a cargo do segurado, não oponível ao terceiro lesado.            
         
   
     
                         
                          
  ANEXO II 
Regras para a codificação das candidaturas, das propostas e das soluções
                            
                           
                             
                               
                             
     (a que se referem a alínea d) do n.º 3 do artigo 64.º, o n.º 3 do artigo 67.º, os n.os 7 e 13 do artigo 68.º e o n.º 4 do artigo 70.º)
  Regras a utilizar na codificação das propostas apresentadas:
  a) O código identificador das propostas resulta da agregação de dois subcódigos, separados por um ponto, respeitantes ao lote do procedimento e à proposta propriamente dita, mesmo que não haja divisão do procedimento em lotes;
  b) O primeiro subcódigo assume o valor 0 quando não existam lotes e números de ordem a partir de 1 para identificar cada lote, quando existam;
  c) O segundo subcódigo assume o valor 0 para uma proposta base e números de ordem a partir de 1 para identificar cada proposta variante.
  Como forma de assegurar um maior esclarecimento apresentam-se quatro exemplos de códigos de propostas:
  0.0 - Não há divisão do procedimento em lotes; proposta base;
  0.2 - Não há divisão do procedimento em lotes; segunda proposta variante;
  3.0 - Terceiro lote de um procedimento; proposta base respetiva;
  2.3 - Segundo lote de um procedimento; terceira proposta variante respetiva.','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:20  
    
  DL n.º 201/2003, de 10 de Setembro  (versão actualizada) REGULA O REGISTO INFORMÁTICO DE EXECUÇÕES    
    
 
Contém as seguintes alterações:   - DL n.º 53/2004, de 18 de Março   - Lei n.º 60-A/2005, de 30 de Dezembro   - DL n.º 226/2008, de 20 de Novembro  
                         
                          
SUMÁRIORegula o registo informático de execuções previsto no Código de Processo Civil
   
O novo regime jurídico da acção executiva, aprovado pelo Decreto-Lei n.º 38/2003, de 8 de Março, tem como objectivo claro a simplificação e aperfeiçoamento do actual processo executivo, pondo termo a uma excessiva morosidade para a qual contribuía a forte jurisdicionalização e rigidez dos actos praticados no âmbito do mesmo. 
  Nessa medida, com o intuito de evitar o impulso processual que venha a revelar-se improfícuo, mas sobretudo de agilizar a fase processual da penhora, conferindo-lhe maior eficácia, o novo regime do processo executivo prevê a existência de um registo informático das execuções. 
  Pretende-se ainda, com este registo, prevenir potenciais litígios jurisdicionais através do acesso concedido à informação dele constante por parte de quem tenha uma relação contratual ou pré-contratual com o titular dos dados. 
  Cabe, aliás, referir que a informação constante deste registo informático já é, na sua totalidade, de acesso público, constando dos processos judiciais pendentes em tribunal. 
  Com essas finalidades, esse registo informático disponibilizará todas as informações necessárias à realização da penhora, nomeadamente um rol dos processos de execução pendentes contra o executado, bem como informação sobre os bens já penhorados no património do mesmo e ainda um elenco das acções instauradas contra o exequente que foram declaradas findas ou suspensas. 
  A qualidade e tratamento dos dados não foi descurada, pelo que o seu registo e actualização, bem como o registo diário dos pedidos de consulta, dos acessos ao registo informático e dos certificados emitidos, é assegurado pela secretaria. Ainda no âmbito desta matéria, foi atribuída ao titular dos dados a faculdade de requerer, a todo o tempo, a actualização ou rectificação dos dados inscritos no registo. 
  Com o fito de proteger os dados de acessos ilegítimos, estabelece-se que apenas poderão proceder à consulta do registo informático de execuções determinadas categorias de pessoas: os magistrados judiciais ou do Ministério Público, as pessoas capazes de exercer o mandato judicial ou os solicitadores de execução, quando munidos de título executivo, o mandatário constituído ou o agente de execução nomeado, o próprio titular dos dados e ainda qualquer pessoa que tenha uma relação contratual ou pré-contratual com o executado, neste último caso mediante autorização judicial e verificados determinados requisitos legais. 
  Ponderados a natureza dos dados inscritos no registo e os objectivos da reforma, as únicas entidades com acesso directo ao registo são os magistr','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ados judiciais ou do Ministério Público; nas restantes situações, a consulta do registo de execuções depende de pedido formulado em requerimento cujo modelo consta de portaria do Ministro da Justiça. 
  Ainda em obediência a objectivos de garantia da segurança da informação contida no registo de execuções, foram adoptadas medidas legislativas adequadas a proteger os dados pessoais, cabendo ao director-geral da Administração da Justiça velar pela utilização das medidas eficazes à prossecução desse propósito. 
  Com este diploma dá-se, assim, cumprimento ao disposto no n.º 4 do artigo 807.º do Código de Processo Civil, na redacção que lhe foi conferida pelo Decreto-Lei n.º 38/2003, de 8 de Março. 
  Nos termos do n.º 2 do artigo 22.º da Lei n.º 67/98, de 26 de Outubro, foi ouvida a Comissão Nacional de Protecção de Dados. 
  Assim: 
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte:
    
  Artigo 1.º Objecto e finalidade do registo
                            
                           
                             
                               
                             
     1 - O registo informático de execuções contém o rol das execuções cíveis, dos processos laborais de execução e dos processos especiais de insolvência e recuperação de empresas.
  2 - O registo informático tem como finalidade a criação de mecanismos expeditos para conferir eficácia à penhora e à liquidação de bens. 
  3 - O registo informático tem ainda como finalidade a prevenção de eventuais conflitos jurisdicionais resultantes de incumprimento contratual.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 2.º Dados do registo
                            
                           
                             
                               
                             
     1 - O registo informático de execuções contém o rol das execuções pendentes e, relativamente a cada uma delas, a seguinte informação:
  a) Identificação da execução;
  b) Identificação do agente de execução, através de nome, domicílio profissional, números de cédula profissional e de identificação fiscal, ou do oficial de justiça, através de nome e número mecanográfico;
  c) Identificação das partes, nos termos da alínea a) do n.º 1 do artigo 467.º do Código de Processo Civil, incluindo ainda, sempre que possível, o número de identificação de pessoa colectiva, a filiação, o número de identificação fiscal, o número de bilhete de identidade ou, na impossibilidade atendível da sua apresentação, os números de passaporte ou de licença de condução; 
  d) Pedido, indicando o fim e o montante, a coisa ou a prestação, consoante os casos; 
  e) Bens indicados para penhora; 
  f) Bens penhorados, com indicação da data e hora da penhora','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' e da adjudicação ou venda; 
  g) Identificação dos créditos reclamados, através do seu titular e montante do crédito. 
  h) Indicação da realização de citação edital.
  2 - Do mesmo registo consta também o rol das execuções findas ou suspensas, mencionando-se, além dos elementos referidos no número anterior: 
  a) A extinção com pagamento integral; 
  b) A extinção com pagamento parcial; 
  c) A extinção da execução por não terem sido encontrados bens penhoráveis, nos termos do disposto no n.º 3 do artigo 832.º e no n.º 6 do artigo 833.º-B do Código de Processo Civil.
  3 - Na sequência de despacho judicial, procede-se ainda à introdução dos seguintes dados: 
  a) A declaração de insolvência e a nomeação de um administrador da insolvência, bem como o encerramento do processo especial de insolvência; 
  b) O arquivamento do processo executivo de trabalho, por não se terem encontrado bens para penhora. 
  4 - Os dados previstos no número anterior são acompanhados da identificação do processo e da informação referida na alínea c) do n.º 1.
  5 - Não havendo indicação do número de identificação fiscal do titular dos dados ou, em alternativa, do número de identificação civil, passaporte ou licença de condução, deve o agente de execução promover as diligências necessárias à obtenção destes elementos, designadamente mediante consulta das bases de dados, arquivos e outros registos, nos termos previstos no artigo 833.º-A do Código de Processo Civil.
  6 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro).
  7 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro).            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 53/2004, de 18 de Março   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro    - 2ª versão: DL n.º 53/2004, de 18 de Março   
     
                         
                          
  Artigo 3.º Momento da inscrição
                            
                           
                             
                               
                             
     O agente de execução inscreve a execução no registo informático após a consulta prévia efectuada nos termos do artigo 832.º do Código de Processo Civil.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 4.º Modo de recolha e actualização
                            
                           
                             
                               
                             
     1 - Os dados do registo informático de execuções são inscritos e actualizados pelo agente de execução a partir dos elementos de que disponha.
  2 - Os dados constantes dos n.os 1 e 2 do artigo 2.º são introduzidos no prazo de dois dias úte','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('is após a sua obtenção.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 5.º Actualização, rectificação e eliminação dos dados
                            
                           
                             
                               
                             
     1 - A actualização ou rectificação dos dados inscritos no registo informático de execuções pode ser requerida pelo respectivo titular, a todo o tempo, junto da secretaria do tribunal materialmente competente.
  2 - A extinção da execução por procedência da oposição à execução ou por qualquer outro facto, com excepção dos previstos nas alíneas b) e c) do n.º 2 do artigo 2.º, determina a eliminação oficiosa do registo da execução.
  3 - O registo da execução finda com pagamento integral é igualmente eliminado oficiosamente, uma vez determinada ou verificada a extinção da execução.
  4 - A menção de execução finda com pagamento parcial ou de execução extinta, nos termos das alíneas b) e c) do n.º 2 do artigo 2.º, é eliminada a requerimento do devedor logo que este prove o cumprimento da obrigação.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 6.º Legitimidade para consultar o registo informático
                            
                           
                             
                               
                             
     1 - A consulta do registo informático de execuções pode ser efectuada: 
  a) Por magistrado judicial ou do Ministério Público; 
  b) Por pessoa capaz de exercer o mandato judicial ou agente de execução;
  c) (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro). 
  d) Pelo titular dos dados; 
  e) Por quem tenha relação contratual ou pré-contratual com o titular dos dados ou revele outro interesse atendível na consulta, mediante consentimento do titular ou autorização dada por entidade judicial. 
  2 - Para efeitos da alínea e) do número anterior, considera-se existir interesse atendível quando a consulta do registo informático de execuções se destine à obtenção de certificado para demonstração da natureza incobrável de créditos resultantes de incumprimento contratual.
  3- Para efeitos da alínea e) do número anterior, considera-se existir interesse atendível quando a consulta do registo informático de execuções se destine à obtenção de certificado para demonstração da natureza incobrável de créditos resultantes de incumprimento contratual.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 60-A/2005, de 30 de Dezembro   - DL ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro    - 2ª versão: Lei n.º 60-A/2005, de 30 de Dezembro   
     
                         
                          
  Artigo 7.º Competência para deferir a consulta
                            
                           
                             
                               
                             
     1 - O pedido de consulta é dirigido a qualquer tribunal cível.
  2 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro).            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 8.º Formas de acesso
                            
                           
                             
                               
                             
     1 - A consulta do registo de execuções pode ser feito pelas formas seguintes: 
  a) Certificado passado pela secretaria do tribunal; 
  b) Acesso directo. 
  2 - O certificado deve transcrever integralmente todos os dados que o registo de execuções contém relativamente ao titular de dados. 
  3 - O certificado é passado no prazo máximo de três dias úteis a contar da data em que foi requerido. 
  4 - A passagem do certificado pode ser requerida com urgência, quando se alegue fundamento razoável, sendo o mesmo passado com preferência sobre o restante serviço, dentro do prazo máximo de vinte e quatro horas. 
  5 - Pela passagem do certificado é devida a quantia de um quarto de unidade de conta, que reverte, na sua totalidade, para o Instituto de Gestão Financeira e de Infra-Estruturas das Justiça, I. P.
  6 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro). 
  7 - No caso de a passagem do certificado ser requerida com urgência, a quantia referida no número anterior é elevada ao dobro. 
  8 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro).            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 9.º Consulta por magistrados
                            
                           
                             
                               
                             
     Consulta por acesso directo
  1 - Os magistrados judiciais e do Ministério Público, as pessoas capazes de exercer o mandato judicial e os agentes de execução têm acesso directo ao registo informático, nos termos a definir por portaria do membro do Governo responsável pela área da justiça.
  2 - As pesquisas ou as tentativas de pesquisa directa de informação ficam registadas automaticamente por período nunca inferior a um ano.            
','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 10.º Consulta sem necessidade de autorização judicial
                            
                           
                             
                               
                             
     1 - O pedido de consulta pelo titular dos dados ou por quem tenha autorização do titular dos dados é dirigido à secretaria do tribunal competente.
  2 - O requerimento é formulado em modelo aprovado por portaria do Ministro da Justiça. 
  3 - A utilização do modelo para requerimento de certificado pode ser dispensada, em condições a fixar por despacho do director-geral da Administração da Justiça, quando o pedido é feito presencialmente nas secretarias judiciais. 
  4 - O requerimento é acompanhado de comprovativo do pagamento da quantia referida nos n.os 6 e 7 do artigo 8.º ou da estampilha aprovada pela Portaria n.º 233/2003, de 17 de Março, de igual valor. 
  5 - (Revogado pelo Decreto-Lei n.º 226/2008 de 20 de Novembro). 
  6 - O requerimento é assinado pelo requerente e contém a sua identificação bem como a indicação do titular dos dados a que respeita. 
  7 - A identificação do requerente é feita pelo nome, estado e residência sendo confirmada: 
  a) Pela exibição do bilhete de identidade ou de outro documento de identificação idóneo; 
  b) Pelo reconhecimento da assinatura ou pela aposição de assinatura electrónica. 
  8 - A passagem do certificado deve ser rejeitada se o requerente não tiver legitimidade ou não respeitar o disposto nos n.os 2 a 4, sendo o requerimento devolvido com decisão fundamentada do oficial de justiça.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 11.º Consulta com autorização do tribunal
                            
                           
                             
                               
                             
     1 - Nos casos referidos na alínea e) do n.º 1 do artigo 6.º, em que não haja autorização do titular dos dados, o requerimento de autorização para consulta do registo informático de execuções é dirigido ao juiz do tribunal competente, em modelo aprovado nos termos do n.º 2 do artigo anterior.
  2 - No requerimento deve o requerente: 
  a) Designar o tribunal; 
  b) Identificar-se, indicando o seu nome, residência e, sempre que possível, filiação, número de bilhete de identidade e identificação fiscal; 
  c) Identificar o titular dos dados a consultar, indicando os elementos de identificação referidos na alínea anterior; 
  d) Expor os factos e as razões que servem de fundamento ao pedi','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('do. 
  3 - O requerente deve ainda juntar comprovativo do pagamento da quantia referida nos n.os 6 e 7 do artigo 8.º ou estampilha, aprovada pela Portaria n.º 233/2003, de 17 de Março, de igual valor. 
  4 - A secretaria recusa o recebimento do requerimento, indicando por escrito o fundamento da rejeição, quando o requerente não cumpra o disposto nos números anteriores. 
  5 - Do acto de recusa de recebimento cabe reclamação para o juiz, não havendo recurso do despacho que confirme o não recebimento. 
  6 - Recebido o requerimento, o juiz, no prazo de 10 dias, profere despacho fundamentado destinado a: 
  a) Recusar a consulta do registo informático; 
  b) Autorizar a consulta do registo informático, ordenando a secretaria a passar o respectivo certificado. 
  7 - Não cabe recurso dos despachos referidos no número anterior.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 12.º Registo diário de acessos
                            
                           
                             
                               
                             
     1 - A secretaria assegura o registo diário dos pedidos de consulta, dos acessos ao registo informático de execuções e dos certificados emitidos, nos termos do disposto nos números seguintes, com o fim de evitar o acesso não autorizado aos dados pessoais recolhidos e de garantir o respectivo controlo administrativo. 
  2 - Feito o requerimento de consulta do registo de execuções, deve ser lançada a respectiva anotação no registo diário, que deve conter os seguintes elementos: 
  a) A data da entrada do requerimento;
  b) O nome do requerente ou o seu cargo, quando se trate de entidade oficial que nessa qualidade assine o requerimento; 
  c) O nome e número de identificação fiscal do titular dos dados de que se pretende obter informação. 
  3 - O registo diário deve permitir ainda a identificação dos utilizadores do registo informático de execuções, a data e a hora dos respectivos acessos, bem como uma relação discriminada dos certificados emitidos. 
  4 - Apenas os funcionários da secretaria poderão consultar o registo diário, de harmonia com as indicações dadas pelos interessados. 
  5 - Aos dados constantes do registo diário de acessos aplica-se, com as devidas adaptações, o disposto no n.º 1 do artigo 5.º e no artigo seguinte.            
         
   
     
                         
                          
  Artigo 13.º Conservação dos dados
                            
                           
                             
                               
                             
     Sem prejuízo do previsto no artigo 5.º relativamente à eliminação de determinados dados, os dados constantes do registo informático de execuções são conservados em registo até','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 10 anos após a extinção da execução.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 226/2008, de 20 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 201/2003, de 10 de Setembro   
     
                         
                          
  Artigo 14.º Consulta para fins de investigação criminal ou estatística
                            
                           
                             
                               
                             
     1 - Os dados registados na base de dados podem ser consultados, pelas entidades competentes, para efeitos de investigação criminal ou de instrução em processos judiciais, sempre que os dados não possam ou não devam ser obtidos através das entidades a quem respeitam. 
  2 - A informação contida nos dados pode ser divulgada para fins de estatística, desde que não possam ser identificáveis as pessoas a quem respeitam.            
         
   
     
                         
                          
  Artigo 15.º Segurança dos dados
                            
                           
                             
                               
                             
     1 - São objecto de controlo, tendo em vista a segurança da informação:
  a) Os suportes de dados, a fim de impedir que possam ser lidos, copiados, alterados ou eliminados por qualquer pessoa ou por qualquer forma não autorizada; 
  b) A inserção de dados, a fim de impedir a introdução, bem como qualquer tomada de conhecimento, transmissão, alteração ou eliminação não autorizada de dados pessoais; 
  c) O acesso aos dados de modo que as pessoas autorizadas só possam ter acesso aos dados que interessem ao exercício dos seus interesses reconhecidos por lei; 
  d) A transmissão de dados, para garantir que a sua utilização seja limitada às entidades autorizadas; 
  e) A introdução de dados, de forma a verificar-se quando e por quem foram introduzidos. 
  2 - Compete ao director-geral da Administração da Justiça garantir o respeito pelo disposto no número anterior, nomeadamente através da implementação de sistemas de acesso mediante palavras-passe, medidas de restrição de acessos aos equipamentos e aplicações, bem como auditorias para verificação dos acessos ao registo informático de execuções, a realizar através dos mecanismos previstos no artigo 12.º            
         
   
     
                         
                          
  Artigo 16.º Regime transitório
                            
                           
                             
                               
                             
     No que respeita às acções entradas antes de 15 de Setembro de 2003, são desde já inscritos no registo informático das execuções os dados actualmente sujeitos a tratamento informático, sendo a inscrição dos restantes efectuada no prazo máximo de um ano a contar da entrada em vigor deste diploma.            
         
   
     
       ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                  
                          
  Artigo 16.º-A Objecto, finalidades e entidade responsável pela lista pública de execuções
                            
                           
                             
                               
                             
     1 - A lista de execuções extintas com pagamento parcial ou por não terem sido encontrados bens penhoráveis, previstas nas alíneas b) e c) do n.º 2 do artigo 2.º, consta de sítio da Internet de acesso público, em termos a regular por portaria do membro do Governo responsável pela área da justiça.
  2 - O executado é informado da inclusão do seu nome na lista pública de execuções nos termos da portaria referida no número anterior, que especifica o modo de notificação ao executado, bem como um prazo em que este, de modo a evitar a inclusão do seu nome na lista pública de execuções, pode:
  a) Promover o cumprimento da obrigação; ou
  b) Aderir a um plano de pagamento de dívidas nos termos do n.º 2 do artigo 16.º-C.
  3 - A lista pública das execuções tem as seguintes finalidades:
  a) Conferir eficácia à penhora e liquidação de bens;
  b) Prevenir eventuais conflitos jurisdicionais resultantes do incumprimento contratual; e
  c) Promover o cumprimento pontual das obrigações.
  4 - A Direcção-Geral da Administração da Justiça é a entidade responsável pelo tratamento dos dados constantes da lista pública de execuções.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 226/2008, de 20 de Novembro            
         
   
     
                         
                          
  Artigo 16.º-B Actualização e rectificação de registos na lista pública de execuções
                            
                           
                             
                               
                             
     1 - A lista identifica, relativamente a cada execução:
  a) O nome do executado;
  b) O número de identificação fiscal ou, em alternativa, os números de identificação civil, de passaporte ou de licença de condução;
  c) O valor em dívida;
  d) O facto que determinou a extinção da execução.
  2 - A actualização ou rectificação dos dados inscritos na lista de execuções pode ser efectuada oficiosamente pela secretaria ou requerida pelo respectivo titular nos termos previstos no artigo 5.º, bem como por via electrónica no sítio da Internet de onde conste.
  3 - A decisão do requerimento referido no número anterior tem natureza urgente e é adoptada pela secretaria no prazo máximo de dois dias úteis.
  4 - Caso a decisão prevista no número anterior não seja adoptada no prazo previsto, os dados do requerente, identificados na lista, são automática e electronicamente dela retirados até que haja decisão.
  5 - A ausência de decisão no prazo previsto no n.º 4 é comunicada ao Conselho Superior da Magistratura e ao Conselho dos Oficiais de Justiça, por via electrónica, em termos a regular por portaria do membro do Governo responsável pela área da justiça.
  6 - Da d','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ecisão da secretaria cabe impugnação para o juiz.
  7 - As decisões previstas nos números anteriores são, igualmente, e sempre que possível, notificadas por via electrónica, nos termos de portaria do membro do Governo responsável pela área da justiça.
  8 - Havendo lugar a rectificação, o interessado tem o direito, mediante solicitação, que os dados incorrectos constantes da lista de execuções extintas sejam substituídos pelo reconhecimento, expresso e com igual relevo, de se ter verificado a incorrecção.
  9 - O cumprimento da obrigação pelo devedor determina a exclusão da lista, aplicando-se o disposto no n.º 3 do artigo 5.º
  10 - À lista pública de execuções aplica-se, com as necessárias adaptações, o disposto no artigo 14.º e nas alíneas a), b) e e) do n.º 1 e no n.º 2 do artigo 15.º
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 226/2008, de 20 de Novembro            
         
   
     
                         
                          
  Artigo 16.º-C Eliminação e suspensão dos registos da lista pública de execuções
                            
                           
                             
                               
                             
     1 - Todos os registos constantes da lista pública de execuções referentes a processos executivos findos há mais de cinco anos são oficiosamente retirados.
  2 - Os registos referentes a execuções contra executados sobreendividados que adiram e cumpram um plano de pagamento de dívida elaborado por entidades reconhecidas pelo Ministério da Justiça, que prestem apoio a situações de sobreendividamento, podem ser suspensos durante o cumprimento do referido plano, nos termos a definir por portaria do membro do Governo responsável pela área da justiça.
  Aditado pelo seguinte diploma: Decreto-Lei n.º 226/2008, de 20 de Novembro            
         
   
     
                         
                          
  Artigo 17.º Entrada em vigor
                            
                           
                             
                               
                             
     O presente diploma entra em vigor no dia 15 de Setembro de 2003.
  Visto e aprovado em Conselho de Ministros de 31 de Julho de 2003. - José Manuel Durão Barroso - João Luís Mota de Campos. 
  Promulgado em 2 de Setembro de 2003.
  Publique-se.
  O Presidente da República, JORGE SAMPAIO.
  Referendado em 3 de Setembro de 2003.
  O Primeiro-Ministro, José Manuel Durão Barroso.','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:12  
    
  Portaria n.º 365/2017, de 07 de Dezembro  (versão actualizada) REGULAMENTA O SERVIÇO PÚBLICO DE NOTIFICAÇÕES ELETRÓNICAS (SPNE)    
    
 
  
                         
                          
SUMÁRIORegulamenta o Serviço Público de Notificações Eletrónicas (SPNE) associado à morada única digital, previsto no Decreto-Lei n.º 93/2017, de 1 de agosto
Portaria n.º 365/2017, de 7 de dezembro
  O Programa do XXI Governo Constitucional estabelece como uma das suas prioridades fortalecer, simplificar e digitalizar a Administração, com o propósito de a tornar mais eficiente e facilitadora da vida dos cidadãos e das empresas, através do lançamento do Programa SIMPLEX.
  Em preparação do SIMPLEX 2017 e em complemento da medida das notificações eletrónicas prevista no programa SIMPLEX 2016, o Decreto-Lei n.º 93/2017, de 1 de agosto, criou a morada única digital e o Serviço Público de Notificações Eletrónicas (SPNE) associado à morada única digital, regulando o envio e receção de notificações eletrónicas.
  A presente portaria define os termos e as condições de operacionalização do serviço público de notificações eletrónicas associado à morada única digital, na qual se preveem mecanismos que visam garantir especiais medidas de segurança, associadas a este sistema.
  Tais medidas de segurança traduzem-se, nomeadamente, por um lado na necessidade de encriptação das mensagens e dos restantes dados pessoais particularmente sensíveis. Por outro lado, importa garantir e manter o registo de todos os atos praticados no sistema de forma segura e credível, que constituem meios de prova da receção das notificações eletrónicas.
  Foi ouvida a Comissão Nacional de Proteção de Dados.
  Assim:
  Ao abrigo do artigo 16.º do  Decreto-Lei n.º 93/2017, de 1 de agosto, manda o Governo, pelo Ministro das Finanças, pela Secretária de Estado Adjunta e da Modernização Administrativa, pela Secretária de Estado da Justiça, pela Secretária de Estado da Segurança Social e pelo Secretário de Estado Adjunto e da Saúde, o seguinte:
  
  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     A presente portaria regulamenta o Serviço Público de Notificações Eletrónicas (SPNE) associado à morada única digital, previsto no  Decreto-Lei n.º 93/2017, de 1 de agosto, definindo:
  a) O sítio da Internet e a aplicação móvel a partir dos quais é possível aceder ao sistema informático de suporte ao SPNE;
  b) O sistema e os termos de adesão ao SPNE por parte das pessoas a notificar e respetivos mecanismos de autenticação;
  c) O mecanismo seguro de confirmação da titularidade efetiva do endereço de correio eletrónico escolhido;
  d) O mecanismo de reencaminhamento das notificações eletrónicas para a morada única digital da pessoa a notificar, bem como a respetiva periodicidade, no caso de impossibilidade de entrega da mesma;
  e) A definição dos sistemas e','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' dos mecanismos de interoperabilidade utilizados, incluindo os dados usados através do mecanismo de federação de identidades;
  f) A definição de canais de envio de alertas relativos ao envio de notificações.            
         
   
     
                         
                          
  Artigo 2.º 
Disponibilização do sistema de suporte ao SPNE
                            
                           
                             
                               
                             
     O SPNE está disponível em sítio próprio da Internet, acessível através do Portal de Cidadão, bem como acessível na respetiva aplicação móvel.            
         
   
     
                         
                          
  Artigo 3.º 
Termos de adesão e mecanismos de autenticação
                            
                           
                             
                               
                             
     1 - A adesão ao SPNE é realizada:
  a) Diretamente pelo interessado ou seu representante legal, no sítio da Internet ou na aplicação móvel referida no artigo anterior; ou
  b) Através de atendimento digital assistido, presencialmente nos balcões de atendimento dos Espaços cidadão, conservatórias e serviços da Autoridade Tributária e Aduaneira (AT), ou noutros locais protocolados, nos termos do n.º 2 do artigo 4.º do  Decreto-Lei n.º 93/2017, de 1 de agosto.
  2 - A adesão ao SPNE implica a verificação e a validação da identidade da pessoa aderente ou dos seus representantes legais, junto das bases de dados do Instituto dos Registos e Notariado, I. P., e da AT, consoante a natureza da pessoa aderente.
  3 - A verificação da identidade é efetuada através de:
  a) Cartão de Cidadão;
  b) Chave Móvel Digital;
  c) Certificado digital emitido por Estado membro da União Europeia no âmbito do STORK;
  d) Outro meio de identificação eletrónica reconhecido em Estados membros da União Europeia, designadamente a prevista no Regulamento (UE) n.º 910/2014, do Parlamento Europeu e do Conselho, de 23 de julho.
  4 - Pode ser usado o Sistema de Certificação de Atributos Profissionais para a certificação de atributos profissionais, empresariais e públicos do utilizador do SPNE.
  5 - A adesão ao SPNE carece de aceitação expressa das respetivas condições de utilização, nos termos do artigo seguinte.
  6 - Para finalizar a adesão e a respetiva fidelização do endereço de correio eletrónico ao SPNE, a pessoa aderente recebe no endereço de correio eletrónico escolhido uma mensagem com instruções para, no prazo máximo de 30 dias, concluir o processo de fidelização.
  7 - Caso o processo de fidelização não seja concluído nos termos do número anterior, a adesão ao SPNE e respetiva fidelização do endereço de correio eletrónico fica sem efeito.            
         
   
     
                         
                          
  Artigo 4.º 
Condições de segurança e utilização
                            
                           
        ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                     
                               
                             
     1 - A implementação e a manutenção do sistema de suporte ao SPNE reveste-se de especiais medidas de segurança, de forma a garantir a confidencialidade, integridade e autenticidade das notificações.
  2 - As condições de utilização do SPNE são definidas pela Agência para a Modernização Administrativa, I. P. (AMA, I. P.), no sítio da Internet e na aplicação móvel referida no artigo 2.º            
         
   
     
                         
                          
  Artigo 5.º 
Dados recolhidos para fidelização
                            
                           
                             
                               
                             
     1 - No processo de fidelização do endereço de correio eletrónico são recolhidos automaticamente, através do módulo de autenticação, os seguintes dados:
  a) Nome completo ou denominação social, bem como dos representantes legais;
  b) Número de identificação civil ou número de identificação fiscal, bem como dos representantes legais.
  2 - Para proceder à fidelização do endereço de correio eletrónico são recolhidos, através de inserção pelo utilizador, e tendo em vista a associação prevista no n.º 5 do artigo 4.º do Decreto-Lei n.º 93/2017, de 1 de agosto, os seguintes dados:
  a) Endereço de correio eletrónico escolhido;
  b) Número de telemóvel, de forma opcional.
  3 - As trocas de dados entre o sistema de suporte ao SPNE e os organismos que gerem as bases de dados de identificação civil, de identificação de pessoas coletivas e de identidade fiscal, no âmbito do processo de fidelização devem ser realizadas através do mecanismo de federação de identidades, salvaguardando a confidencialidade dos mesmos.            
         
   
     
                         
                          
  Artigo 6.º 
Vicissitudes
                            
                           
                             
                               
                             
     1 - O óbito das pessoas aderentes dá lugar ao cancelamento oficioso da adesão ao SPNE.
  2 - O óbito é comunicado ao SPNE, através da base de dados de registo civil, o qual intercomunica com o ciclo de vida do Cartão de Cidadão.            
         
   
     
                         
                          
  Artigo 7.º 
Adesão das entidades
                            
                           
                             
                               
                             
     1 - As entidades aderentes, referidas no n.º 1 do artigo 7.º do Decreto-Lei n.º 93/2017, de 1 de agosto, podem aderir ao SPNE mediante protocolo que define, nomeadamente as condições de utilização, os níveis de serviço, o prazo da manutenção das notificações, os requisitos e as normas técnicas necessárias e a eventual repartição de custos de operação.
  2 - A lista de entidades aderentes, bem como dos respetivos serviços disponibilizados fica p','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ermanentemente disponível no sítio da Internet do SPNE, na respetiva aplicação móvel e no Portal de Cidadão.            
         
   
     
                         
                          
  Artigo 8.º 
Envio das notificações electrónicas
                            
                           
                             
                               
                             
     1 - As entidades aderentes enviam para o sistema informático de suporte do SPNE associado à morada única digital, através da plataforma de interoperabilidade da administração pública, a notificação eletrónica a remeter, registando:
  a) A entidade aderente;
  b) O assunto da notificação;
  c) A data e hora do envio.
  2 - Para além dos elementos referidos no número anterior, cada notificação eletrónica identifica o respetivo destinatário, através da indicação de um dos seguintes identificadores, de forma cifrada, nos termos da legislação em vigor:
  a) Número de identificação civil;
  b) Número de identificação fiscal;
  c) Número de identificação da segurança social;
  d) Número de utente do Serviço Nacional de Saúde.
  3 - A AMA, I. P., disponibiliza a notificação eletrónica na área reservada do SPNE da pessoa a notificar através da associação dos identificadores referidos no número anterior.
  4 - A AMA, I. P., transmite à entidade aderente, relativamente a cada notificação eletrónica:
  a) Data, hora da disponibilização;
  b) Data, hora do encaminhamento para a morada única digital, bem como dos respetivos reencaminhamentos nos casos de impossibilidade de entrega da notificação;
  c) Data, hora em que a notificação eletrónica foi consultada pela pessoa aderente na respetiva área reservada.
  5 - A correspondência entre os dados da pessoa a notificar, incluindo os respetivos identificadores, do conhecimento da entidade aderente, e os dados necessários para a disponibilização da notificação é garantido pelo mecanismo de federação de identidades.            
         
   
     
                         
                          
  Artigo 9.º 
Consulta de notificações electrónicas
                            
                           
                             
                               
                             
     1 - O SPNE disponibiliza a consulta às notificações eletrónicas através de:
  a) Área reservada da pessoa aderente no SPNE e na respetiva aplicação móvel;
  b) Morada única digital, através do encaminhamento da notificação para aquela.
  2 - O acesso à área reservada e à aplicação móvel é efetuado por um dos meios de autenticação referidos no n.º 3 do artigo 3.º
  3 - Todas as notificações eletrónicas são assinadas digitalmente quando encaminhadas para a morada única digital, o que constitui o mecanismo de confirmação e validação da autenticidade das mesmas.
  4 - No caso de impossibilidade de entrega da notificação eletrónica encaminhada para a morada única digital, o sistema de suporte ao SPNE reencaminha a notificação duas v','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ezes por dia, nos cinco dias subsequentes ao primeiro encaminhamento.            
         
   
     
                         
                          
  Artigo 10.º 
Registo de atividades no SPNE
                            
                           
                             
                               
                             
     Na área reservada do sistema de suporte ao SPNE da pessoa aderente é disponibilizado o registo de atividade com a indicação assunto e entidade aderente e ainda:
  a) Da data e hora do envio de cada notificação pelas entidades aderentes para o sistema de suporte;
  b) Da data e hora da disponibilização de cada notificação na área reservada da pessoa aderente a notificar;
  c) Da data e hora do encaminhamento de cada notificação para a morada única digital da pessoa aderente a notificar;
  d) Da data e hora dos reencaminhamentos de cada notificação para a morada única digital da pessoa aderente a notificar.            
         
   
     
                         
                          
  Artigo 11.º 
Canais de envio de alertas
                            
                           
                             
                               
                             
     Podem ser remetidos alertas ao destinatário das notificações, nomeadamente através da morada única digital ou através do envio de Short Message Service (SMS).            
         
   
     
                         
                          
  Artigo 12.º 
Gratuitidade
                            
                           
                             
                               
                             
     A adesão ao SPNE é totalmente gratuita para as pessoas a notificar.
  
  O Ministro das Finanças, Mário José Gomes de Freitas Centeno, em 10 de novembro de 2017. - A Secretária de Estado Adjunta e da Modernização Administrativa, Graça Maria da Fonseca Caetano Gonçalves, em 20 de novembro de 2017. - A Secretária de Estado da Justiça, Anabela Damásio Caetano Pedroso, em 16 de novembro de 2017. - A Secretária de Estado da Segurança Social, Cláudia Sofia de Almeida Gaspar Joaquim, em 17 de novembro de 2017. - O Secretário de Estado Adjunto e da Saúde, Fernando Manuel Ferreira Araújo, em 20 de novembro de 2017.','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:71  
    
  Portaria n.º 282/2013, de 29 de Agosto  (versão actualizada) REGULAMENTA VÁRIOS ASPETOS DAS AÇÕES EXECUTIVAS CÍVEIS     
    
 
Contém as seguintes alterações:   - Retificação n.º 45/2013, de 28 de Outubro   - Portaria n.º 233/2014, de 14 de Novembro   - Portaria n.º 349/2015, de 13 de Outubro   - Portaria n.º 267/2018, de 20 de Setembro   - Portaria n.º 239/2020, de 12 de Outubro  
                         
                          
SUMÁRIORegulamenta vários aspetos das ações executivas cíveis
Portaria n.º 282/2013, de 29 de agosto 
  A entrada em vigor do novo Código de Processo Civil, aprovado pela  Lei n.º 41/2013, de 26 de junho, dita a revisão e a simplificação de algumas matérias no âmbito da ação executiva, em linha com as alterações introduzidas neste domínio com vista à agilização da tramitação da ação executiva. 
  Dada a multiplicidade de diplomas regulamentares que regem aspetos da ação executiva, que proliferam na nossa ordem jurídica, opta-se por condensar na presente portaria as disposições constantes de grande parte desses diplomas, regulamentando numa só portaria os aspetos essenciais do processo executivo. Procura-se, desta forma, simplificar o quadro normativo atualmente existente, em linha com a simplificação e agilização que se pretende operar em matéria de ação executiva por via da aplicação do novo Código de Processo Civil, de forma a garantir aos destinatários das normas não apenas o seu conhecimento mas também a sua simples e rápida aplicação. 
  O facto de algumas das portarias não serem da exclusiva competência do membro do Governo responsável pela área da justiça, reclamando, pela natureza das matérias envolvidas, aprovação conjunta com outros membros do Governo responsáveis determina, todavia, que nem todos os aspetos regulamentares da ação executiva constem desta portaria. Também as questões transversais a todo o processo civil, que não se limitam à vertente executiva, constam de outros diplomas avulsos. 
  Nunca é demais frisar que um sistema de execuções eficaz é um fator essencial para o bom funcionamento da economia e do sistema de justiça, o que é reconhecido não só interna como externamente. Com efeito, a capacidade atrativa de um país para o investimento interno e externo na economia mede-se, também, pela celeridade e eficácia em garantir, caso necessário por via coerciva, o cumprimento das obrigações devidas. Neste contexto, a cobrança de dívidas assume especial relevo, sendo essencial garantir-se a existência de um regime apto a dar um resposta célere e eficaz a quem dela necessita, seja por motivos de natureza empresarial ou não. Execuções eficientes contribuem, sem margem para dúvida, para a melhoria do ambiente económico e para a confiança dos agentes no sistema de justiça. 
  A presente portaria, regulamentando vários aspetos da ação executiva, define o modelo e os termos de apresentação do requerimento executivo, o qual pode ser enviado e recebido por transmissão eletrónica d','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e dados, através da Internet, sendo obrigatório o envio por essa forma quando a parte esteja representada por mandatário. 
  Nos casos de execução de sentença condenatória, definem-se os termos como a execução corre nos próprios autos, designadamente, a forma como se desencadeia o início das diligências de execução. 
  Na esteira do caminho que vem sendo trilhado nos últimos anos em matéria de tramitação da ação executiva, mantém-se a obrigatoriedade de utilização do sistema informático de suporte à atividade dos agentes de execução pelos agentes de execução, garantindo-se a máxima transparência na tramitação processual, por força da comunicação automática entre este sistema informático e o sistema informático de suporte à atividade dos tribunais. Aproveita-se esta ocasião para dedicar uma secção específica da presente portaria à tramitação e registo eletrónico da prática de atos pelo agente de execução. 
  Quanto à movimentação das contas-clientes mantém-se o regime instituído pela Portaria n.º 308/2011, de 21 de dezembro, no sentido de se tornarem os movimentos de verbas de e para o agente de execução mais ágeis e totalmente transparentes. 
  Com idêntico propósito de tornar as execuções mais simples, regulamenta-se um conjunto de diligências de execução, tais como citações, notificações, publicações e penhoras a promover pelo agente de execução. Mantém-se para este efeito, naturalmente, a utilização de meios eletrónicos, sendo de salientar a inovação que surge agora em matéria de penhora eletrónica de depósitos bancários, após a obtenção, por via também ela eletrónica, da informação disponibilizada pelo Banco de Portugal relativa às instituições legalmente autorizadas a receber depósitos em que o executado detenha contas bancárias. 
  Estão, finalmente, reunidas as condições para efetivar a penhora de depósitos bancários, de uma forma célere e eficaz, definindo-se na presente portaria quer a forma como o Banco de Portugal disponibiliza, por meios eletrónicos, ao agente de execução, a informação relativa às instituições legalmente autorizadas a receber depósitos em que o executado detenha conta aberta quer o procedimento eletrónico de penhora dos depósitos bancários de que o executado seja titular. 
  Sublinhe-se a opção do legislador de dispensar a necessidade de despacho judicial prévio para efeitos de penhora de depósitos bancários, agora prevista no artigo 780.º do novo Código de Processo Civil. Em consonância com esta alteração legislativa, a presente portaria simplifica a comunicação de informação das instituições bancárias aos agentes de execução e a penhora de depósitos bancários, desjudicializando o processo e tornando-o mais ligeiro e eficaz. 
  A presente portaria regula ainda o regime dos depósitos públicos e equiparados e da venda de bens penhorados nestes depósitos. Passa agora a estar igualmente regulamentada a venda de bens penhorados em leilão eletrónico. As vantagens do leilão eletrónico são claras, permitindo obter a máxima t','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ransparência do ato de venda e criar as condições para a valorização máxima dos bens, ao mesmo tempo que se obtém maior celeridade na tramitação. São, por esta via, beneficiados todos agentes processuais e a generalidade dos potenciais interessados na aquisição dos bens, à semelhança do que tem sucedido nas execuções fiscais. 
  Aspetos como os meios de identificação do agente execução no desempenho das suas funções, a criação e publicitação eletrónica da lista atualizada dos agentes de execução, a designação a forma de substituição do agente de execução, quer quando tal decorra da vontade do exequente, devidamente fundamentada, ou da sua destituição pelo órgão disciplinar, são também regulamentados pela presente portaria. 
  Regulamenta-se igualmente o dever de informação e comunicação do agente de execução perante as partes, garante da transparência na condução de cada processo. 
  No que respeita à remuneração do agente de execução pelo exercício das suas funções, plasma-se na presente portaria o regime aprovado pela Portaria n.º 225/2013, de 10 de julho, o qual opera um conjunto de alterações numa matéria especialmente sensível, não só para os próprios profissionais que desempenham as funções de agente de execução, como também para as partes que terão de suportar tais custos. Pretende-se que o regime seja tão simples e claro quanto possível. Só assim poderão quaisquer interessados avaliar, com precisão, todos os custos de um processo e decidir quanto à viabilidade e interesse na instauração do mesmo, sobretudo, quando esteja em causa o cumprimento coercivo de uma obrigação não satisfeita voluntária e pontualmente, na maioria dos casos, a cobrança coerciva de uma dívida. Previsibilidade e segurança num domínio como o dos custos associados à cobrança coerciva de dívidas são, reconhecidamente, fatores determinantes para o investimento externo na economia nacional e para a confiança dos cidadãos e das empresas. 
  Clarificam-se os momentos e a forma como os honorários e despesas devem ser adiantados ou pagos pelos respetivos responsáveis, no intuito de evitar conflitos entre o agente de execução e as partes, tantas vezes surgidos nesta matéria. Nos termos deste novo regime, deixam de existir montantes máximos até aos quais o agente de execução pode acordar livremente com as partes os valores a cobrar. Passam, ao invés, a existir tarifas fixas quer para efeitos de adiantamento de honorários e despesas, quer para honorários devidos pela tramitação dos processos, quer ainda pela prática de atos concretos que lhes caiba praticar. 
  Precisa-se melhor a estrutura de fases do processo executivo, para efeitos de adiantamento de honorários e despesas, reduzindo-se o valor da fase 1. 
  Ao adotar um regime de tarifas fixas, procura-se estimular a sã concorrência entre agentes de execução, baseada na qualidade do serviço prestado e não em diferentes valores a acordar, caso a caso, entre agente de execução e exequente, autor ou requerente. 
  Por outro lado','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (', com vista a promover uma maior eficiência e celeridade na recuperação das quantias devidas ao exequente, reforçam-se os valores pagos aos agentes de execução, a título de remuneração adicional, num sistema misto como o nosso, que combina uma parte fixa com uma parte variável. Uma vez que parte das execuções é de valor reduzido, prevê-se a atribuição de um valor mínimo ao agente de execução quando seja recuperada a totalidade da dívida, precisamente para incentivar a sua rápida recuperação. 
  Procura-se igualmente estimular o pagamento integral voluntário da quantia em dívida bem como a celebração de acordos de pagamento entre as partes, que pretendam pôr termo ao processo. Para tanto, prevê-se o pagamento de uma remuneração adicional ao agente de execução quando a recuperação da quantia tenha tido lugar na sequência de diligências por si promovidas, ou a dispensa do pagamento de qualquer remuneração adicional ao agente de execução quando, logo no início do processo, a dívida seja satisfeita de modo voluntário, sem a intermediação do agente de execução. Este regime visa, em última linha, tornar mais simples e mais célere a fiscalização da atividade dos agentes de execução, no que respeita a esta matéria em particular, e promover uma mais rápida ação em caso de atuações desconformes. 
  Outra matéria regulamentada na presente portaria é o acesso dos agentes de execução e dos mandatários ao registo informático de execuções, instrumento essencial para identificação de execuções instauradas contra o executado e respetivo desfecho, o que pode conduzir a uma decisão mais consciente da parte do exequente em avançar com uma nova ação executiva, e que se revela também determinante para a própria condução, pelo agente de execução, dos processos executivos já instaurados. Daí a importância em manter este registo permanentemente atualizado, tarefa a cargo do agente de execução. 
  Por fim, tendo em conta que existem situações em que a realização de diligências de execução compete a oficiais de justiça, passa a definir-se, nesta portaria, quem, de entre estes, é responsável pela tramitação das mesmas, o regime de delegação de competências, bem como o regime de impedimentos, suspeições e substituição a que o mesmo está sujeito, bem como as disposições regulamentares que se lhes aplicam. 
  Foram promovidas as audições do Conselho Superior da Magistratura, do Conselho Superior do Ministério Público, do Conselho Superior dos Tribunais Administrativos e Fiscais, da Ordem dos Advogados, da Câmara dos Solicitadores, da Associação Sindical dos Juízes Portugueses, do Sindicato dos Magistrados do Ministério Público, do Sindicato dos Funcionários Judiciais, da Associação dos Oficiais de Justiça, do Conselho dos Oficiais de Justiça, do Sindicato dos Oficiais de Justiça, da Comissão Nacional de Proteção de Dados, do Banco de Portugal e da Associação Portuguesa de Bancos. 
  Assim: 
  Ao abrigo do disposto nos artigos 132.º, 552.º, 626.º, 712.º, 719.º, 720.º, 722.º, 724','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('.º, 749.º, 753.º, 754.º, 755.º, 780.º, 786.º, 817.º, 836.º e 837.º do Código de Processo Civil, aprovado pela  Lei n.º 41/2013, de 26 de junho, nos artigos 119.º-B, 123.º, 126.º e 127.º do Estatuto da Câmara dos Solicitadores, aprovado pelo  Decreto-Lei n.º 88/2003, de 26 de abril, e alterado pelas Leis n.os 49/2004, de 24 de agosto, e 14/2006, de 26 de abril, e pelo Decreto-Lei n.º 226/2008, de 20 de novembro, no artigo 9.º do  Decreto-Lei n.º 201/2003, de 10 de setembro, alterado pelo Decreto-Lei n.º 53/2004, de 18 de março, pela Lei n.º 60-A/2005, de 30 de dezembro, e pelo Decreto-Lei n.º 226/2008, de 20 de novembro, manda o Governo, pela Ministra da Justiça, o seguinte:CAPÍTULO I 
  Disposições gerais  Artigo 1.º Objeto
                            
                           
                             
                               
                             
     1 - A presente portaria regulamenta os seguintes aspetos das ações executivas cíveis: 
  a) Termos de apresentação do requerimento executivo; 
  b) Termos de apresentação do requerimento nas execuções de decisão judicial condenatória; 
  c) Tramitação e registo eletrónico da prática dos atos; 
  d) Movimentação das contas-clientes; 
  e) Citações, notificações e publicações; 
  f) Disponibilização, pelo Banco de Portugal, da informação relativa às instituições bancárias em que o executado detém conta; 
  g) Penhora de depósitos bancários; 
  h) Registo de depósito de bens penhoráveis; 
  i) Publicitação da venda dos bens penhorados através de anúncio eletrónico; 
  j) Termos da venda em leilão eletrónico de bens penhorados; 
  k) Venda de bens em depósito público ou equiparado; 
  l) Não aceitação, identificação, substituição e destituição do agente de execução; 
  m) Lista de agentes de execução; 
  n) Dever de informação e comunicação do agente de execução; 
  o) Remuneração do agente de execução; 
  p) Acesso ao registo informático de execuções; 
  q) Diligências de execução promovidas por funcionários de justiça. 
  2 - São aprovados pela presente portaria os seguintes modelos no âmbito da ação executiva: 
  a) Requerimento executivo em suporte de papel, constante do anexo I da presente portaria, da qual faz parte integrante; 
  b) Requerimento de execução da decisão judicial condenatória constante do anexo II da presente portaria, da qual faz parte integrante; 
  c) Auto de penhora, constante do anexo III da presente portaria, da qual faz parte integrante; 
  d) Edital de penhora de imóveis, constante do anexo IV da presente portaria, da qual faz parte integrante; 
  e) Selos de penhora de veículos automóveis, constante do anexo V da presente portaria, da qual faz parte integrante.            
         
   
     
                         
                          
  CAPÍTULO II 
  Requerimento executivo 
  SECÇÃO I 
  Apresentação por via eletrónica  Artigo 2.º  
Termos de apresentação eletrónica
                            
                           
                 ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('            
                               
                             
     1 - O requerimento executivo é apresentado por mandatário judicial através do preenchimento e submissão do formulário eletrónico de requerimento executivo constante do sítio eletrónico http://citius.tribunaisnet.mj.pt, nos termos do artigo 132.º do Código de Processo Civil e de acordo com os procedimentos e instruções aí constantes, ao qual se anexam os documentos que o devem acompanhar. 
  2 - Sempre que o exequente não designe o agente de execução no requerimento executivo, a designação referida no n.º 2 do artigo 720.º do Código de Processo Civil é realizada automaticamente no momento do preenchimento do requerimento. 
  3 - Devem ser indicados ao exequente, relativamente ao agente de execução designado, os seguintes elementos: 
  a) O nome profissional; 
  b) O número da cédula; 
  c) O endereço de correio eletrónico; 
  d) O número de telefone; 
  e) O número de fax; e 
  f) A morada do escritório. 
  4 - Após a validação, pelo sistema informático de suporte à atividade dos tribunais, do preenchimento pelo exequente de todos os campos de preenchimento obrigatório, o requerimento executivo é entregue no referido sistema e, caso o exequente não beneficie de apoio judiciário na modalidade de atribuição de agente de execução, é lhe disponibilizada a referência multibanco referente ao pagamento da quantia inicialmente devida ao agente de execução a título de honorários e despesas, e, se for o caso, do pagamento da retribuição prevista no n.º 8 do artigo 749.º do Código de Processo Civil. 
  5 - A emissão da referência prevista no número anterior é da responsabilidade da Câmara dos Solicitadores, devendo o exequente proceder ao seu pagamento no prazo de 10 dias e considerando-se o requerimento executivo apresentado apenas na data desse pagamento, nos termos do disposto no n.º 6 do artigo 724.º do Código de Processo Civil. 
  6 - Findo o prazo de 10 dias previsto no número anterior para pagamento da referência multibanco sem que a mesma se encontre paga, o sistema informático de suporte à atividade dos agentes de execução pode proceder à invalidação da referência em causa, não sendo possível a partir desse momento o seu pagamento nem, consequentemente, a apresentação do requerimento. 
  7 - A comprovação da realização do pagamento previsto no n.º 5 é comunicada eletronicamente pela Câmara dos Solicitadores ao sistema informático de suporte à atividade dos tribunais, estando o exequente dispensado de remeter ao processo o comprovativo do mesmo. 
  8 - Sem prejuízo do disposto nos números anteriores, à apresentação do requerimento executivo por via eletrónica aplica-se, com as necessárias adaptações, o disposto na portaria que regula a tramitação eletrónica dos processos judiciais.
  9 - Sempre que a execução resulte de pedido de convolação de procedimento extrajudicial pré-executivo, o exequente deve indicar o número do procedimento e juntar o relatório previsto no artig','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o 10.º da Lei n.º 32/2014, de 30 de maio, não havendo lugar à emissão da referência de pagamento prevista no n.º 4, sempre que o procedimento tenha sido extinto há menos de 30 dias.
  10 - Até que se encontre disponível a funcionalidade prevista no número anterior, o exequente, depois de submeter o requerimento executivo, deve aceder à plataforma informática de suporte ao procedimento extrajudicial pré-executivo, e aí indicar a referência de pagamento emitida após submissão do requerimento executivo, para que seja confirmada a remessa à distribuição sem que haja lugar ao pagamento do valor ali indicado.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 233/2014, de 14 de Novembro   - Portaria n.º 349/2015, de 13 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto    - 2ª versão: Portaria n.º 233/2014, de 14 de Novembro   
     
                         
                          
  SECÇÃO II 
  Apresentação em suporte físico  Artigo 3.º 
Termos de apresentação em suporte físico
                            
                           
                             
                               
                             
     1 - Quando a parte não esteja representada por mandatário judicial, ou, estando, haja justo impedimento para a prática do ato nos termos do artigo anterior, o requerimento executivo pode ser apresentado em suporte físico, por entrega na secretaria judicial ou remessa pelo correio, sob registo, ou por telecópia, no tribunal competente, utilizando o modelo de requerimento executivo que consta do anexo I do presente diploma ao qual se anexam os documentos que o devem acompanhar. 
  2 - Entregue o requerimento nos termos do número anterior, a secretaria, após análise do mesmo nos termos dos artigos 724.º e 725.º do Código de Processo Civil e antes de ser efetuada a distribuição, procede, caso o exequente não o tenha feito, à designação do agente de execução referida no n.º 2 do artigo 720.º do Código de Processo Civil. 
  3 - Nos casos previstos no número anterior, a secretaria deve comunicar ao exequente, relativamente ao agente de execução designado, os seguintes elementos: 
  a) O nome profissional; 
  b) O número da cédula; 
  c) O endereço de correio eletrónico; 
  d) O número de telefone; 
  e) O número de fax; e 
  f) A morada do escritório. 
  4 - Após os atos previstos no n.º 2 e antes de ser efetuada a distribuição, a secretaria notifica o exequente, juntamente com a informação referida no número anterior, para pagamento, no prazo de 10 dias, da quantia inicialmente devida ao agente de execução a título de honorários e despesas, caso o exequente não beneficie de apoio judiciário na modalidade de atribuição de agente de execução, e, se for o caso, do pagamento da retribuição prevista no n.º 8 do artigo 749.º do Código de Processo Civil. 
  5 - A notificação referida no número anterior é acompanhada da referência multib','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('anco respeitante ao pagamento aí referido, que é disponibilizada à secretaria, no sistema informático de suporte à atividade dos tribunais, pela Câmara dos Solicitadores. 
  6 - Quando haja lugar ao pagamento previsto no n.º 4, o requerimento executivo, nos termos do disposto no n.º 6 do artigo 724.º do Código de Processo Civil, só se considera apresentado após o pagamento. 
  7 - Findo o prazo de 10 dias previsto no n.º 4 para pagamento da referência multibanco sem que a mesma se encontre paga, o sistema informático de suporte à atividade dos agentes de execução pode proceder à invalidação da referência em causa, não sendo possível a partir desse momento o seu pagamento nem, consequentemente, a apresentação do requerimento. 
  8 - A comprovação da realização do pagamento previsto no n.º 4 é comunicada eletronicamente pela Câmara dos Solicitadores ao sistema informático de suporte à atividade dos tribunais, estando o exequente dispensado de remeter ao processo o comprovativo do mesmo.
  9 - Aplica-se ao requerimento em papel, com as necessárias adaptações, o disposto no n.º 9 do artigo anterior.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 233/2014, de 14 de Novembro   - Portaria n.º 349/2015, de 13 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto    - 2ª versão: Portaria n.º 233/2014, de 14 de Novembro   
     
                         
                          
SECÇÃO III 
  Apresentação do requerimento de execução da decisão judicial condenatória  Artigo 4.º Termos de apresentação do requerimento de execução da decisão judicial condenatória
                            
                           
                             
                               
                             
     1 - A apresentação do requerimento de execução da decisão judicial condenatória é efetuada nos termos previstos para as demais peças processuais no Código de Processo Civil e na portaria que regula a tramitação eletrónica dos processos judiciais, com as especificidades previstas nos números seguintes. 
  2 - A apresentação do requerimento de execução da decisão judicial condenatória por via eletrónica deve ser efetuada através do preenchimento do formulário específico constante no sistema informático de suporte à atividade dos tribunais. 
  3 - A apresentação do requerimento de execução da decisão judicial condenatória em suporte físico é dirigida ao tribunal que proferiu a decisão em 1.ª instância, e efetuada por qualquer dos meios legalmente previstos, utilizando o modelo de requerimento que consta do anexo II do presente diploma. 
  4 - O exequente deve indicar, no requerimento de execução da decisão judicial condenatória, a decisão judicial que pretende executar, estando dispensado de juntar cópia ou certidão da mesma. 
  5 - À execução da decisão judicial condenatória aplica-se, com as necessárias adaptações, o disposto nas secções anteriores, ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('considerando-se o requerimento de execução de decisão judicial condenatória apresentado apenas na data de pagamento das quantias previstas no n.º 6 do artigo 724.º do Código de Processo Civil, quando sejam devidas. 
  6 - Quando a parte pretenda executar pedidos com finalidade diversa, é designado apenas um agente de execução para a realização das diligências de execução.            
         
   
     
                         
                          
CAPÍTULO III 
  Diligências de execução 
  SECÇÃO I 
  Tramitação e registo eletrónicos  Artigo 5.º Tramitação e registo eletrónico da prática dos atos
                            
                           
                             
                               
                             
     1 - O processo executivo é tramitado por via eletrónica, através dos sistemas informáticos de suporte à atividade dos agentes de execução e do sistema informático de suporte à atividade dos tribunais, nos termos previstos na portaria que regula a tramitação eletrónica dos processos judiciais. 
  2 - Os atos processuais do agente de execução são praticados através do sistema informático de suporte à atividade dos agentes de execução, ficando os mesmos a constar do sistema informático de suporte à atividade dos tribunais. 
  3 - Os atos que não sejam praticados através do sistema informático de suporte à atividade dos agentes de execução, tais como as diligências externas, são registados no processo, pelo agente de execução, no sistema informático de suporte à atividade dos agentes de execução. 
  4 - Do registo informático referido no número anterior constam os elementos que permitem identificar o ato, cópia dos documentos respeitantes à efetivação do mesmo e, sendo caso disso, cópia dos documentos que o acompanham. 
  5 - O sistema informático de suporte à atividade dos agentes de execução e o sistema informático de suporte à atividade dos tribunais asseguram que qualquer ato registado pode ser consultado no histórico eletrónico do processo, através do sistema informático de suporte à atividade dos tribunais, com respeito pelas limitações à publicidade do processo constantes do previsto na alínea c) do n.º 2 do artigo 164.º do Código de Processo Civil.            
         
   
     
                         
                          
  Artigo 6.º Dispensa de junção dos originais dos documentos
                            
                           
                             
                               
                             
     1 - O registo da prática do ato efetuado nos termos do artigo anterior dispensa a junção aos autos dos documentos comprovativos da efetivação dos mesmos. 
  2 - O disposto no número anterior não prejudica o dever de exibição dos originais dos documentos comprovativos de qualquer ato sempre que o juiz o determine.            
         
   
     
                         
                          
SECÇÃO II 
  Movimentação das contas-clientes  Artigo 7.º','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' Movimentos a crédito nas contas-clientes
                            
                           
                             
                               
                             
     O depósito de quaisquer valores nas contas-clientes à ordem do agente de execução efetua-se através da utilização de um identificador único de pagamento, previamente emitido através do sistema informático de suporte à atividade dos agentes de execução.            
         
   
     
                         
                          
  Artigo 8.º Movimentos a débito nas contas-clientes
                            
                           
                             
                               
                             
     1 - Os pagamentos pelo agente de execução a quaisquer entidades são efetuados após prévio registo no sistema informático de suporte à atividade dos agentes de execução. 
  2 - Os movimentos a débito nas contas-clientes à ordem do agente de execução são concretizados através de número de identificação bancária, referência multibanco ou documento único de cobrança constantes do processo ou, ainda, de entrega em dinheiro num balcão de instituição de crédito definida pela Câmara dos Solicitadores.            
         
   
     
                         
                          
  Artigo 9.º Especificações técnicas
                            
                           
                             
                               
                             
     A concretização de débitos e créditos nas contas-clientes e a articulação com a plataforma informática da instituição de crédito a que se refere o artigo anterior efetuam-se de acordo com as especificações técnicas constantes do sistema informático de suporte à atividade dos agentes de execução, definidas pela Câmara dos Solicitadores.            
         
   
     
                         
                          
SECÇÃO III 
  Citação, notificações, informações, comunicações e publicações  Artigo 10.º Modalidades e termos da citação
                            
                           
                             
                               
                             
     1 - O agente de execução procede à citação pessoal do executado, do cônjuge e dos credores nos termos gerais definidos na lei processual civil. 
  2 - Frustrada a citação pessoal por carta registada com aviso de receção ou frustrada a citação por contacto pessoal o agente de execução procede à citação edital eletrónica do executado ou do cônjuge do executado, nos termos dos artigos seguintes.            
         
   
     
                         
                          
  Artigo 11.º 
Citação edital por incerteza do lugar
                            
                           
                             
                               
                             
     1 - A citação edital do executado ou do cônjuge determinada por incerteza do lugar é feita pela a','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('fixação de edital e pela publicação de anúncio em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt.
  2 - O edital é afixado na porta da última residência ou sede que o executado teve no país. 
  3 - O edital especifica: 
  a) O tribunal competente, o juízo e a respetiva secção; 
  b) O número de processo em que o executado é citado; 
  c) O nome do exequente; 
  d) O valor e o pedido; 
  e) A identificação do agente de execução; 
  f) De forma simples e percetível, o prazo para a defesa e a cominação, explicando que o prazo para defesa só começa a correr depois de finda a dilação e o respetivo modo de contagem; 
  g) De forma autónoma da informação referida nas alíneas anteriores, a referência aos artigos ou atos legislativos ou regulamentares que a fundamentam; 
  h) A data da afixação; 
  i) A referência à publicação de anúncio eletrónico, a realizar num prazo máximo de cinco dias úteis, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt.
  4 - No prazo máximo de cinco dias úteis após a afixação do edital, o agente de execução faz publicar, através do sistema informático de suporte à atividade dos agentes de execução, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt, o anúncio eletrónico de citação edital.
  5 - O anúncio eletrónico de citação edital contém a informação referida nas alíneas a) a h) do n.º 3. 
  6 - O sistema informático de suporte à atividade dos agentes de execução assegura a publicitação, no anúncio eletrónico, da data da sua publicação. 
  7 - A contagem do prazo para a defesa faz-se a partir da data de publicação do anúncio eletrónico efetuada nos termos dos números anteriores.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 12.º 
Citação edital por incerteza das pessoas
                            
                           
                             
                               
                             
     1 - A citação edital do executado ou do cônjuge determinada pela incerteza das pessoas a citar ocorre nos casos em que não é possível identificar o executado ou em que os incertos forem citados como herdeiros ou representantes de pessoa falecida. 
  2 - A citação edital determinada pela incerteza das pessoas a citar efetua-se: 
  a) Pela publicação de anúncio de citação edital, pelo agente de execução, através do sistema informático de suporte à atividade dos agentes de execução, em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt., nos termos dos n.os 5 a 7 do artigo anterior, com as de','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('vidas adaptações; e
  b) Pela afixação de edital, nos termos do n.º 3 do artigo anterior, na porta da casa da última residência do falecido, se for conhecida.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 13.º Termos das notificações
                            
                           
                             
                               
                             
     1 - O agente de execução efetua todas as notificações previstas na lei preferencialmente por transmissão eletrónica de dados, através do sistema informático de suporte à atividade dos agentes de execução. 
  2 - A notificação dos mandatários das partes efetua-se por transmissão eletrónica de dados, nos termos da portaria que regula a tramitação eletrónica dos processos judiciais. 
  3 - Para efeitos do número anterior, a data de elaboração da notificação corresponde à data de depósito da notificação no sistema informático de suporte à atividade dos tribunais.            
         
   
     
                         
                          
  Artigo 14.º Termos das informações
                            
                           
                             
                               
                             
     1 - O agente de execução deve prestar todas as informações previstas na lei preferencialmente por via eletrónica, através do sistema informático de suporte à atividade dos agentes de execução. 
  2 - Quando a parte esteja representada por mandatário judicial, as informações são prestadas por transmissão eletrónica de dados, através do sistema informático de suporte à atividade dos agentes de execução, que assegura automaticamente a sua disponibilização no sistema informático de suporte à atividade dos tribunais, e consulta no endereço eletrónico http://citius.tribunaisnet.mj.pt. 
  3 - No caso previsto no número anterior, o dever de informação considera-se cumprido com o registo da informação no sistema informático de suporte à atividade dos tribunais que permita a consulta do ato no histórico eletrónico do processo judicial.            
         
   
     
                         
                          
  Artigo 15.º Informações a prestar após a inserção na lista pública de execuções
                            
                           
                             
                               
                             
     1 - Após a inclusão da execução na lista pública de execuções, nos termos da portaria que regula essa inclusão, e até à sua exclusão por cumprimento da obrigação ou decurso do prazo limite de cinco anos, o exequente pode requerer ao agente de execução a consulta às bases de dados referidas no artigo 749.º do Código de Processo Civil para identificação de bens de mo','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('do a poder decidir sobre a oportunidade de renovação da instância. 
  2 - A consulta eletrónica às bases de dados: 
  a) É efetuada, no âmbito do processo respetivo, por meios exclusivamente eletrónicos no prazo máximo de cinco dias; 
  b) O processo deve ser retirado do arquivo para possibilitar a prática do ato, mas a consulta não implica qualquer renovação da instância; e 
  c) O resultado da consulta fica registado no processo, nos sistemas informáticos de suporte à atividade dos agentes de execução e dos tribunais, e é enviado ao exequente nos termos do artigo anterior. 
  3 - Pelo ato referido no número anterior o agente de execução aplica a tarifa constante do ponto 1.4 da tabela do anexo VII da presente portaria.            
         
   
     
                         
                          
  Artigo 16.º 
Termos das publicações
                            
                           
                             
                               
                             
     O agente de execução, nos termos do artigo 719.º do Código de Processo Civil, procede às publicações previstas na lei mediante anúncio em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt, através do sistema informático de suporte à atividade dos agentes de execução e do sistema informático de suporte à atividade dos tribunais.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
SECÇÃO IV 
  Disponibilização de informação e penhora de depósitos bancários  Artigo 17.º Disponibilização de informação
                            
                           
                             
                               
                             
     1 - O agente de execução, para efeitos de penhora de depósitos bancários, solicita ao Banco de Portugal a disponibilização de informação acerca das instituições legalmente autorizadas a receber depósitos em que o executado detém contas ou depósitos bancários através dos sistemas informáticos de suporte à atividade dos tribunais e dos agentes de execução. 
  2 - O Banco de Portugal disponibiliza a informação prevista no número anterior nos termos definidos por protocolo celebrado entre o Ministério da Justiça, a Câmara dos Solicitadores e o Banco de Portugal, a qual é comunicada ao agente de execução através dos sistemas informáticos de suporte à atividade dos tribunais e dos agentes de execução.            
         
   
     
                         
                          
  Artigo 18.º Penhora de depósitos bancários
                            
                           
                             
                               
                             
     1 - A penhora de depósitos ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('bancários, por comunicação eletrónica realizada pelo agente de execução, efetua-se através do sistema informático de suporte à atividade dos agentes de execução, nos termos previstos nos números seguintes, e de acordo com os procedimentos e instruções constantes do referido sistema informático. 
  2 - A receção e o envio de todas as comunicações pelas instituições de crédito, no âmbito da penhora de depósitos bancários, processam-se através de plataforma informática criada especialmente para o efeito, disponível no endereço eletrónico https://penhorabancaria.mj.pt., cujos termos de acesso e utilização são definidos pelo Ministério da Justiça. 
  3 - O agente de execução, através do sistema informático de suporte à atividade dos agentes de execução, efetua o pedido de bloqueio do saldo existente, ou da quota-parte do executado nesse saldo, até ao valor limite da penhora, à instituição de crédito, sendo o mesmo acompanhado dos elementos previstos no n.º 3 do artigo 780.º do Código de Processo Civil. 
  4 - O pedido é comunicado à instituição de crédito através da plataforma informática referida no n.º 2. 
  5 - A instituição de crédito considera-se notificada no dia da receção do pedido de bloqueio do agente de execução, ou no primeiro dia útil seguinte caso o dia da receção não o seja, exceto se o pedido for insuscetível de tratamento técnico, por causa que não seja imputável à instituição de crédito, caso em que a notificação apenas se considera efetuada no primeiro dia útil em que o pedido possa ser tecnicamente tratado por esta. 
  6 - A instituição de crédito deve executar os pedidos de bloqueio e de penhora até às 23:59 horas do dia em que se considera notificada. 
  7 - No prazo de dois dias úteis após a data da notificação do pedido de bloqueio, a instituição de crédito comunica ao agente de execução o montante bloqueado ou o montante dos saldos existentes ou a inexistência de conta ou saldo, de acordo com o disposto no n.º 8 do artigo 780.º do Código de Processo Civil, sendo a informação disponibilizada ao agente de execução através do sistema informático de suporte à atividade dos agentes de execução. 
  8 - O disposto no número anterior aplica-se, com as necessárias adaptações, às comunicações de penhora. 
  9 - O agente de execução considera-se notificado no dia da receção, no sistema informático de suporte à atividade dos agentes de execução, das comunicações das instituições de crédito, ou no primeiro dia útil seguinte caso o dia da receção não o seja, exceto se o pedido for insuscetível de tratamento técnico, por causa que não lhe seja imputável, caso em que a notificação apenas se considera efetuada no primeiro dia útil em que a comunicação possa ser tecnicamente tratada pelo agente de execução. 
  10 - O agente de execução, no prazo de cinco dias após a receção da comunicação de cada instituição de crédito, comunica a esta, através do sistema informático de suporte à atividade dos agentes de execução, quais os montantes que pretend','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e penhorar e quais os saldos de contas a desbloquear. 
  11 - A instituição de crédito considera-se notificada da comunicação referida no número anterior no dia da receção dessa comunicação, ou no primeiro dia útil seguinte caso o dia da receção não o seja, exceto se a comunicação for insuscetível de tratamento técnico, por causa que não lhe seja imputável, caso em que a notificação apenas se considera efetuada no primeiro dia útil em que o pedido possa ser tecnicamente tratado pela instituição de crédito. 
  12 - São válidas as comunicações de penhora efetuadas pelo agente de execução através do sistema informático de suporte à atividade dos agentes de execução até ao termo do 5.º dia seguinte ao da receção da comunicação da instituição de crédito referida no n.º 7, independentemente da data em que a instituição de crédito se deva considerar notificada. 
  13 - Na pendência do prazo referido no n.º 10, as instituições de crédito comunicam ao agente de execução, através da plataforma referida no n.º 2, a receção de qualquer ordem de penhora ou qualquer outra forma de apreensão ou de oneração, judicial ou administrativa, que incida sobre os saldos bloqueados e determine o levantamento total ou parcial do bloqueio. 
  14 - Na pendência do prazo referido n.º 10, as instituições de crédito apenas podem desbloquear o remanescente do saldo da conta penhorada bem como os demais saldos das contas bloqueadas após a receção da comunicação de desbloqueio efetuada pelo agente de execução, através do sistema informático de suporte à atividade dos agentes de execução. 
  15 - Decorrido o prazo referido no n.º 10, a instituição de crédito apenas pode desbloquear o remanescente do saldo da conta penhorada bem como os demais saldos das contas bloqueadas, sem indicação do agente de execução, após ser notificada das comunicações respeitantes ao 5.º dia do prazo a que alude o n.º 10. 
  16 - Quando o saldo bloqueado ou penhorado venha a ser afetado, nos termos previstos no n.º 10 do artigo 780.º, a instituição de crédito, através da plataforma informática referida no n.º 2, comunica o facto ao agente de execução, e, caso a afetação se deva a operações anteriores à data do bloqueio, disponibiliza o extrato onde constem todas as operações que afetem os depósitos penhorados. 
  17 - O agente de execução pode cancelar o pedido de bloqueio ou de penhora, esta última até ao momento da transferência da quantia penhorada, indicando o motivo de cancelamento. 
  18 - Reunidos os requisitos legais previstos no n.º 13 do artigo 780.º do Código de Processo Civil, o agente de execução efetua o pedido de transferência do montante penhorado à instituição de crédito, através do sistema informático de suporte à atividade do agente de execução, a qual, uma vez realizada, é comunicada ao agente de execução. 
  19 - As transferências das quantias penhoradas devem ser efetuadas por referência multibanco, ou por documento único de cobrança (DUC) quando o agente de execução seja oficial de','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' justiça. 
  20 - As instituições de crédito que não possam efetuar a transferência das quantias penhoradas por referência multibanco, podem fazê-lo por transferência bancária para a conta-cliente do agente de execução, devendo a instituição de crédito comunicar, através da plataforma e na data da transferência, a operação efetuada. 
  21 - Para operacionalização do procedimento definido no presente artigo e definição de direitos e deveres mútuos, podem ser celebrados protocolos entre as instituições de crédito, o Ministério da Justiça e a Câmara dos Solicitadores.            
         
   
     
                         
                          
  SECÇÃO V 
  Venda 
  SUBSECÇÃO I 
  Publicidade da venda  Artigo 19.º 
Anúncio electrónico
                            
                           
                             
                               
                             
     1 - A venda dos bens penhorados é publicitada, nos termos da alínea a) do n.º 1 do artigo 817.º do Código de Processo Civil, através de anúncio na página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt.
  2 - O anúncio contém: 
  a) A identificação do processo de execução; 
  b) O nome do executado; 
  c) A identificação do agente de execução; 
  d) As características do bem; 
  e) A modalidade da venda; 
  f) O valor para a venda; 
  g) O dia, hora e local de abertura das propostas; 
  h) O local e horário fixado para facultar a inspeção do bem; 
  i) Menção, sendo caso disso, ao facto de a sentença que serve de título executivo estar pendente de recurso ou de oposição à execução ou à penhora. 
  3 - O anúncio deve ainda conter quaisquer outras informações relevantes, designadamente ónus ou encargos que incidam sobre o bem, e que não caduquem com a venda, bem como, sempre que possível, fotografia que permita identificar as características exatas do bem e o seu estado de conservação. 
  4 - A publicação dos anúncios é efetuada de forma a que não seja possível a sua indexação a motores de busca.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
SUBSECÇÃO II 
  Termos da venda em leilão eletrónico de bens penhorados  Artigo 20.º Noção de leilão eletrónico
                            
                           
                             
                               
                             
     Entende-se por leilão eletrónico a modalidade de venda de bens penhorados, que se processa em plataforma eletrónica acessível na Internet, concebida especificamente para permitir a licitação dos bens a vender em processo de execução, nos termos definidos na presente portaria e nas regras do sistema que venham a ser aprovadas pela entidade gestora da ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('plataforma e homologadas pelo membro do Governo responsável pela área da justiça.            
         
   
     
                         
                          
  Artigo 21.º Regras gerais
                            
                           
                             
                               
                             
     1 - A entidade gestora da plataforma eletrónica, a qual é definida por despacho do membro do Governo responsável pela área da justiça, disponibiliza a todos os interessados, em sítio da Internet de acesso público definido nas regras do sistema, a consulta dos anúncios de venda de bens que decorra através de leilão eletrónico bem como as regras do sistema. 
  2 - A plataforma eletrónica mencionada no artigo anterior dispõe de um módulo de acesso restrito a utilizadores registados no sistema, no qual se processa a negociação dos bens a vender em leilão eletrónico, estando permanente e publicamente visível em cada leilão o preço base dos bens a vender, o valor da última oferta e o valor de venda efetiva dos bens leiloados. 
  3 - Só podem efetuar ofertas de licitação no leilão eletrónico regulado na presente portaria utilizadores que se encontrem registados, após autenticação efetuada de acordo com as regras do sistema. 
  4 - As regras do sistema regulam o processo de registo referido no número anterior, devendo assegurar a completa, inequívoca e verdadeira identificação de cada uma das pessoas registadas como utilizadores da plataforma a que alude o artigo anterior. 
  5 - A cada utilizador registado são fornecidas credenciais de acesso constituídas por um nome de utilizador e uma palavra-chave pessoais e intransmissíveis, que permitam a sua autenticação na plataforma referida no artigo anterior.            
         
   
     
                         
                          
  Artigo 22.º Duração do leilão
                            
                           
                             
                               
                             
     O dia e a hora de abertura e de termo de cada leilão eletrónico são estabelecidos pela entidade gestora da plataforma eletrónica, sendo tais prazos divulgados na mencionada plataforma eletrónica, pelo menos, com cinco dias de antecedência face ao seu início.            
         
   
     
                         
                          
  Artigo 23.º Ofertas
                            
                           
                             
                               
                             
     1 - As ofertas de licitação para aquisição dos bens em leilão são introduzidas na plataforma a que se refere o artigo 20.º, entre o momento de abertura do leilão e o dia e hora designados na plataforma eletrónica referida no artigo anterior para o seu termo. 
  2 - Só podem ser aceites ofertas de valor igual ou superior ao valor base da licitação de cada bem a vender e, de entre estas, é escolhida a proposta cuja oferta corresponda ao ma','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ior dos valores de qualquer das ofertas anteriormente inseridas no sistema para essa venda. 
  3 - As ofertas, uma vez introduzidas no sistema, não podem ser retiradas.            
         
   
     
                         
                          
  Artigo 24.º Resultado do leilão
                            
                           
                             
                               
                             
     O resultado do leilão eletrónico é disponibilizado no sítio da Internet de acesso público a que se refere o n.º 1 do artigo 21.º            
         
   
     
                         
                          
  Artigo 25.º Falta de pagamento do preço
                            
                           
                             
                               
                             
     À falta de pagamento do preço no prazo legal é aplicável o disposto no artigo 825.º do Código de Processo Civil, devendo as condições de pagamento ser definidas nas regras do sistema.            
         
   
     
                         
                          
  Artigo 26.º Adjudicação dos bens
                            
                           
                             
                               
                             
     1 - Compete ao agente de execução a decisão de adjudicação dos bens. 
  2 - Os direitos ou deveres legalmente previstos podem ser exercidos até ao momento da adjudicação.            
         
   
     
                         
                          
  SUBSECÇÃO III 
  Venda em depósito público ou equiparado  Artigo 27.º 
Depósito público e depósito equiparado a depósito público
                            
                           
                             
                               
                             
     1 - Por depósito público entende-se qualquer local de armazenagem de bens que tenha sido afeto, por despacho do diretor-geral da Direção-Geral da Administração da Justiça, à remoção e depósito de bens penhorados no âmbito de um processo executivo. 
  2 - Por depósito equiparado a depósito público entende-se qualquer local de armazenagem de bens que tenha sido afeto por um agente de execução à remoção e depósito de bens penhorados no âmbito de um processo executivo e cuja propriedade, arrendamento ou outro título que lhe confira a utilização do local ou dos serviços de armazenagem seja registado por via eletrónica junto da Câmara dos Solicitadores, nos termos da alínea o) do n.º 1 do artigo 123.º do Estatuto da Câmara dos Solicitadores. 
  3 - Cada depósito público ou equiparado deve ter disponível para consulta, por qualquer interessado, os seguintes elementos: 
  a) A identificação do proprietário ou arrendatário do imóvel que integra o depósito ou do titular de outro direito que lhe confira a utilização do local ou dos serviços de armazenagem; 
  b) Número de código da certidão permanente de registo predial que permita, através d','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a Internet, verificar a situação registal do imóvel que integra o depósito público; 
  c) Morada do depósito; 
  d) Identificação da apólice do seguro em vigor devido pelo imóvel e do seu período de vigência; 
  e) Nos casos em que o imóvel que integra o depósito é arrendado, a indicação do período de duração do contrato de arrendamento ou do contrato que confira a utilização do local ou dos serviços de armazenagem e condições de prorrogação, modificação ou revogação do mesmo. 
  4 - O Ministério da Justiça disponibiliza, em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt, e faculta à Ordem dos Solicitadores e dos Agentes de Execução para publicitação em página informática de acesso público, no sítio oficial da Ordem, uma lista dos depósitos públicos que contém e, em relação a cada depósito, a informação constante do número anterior.
  5 - A Ordem dos Solicitadores e dos Agentes de Execução disponibiliza, em página informática de acesso público, no sítio oficial da Ordem, e faculta ao Ministério da Justiça para publicitação em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt, uma lista dos depósitos equiparados a depósitos públicos registados nos termos do n.º 2 que contém, em relação a cada depósito, a informação constante do n.º 3.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 28.º Bens sujeitos a remoção para depósito público
                            
                           
                             
                               
                             
     1 - Salvo disposição em contrário, podem ser removidos para depósito público os seguintes bens: 
  a) Bens móveis não sujeitos a registo; 
  b) Bens móveis sujeitos a registo, quando seja necessária ou conveniente a sua remoção efetiva, desde que a natureza do bem não seja incompatível com a estrutura do armazém. 
  2 - Quando o bem seja removido para depósito público, deve ser entregue ao agente de execução um documento que sirva de título de depósito e que este deve notificar, preferencialmente por meios eletrónicos, ao exequente e ao executado. 
  3 - O título de depósito constitui prova do depósito dos bens e contém os seguintes elementos: 
  a) Identificação dos bens penhorados, podendo ser emitido um só título quando sejam penhorados vários bens ao mesmo executado por conta do mesmo processo, desde que se discriminem os respetivos bens; 
  b) Descrição elementar dos bens penhorados com indicação do seu valor aproximado ou estimado. 
  4 - Atenta a especial natureza dos bens penhorados ou o seu diminuto valor económico, a Direção-Geral da Administ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ração da Justiça pode rejeitar, desde que fundamentadamente, a sua remoção para depósito público.            
         
   
     
                         
                          
  Artigo 29.º Bens sujeitos a remoção para depósito equiparado a depósito público
                            
                           
                             
                               
                             
     1 - Salvo disposição em contrário, podem ser removidos para depósito equiparado a depósito público os bens referidos no n.º 1 do artigo anterior, quando penhorados no âmbito de uma execução em que o agente de execução titular do depósito é o agente de execução designado. 
  2 - Quando o bem seja removido para depósito equiparado a depósito público, o agente de execução titular do depósito deve produzir um título nos termos dos n.os 2 e 3 do artigo anterior, que deve notificar, preferencialmente por meios eletrónicos, ao exequente e ao executado.            
         
   
     
                         
                          
  Artigo 30.º Preço pela utilização do depósito público ou equiparado
                            
                           
                             
                               
                             
     1 - Pelo depósito de qualquer bem é devido o pagamento do preço ao depositário. 
  2 - O preço devido pela utilização do depósito público ou equiparado é fixado em 0,0075 UC por metro quadrado ou metro cúbico, consoante os casos, por cada dia de utilização. 
  3 - Ao preço devido pela ocupação do depósito público ou equiparado podem acrescer despesas extraordinárias de manutenção ou seguros especiais, quando existam e sejam justificadas em face da especial natureza dos bens penhorados. 
  4 - Os custos referidos nos números anteriores são imediatamente suportados pelo exequente, a título de encargos, sendo posteriormente imputados na conta de custas nos termos gerais. 
  5 - O exequente deve provisionar o agente de execução ou o tribunal, caso as diligências de execução sejam promovidas por oficial de justiça, com um valor equivalente a três meses de depósito, sem prejuízo do reforço sempre que esse prazo venha a ser ultrapassado. 
  6 - Antes da remoção de qualquer bem para depósito público ou equiparado, o agente de execução deve dar conhecimento ao exequente e ao executado dos preços praticados pelo depositário, nos termos dos n.os 2 e 3, podendo qualquer um destes opor-se a tal remoção, desde que indique outro depositário idóneo. 
  7 - Quando o exequente beneficie de apoio judiciário ou quando se verifique alguma forma de isenção do pagamento de custas, os bens só podem ser removidos para depósito público ou equiparado quando necessário, sendo o respetivo modo de pagamento fixado no regime do acesso ao direito.            
         
   
     
                         
                          
  Artigo 31.º Momento da venda
                            
                           
     ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                        
                               
                             
     1 - São vendidos os bens que se encontrem em depósito público ou equiparado assim que a venda seja processualmente possível, desde que a execução não se encontre suspensa. 
  2 - Mesmo que a execução se encontre suspensa, são logo vendidos os bens que se encontrem dentro das condições referidas no artigo 814.º do Código de Processo Civil. 
  3 - Cabe ao depositário disponibilizar aos agentes de execução, por escrito ou em formato eletrónico que permita um registo temporário da informação, todas as informações relativas à periodicidade das vendas, datas em que devem ser realizadas e modo de realização de cada venda. 
  4 - Cabe ao agente de execução informar o depositário, por escrito ou em formato eletrónico que permita um registo temporário da informação, dos bens que devem ser vendidos e o respetivo valor base.            
         
   
     
                         
                          
  Artigo 32.º Modalidades da venda em depósito público ou equiparado
                            
                           
                             
                               
                             
     1 - A venda em depósito público ou equiparado só pode ser realizada mediante: 
  a) Regime de leilão eletrónico; 
  b) Regime de leilão; 
  c) Negociação particular; 
  d) Venda direta a pessoas ou entidades que tenham um direito reconhecido a adquirir os bens. 
  2 - Os bens removidos para depósito público ou equiparado são preferencialmente vendidos em leilão eletrónico. 
  3 - Frustrada a venda em leilão eletrónico os bens são colocados em venda na modalidade de leilão. 
  4 - Frustrada a venda em leilão eletrónico e a venda na modalidade de leilão os bens podem ser vendidos mediante negociação particular. 
  5 - As regras relativas às modalidades de venda previstas nos artigos 811.º e seguintes do Código de Processo Civil aplicam-se às modalidades aqui previstas em tudo o que não esteja especialmente regulado.            
         
   
     
                         
                          
  Artigo 33.º Modo de realização da venda em leilão
                            
                           
                             
                               
                             
     1 - A venda deve ser realizada em local aberto ao público, preferencialmente no próprio local do depósito, salvo se a natureza da venda ou dos bens aconselhar algum outro local específico. 
  2 - Independentemente da modalidade e modo de realização da venda, esta deve ser sempre publicitada, para além dos termos previstos no n.º 2 do artigo 836.º do Código de Processo Civil, na página eletrónica do depositário. 
  3 - Sempre que possível, a venda deve realizar-se na presença do agente de execução. 
  4 - Os potenciais interessados têm o direito de inspecionar os bens a vender, no local onde estes se encontrem, entre a data de publicitação e a data de','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' realização da venda.            
         
   
     
                         
                          
  Artigo 34.º Venda periódica em leilão
                            
                           
                             
                               
                             
     1 - Semanal ou mensalmente, quando o volume de bens o aconselhe, o depositário organiza vendas periódicas em regime de leilão. 
  2 - É aplicável à venda em regime de leilão o disposto no n.º 2 do artigo 816.º do Código de Processo Civil. 
  3 - Os interessados na aquisição de bens devem inscrever-se junto do depositário até ao início da realização da venda. 
  4 - Após identificação de cada bem ou lote de bens, é concedida aos presentes a possibilidade de apresentação verbal de propostas de aquisição em regime de leilão. 
  5 - O bem ou lote de bens é vendido ao proponente que apresente a proposta mais elevada, devendo o valor em causa ser imediatamente entregue ao agente de execução, ao depositário ou ao seu representante. 
  6 - Caso o agente de execução não esteja presente, deve definir previamente as condições de aceitação da venda e entregá-las ao depositário. 
  7 - Se a venda for realizada nos termos das condições de aceitação definidas pelo agente de execução, esta fica definitivamente realizada, devendo o bem vendido ser entregue ao adquirente e o preço ser entregue pelo depositário ao agente de execução no prazo máximo de dois dias úteis. 
  8 - Se a venda não for realizada nos termos das condições de aceitação definidas pelo agente de execução, esta deve ser-lhe comunicada imediatamente para que este manifeste o seu acordo ou oposição no prazo de vinte e quatro horas. 
  9 - Quando o agente der o seu acordo, fica a venda definitivamente realizada, devendo o preço ser entregue ao agente de execução no prazo máximo de dois dias úteis. 
  10 - Os bens vendidos são entregues ao adquirente, tendo sido pago o preço, até cinco dias após a comunicação ao depositário do acordo do agente de execução.            
         
   
     
                         
                          
  Artigo 35.º Ata
                            
                           
                             
                               
                             
     Do resultado da venda é lavrada ata, que é sempre assinada pelo agente de execução responsável pelo processo onde foram penhorados os bens, pelo adquirente e pelo depositário.            
         
   
     
                         
                          
CAPÍTULO IV 
  Agente de execução 
  SECÇÃO I 
  Não aceitação, identificação, substituição e destituição do agente de execução  Artigo 36.º Notificação da designação e declaração de não aceitação
                            
                           
                             
                               
                             
     1 - O agente de execução designado é notificado da designação, por via eletrónica, através do sist','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ema informático de suporte à atividade dos agentes de execução. 
  2 - O agente de execução tem cinco dias após a notificação para declarar que não aceita a designação, nos termos do n.º 8 do artigo 720.º do Código de Processo Civil. 
  3 - A não aceitação da designação pelo agente de execução é efetuada no sistema informático de suporte à atividade dos agentes de execução e imediatamente notificada ao mandatário judicial da parte que procedeu à designação, mediante aviso gerado pelo sistema informático de suporte à atividade dos tribunais. 
  4 - Se o exequente não designar agente de execução substituto no prazo de cinco dias, é designado um agente de execução, por meios eletrónicos, de forma aleatória e automática, nos termos do artigo 720.º do Código de Processo Civil. 
  5 - O disposto no presente artigo é aplicável, com as necessárias adaptações, à delegação de processos ou atos entre agentes de execução.            
         
   
     
                         
                          
  Artigo 37.º Identificação do agente de execução
                            
                           
                             
                               
                             
     Na prática de diligências junto do executado, de organismos oficiais ou de terceiros, o agente de execução designado no processo identifica-se com o cartão de agente de execução e um comprovativo impresso, emitido pelo sistema informático de suporte à atividade dos agentes de execução, o qual contém os seguintes elementos: 
  a) O número do processo; 
  b) O tribunal competente; 
  c) O valor do processo; 
  d) O nome de exequente; 
  e) A morada do exequente; 
  f) O nome do executado; 
  g) A morada do executado; 
  h) A data de impressão; 
  i) O nome do agente de execução; 
  j) O número da cédula do agente de execução; 
  k) O domicílio profissional do agente de execução.            
         
   
     
                         
                          
  Artigo 38.º Substituição do agente de execução pelo exequente
                            
                           
                             
                               
                             
     1 - A substituição do agente de execução pelo exequente e a exposição do respetivo motivo, prevista na primeira parte do n.º 4 do artigo 720.º do Código de Processo Civil, é efetuada pelas seguintes formas: 
  a) Quando apresentada por via eletrónica, através de formulário próprio disponibilizado no sistema informático de suporte à atividade dos tribunais; 
  b) Quando apresentada em suporte físico, pelos restantes meios legalmente previstos para a prática de atos. 
  2 - O agente de execução é notificado da substituição promovida pelo exequente através do sistema informático de suporte à atividade dos agentes de execução. 
  3 - A substituição do agente de execução, nos termos dos números anteriores, implica a designação de agente de execução substituto nos termos do n.º 1, que, não sen','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('do efetuada pelo exequente aquando da apresentação da substituição, é realizada por meios eletrónicos, de forma aleatória e automática, nos termos do n.º 2 do artigo 720.º do Código de Processo Civil. 
  4 - O agente de execução substituto é notificado da substituição através do sistema informático de suporte à atividade dos agentes de execução. 
  5 - Se o agente de execução substituto declarar que não aceita a designação nos termos do artigo 36.º, é designado imediatamente novo agente de execução substituto nos termos do n.º 2 do artigo 720.º do Código de Processo Civil. 
  6 - Os elementos previstos no n.º 2 do artigo 129.º do Estatuto da Câmara dos Solicitadores, juntamente com a nota discriminativa de honorários e despesas, são entregues ao agente de execução substituto pelo agente de execução substituído no prazo de cinco dias após o pedido de entrega desses elementos pelo agente de execução substituto. 
  7 - Cabe ao agente de execução substituto notificar o exequente da nota discriminativa apresentada pelo agente de execução substituído, devendo aquele observar o disposto no artigo 721.º do Código de Processo Civil.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 45/2013, de 28 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 39.º Substituição do agente de execução por outras razões
                            
                           
                             
                               
                             
     1 - A Câmara dos Solicitadores notifica, em simultâneo, o tribunal, por via eletrónica e automática, e o exequente, preferencialmente por via eletrónica, sempre que tiver conhecimento da morte, da incapacidade definitiva ou da cessação das funções do agente de execução. 
  2 - A Comissão para a Eficácia das Execuções notifica, em simultâneo, o tribunal, por via eletrónica e automática, e o exequente, preferencialmente por via eletrónica, sempre que aplicar pena de suspensão por período superior a 10 dias ou de expulsão ao agente de execução. 
  3 - A designação, pelo exequente, do agente de execução substituto, prevista no n.º 1 do artigo 129.º do Estatuto da Câmara dos Solicitadores é apresentada, nos termos do n.º 1 do artigo anterior. 
  4 - Se a designação não for efetuada no prazo de cinco dias a contar da receção da notificação pelo tribunal ou o agente de execução substituto declarar que não aceita a designação nos termos do artigo 36.º, é designado agente de execução substituto nos termos do n.º 2 do artigo 720.º do Código de Processo Civil. 
  5 - O agente de execução substituto é notificado da substituição através do sistema informático de suporte à atividade dos agentes de execução. 
  6 - Os elementos previstos no n.º 2 do artigo 129.º do Estatuto da Câmara dos Solicitadores são entregues ao agente de execução substituto ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pela Câmara dos Solicitadores, nos casos previstos no n.º 1, e pela Comissão para a Eficácia das Execuções, nos casos previstos no n.º 2.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 45/2013, de 28 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 40.º Destituição
                            
                           
                             
                               
                             
     1 - A Comissão para a Eficácia das Execuções notifica, em simultâneo, o tribunal, por via eletrónica e automática, e o exequente, preferencialmente por via eletrónica, sempre que destituir o agente de execução, produzindo a destituição efeitos na data de comunicação. 
  2 - Em caso de destituição, o exequente pode designar agente de execução substituto, nos termos do n.º 1 do artigo 38.º 
  3 - Se a designação não for efetuada no prazo de cinco dias a contar da notificação pela Comissão para a Eficácia das Execuções ou o agente de execução substituto declarar que não aceita a designação nos termos do artigo 36.º, é designado agente de execução substituto nos termos do n.º 2 do artigo 720.º do Código de Processo Civil. 
  4 - O agente de execução substituto é notificado da substituição através do sistema informático de suporte à atividade dos agentes de execução. 
  5 - Os elementos previstos no n.º 2 do artigo 129.º do Estatuto da Câmara dos Solicitadores são entregues ao agente de execução substituto pelo agente de execução destituído no prazo de cinco dias após o pedido de entrega desses elementos pelo agente de execução substituto ou, caso aquele não o faça, pela Comissão para a Eficácia das Execuções.            
         
   
     
                         
                          
  Artigo 41.º 
Lista de agentes de execução
                            
                           
                             
                               
                             
     1 - Para efeitos de publicitação, a Câmara dos Solicitadores disponibiliza uma lista informática que contém a informação relativa aos agentes de execução inscritos ou registados na Câmara dos Solicitadores, pesquisável por comarca. 
  2 - A lista de agentes de execução contém a informação referida no n.º 3 do artigo 2.º 
  3 - A lista de agentes de execução é disponibilizada em página informática de acesso público, no sítio oficial da Ordem dos Solicitadores e dos Agentes de Execução e em página informática de acesso público, na Área de Serviços Digitais dos Tribunais, acessível no endereço eletrónico https://tribunais.org.pt.
  4 - A lista de agentes de execução é publicada de modo a não ser possível a sua indexação a motores de busca.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Portaria n.º 267/2018, de 20 de Setembro
  Versões anteri','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
SECÇÃO II 
  Dever de informação e comunicação  Artigo 42.º Conteúdo do dever de informação e comunicação
                            
                           
                             
                               
                             
     1 - O sistema informático de suporte à atividade dos agentes de execução assegura a disponibilização ao exequente, através do sistema informático de suporte à atividade dos tribunais, no endereço http://citius.tribunaisnet.mj.pt, de informação sobre: 
  a) O resultado das diligências prévias à penhora, previstas nos artigos 748.º e 749.º do Código de Processo Civil; 
  b) Todas as demais diligências efetuadas pelo agente de execução ou sob sua responsabilidade; 
  c) O motivo de frustração da penhora. 
  2 - Nos casos em que o requerimento executivo é apresentado nos termos do artigo 3.º, a informação é prestada através das seguintes formas: 
  a) As informações referidas nas alíneas a) e c) do número anterior são oficiosamente notificadas ao exequente por carta registada no prazo de cinco dias após a obtenção da última informação ou a pedido do exequente, preferencialmente por via eletrónica, cinco dias após a receção do pedido; 
  b) As informações referidas na alínea b) do número anterior são transmitidas ao exequente, a seu pedido, preferencialmente por via eletrónica, cinco dias após a receção do pedido. 
  3 - As informações prestadas nos termos do n.º 1 não são consideradas, para efeitos de remuneração, como notificações ou comunicações.            
         
   
     
                         
                          
SECÇÃO III 
  Remuneração do agente de execução 
  SUBSECÇÃO I 
  Disposições gerais  Artigo 43.º Honorários e reembolso de despesas
                            
                           
                             
                               
                             
     O agente de execução tem direito a receber honorários pelos serviços prestados, bem como a ser reembolsado das despesas que realize e que comprove devidamente, nos termos da presente portaria.            
         
   
     
                         
                          
  Artigo 44.º Dever de informação e de registo
                            
                           
                             
                               
                             
     1 - O exequente, o executado, a Câmara dos Solicitadores, o tribunal e qualquer terceiro que tenha um interesse legítimo no processo têm direito a ser informados, preferencialmente por via eletrónica, sobre a conta corrente discriminada do processo. 
  2 - O agente de execução deve manter, no sistema informático de suporte à atividade dos agentes de execução, a conta corrente do processo discriminada permanentemente atualizada. 
  3 - Na conta corrente discriminada do processo são in','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cluídas as despesas previsíveis para a conclusão do processo, designadamente as resultantes de cancelamentos de registos. 
  4 - É assegurada às partes a disponibilização, através do sistema informático de suporte à atividade dos agentes de execução, do acesso à conta corrente discriminada dos processos em que sejam intervenientes. 
  5 - O agente de execução deve informar o exequente, no início do processo, e o executado, no ato da citação, do montante provável dos seus honorários e despesas, devendo tal informação ser registada no sistema informático de suporte à atividade dos agentes de execução e constar do processo. 
  6 - O registo dos atos que não são praticados através do sistema informático de suporte à atividade dos agentes de execução, designadamente os atos externos, deve ser efetuado, no referido sistema, até ao termo do 2.º dia útil seguinte ao da prática do ato, sob pena de o agente de execução não poder ser reembolsado das despesas relativas ao ato realizado. 
  7 - É disponibilizado, pela Câmara dos Solicitadores, um simulador de honorários e despesas dos agentes de execução, com valor meramente informativo, em página informática de acesso público, no sítio oficial da Câmara dos Solicitadores.            
         
   
     
                         
                          
  Artigo 45.º Pagamento de honorários e reembolso de despesas
                            
                           
                             
                               
                             
     1 - Nos casos em que o pagamento das quantias devidas a título de honorários e despesas do agente de execução não possa ser satisfeito através do produto dos bens penhorados ou pelos valores depositados à ordem do agente de execução decorrentes do pagamento voluntário, integral ou em prestações, realizados através do agente de execução, os honorários devidos ao agente de execução e o reembolso das despesas por ele efetuadas, bem como os débitos a terceiros a que a venda executiva dê origem, são suportados pelo autor ou exequente, podendo este reclamar o seu reembolso ao réu ou executado. 
  2 - O autor ou exequente que, por sua iniciativa, requeira ao agente de execução a prática de atos não compreendidos na remuneração fixa prevista na tabela do anexo VII da presente portaria é exclusivamente responsável pelo pagamento dos honorários e despesas incorridas com a prática dos mesmos, não podendo reclamar o seu pagamento ao executado exceto quando os atos praticados atinjam efetivamente o seu fim. 
  3 - No caso previsto na parte final do número anterior, o executado apenas é responsável pelo pagamento dos atos que efetivamente atingiram o seu fim. 
  4 - O agente de execução que, por sua iniciativa, pratique atos desnecessários, inúteis ou dilatórios, é responsável pelos mesmos, não podendo reclamar a qualquer das partes o pagamento de honorários ou despesas incorridas em virtude da sua prática.            
         
   
     
                    ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
                          
  Artigo 46.º Reclamação da nota de honorários e despesas
                            
                           
                             
                               
                             
     Qualquer interessado pode, no prazo de 10 dias contados da notificação da nota discriminativa de honorários e despesas, apresentar reclamação ao juiz, com fundamento na desconformidade com o disposto na presente portaria.            
         
   
     
                         
                          
  Artigo 47.º Fases do processo executivo
                            
                           
                             
                               
                             
     1 - Para efeitos de adiantamento de honorários e despesas ao agente de execução, o processo executivo para pagamento de quantia certa compreende as seguintes fases: 
  a) Fase 1, que se inicia com o pagamento da respetiva provisão e inclui os atos necessários à verificação da regularidade do título executivo, consulta ao registo informático das execuções e às bases de dados de consulta direta eletrónica para apuramento de bens penhoráveis, terminando com a notificação do exequente para proceder ao pagamento da provisão dos honorários da fase 2 ou da fase 3; 
  b) Fase 2, que se inicia com o pagamento da respetiva provisão e inclui a citação prévia do executado, quando a lei assim o imponha, ou a citação do executado para a indicação de bens à penhora, quando não sejam identificados bens penhoráveis, terminando com a notificação do exequente para proceder ao pagamento dos honorários da fase 3 ou com a extinção do processo; 
  c) Fase 3, que se inicia com o pagamento da respetiva provisão e inclui as diligências de penhora, bem como as citações que tenham lugar após a realização da penhora, terminando com a notificação do exequente para proceder ao pagamento dos honorários da fase 4; 
  d) Fase 4, que se inicia com o pagamento da respetiva provisão e inclui as diligências de venda, liquidação e pagamento, terminando com a extinção do processo. 
  2 - Salvo nos casos excecionais previstos na lei, o exequente deve, por via eletrónica: 
  a) Pagar, com a entrega do requerimento executivo, o montante correspondente à fase 1; 
  b) Pagar, finda cada uma das fases, o montante respeitante à fase subsequente. 
  3 - Os montantes a que se refere o n.º 1 são os fixados na tabela do anexo VI da presente portaria, podendo o agente de execução solicitar reforço de provisão nos casos em que o exequente requeira a realização de atos que ultrapassem os limites previstos na tabela do anexo VII da presente portaria. 
  4 - Para efeitos de reforço de provisão, o agente de execução apresenta ao exequente conta corrente discriminada dos atos já realizados. 
  5 - Se o valor da provisão for superior ao valor dos honorários e despesas efetivamente devido no final da respetiva fase, o excesso reverte para a fase subsequente. 
  6 - Em cas','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o de substituição do agente de execução ou extinta a execução: 
  a) Não é reembolsável o montante correspondente à fase 1; 
  b) É reembolsável o montante provisionado nas restantes fases que exceda o valor dos honorários e despesas efetivamente devido. 
  7 - Para efeitos de adiantamento de honorários e despesas ao agente de execução, as execuções para entrega de coisa certa ou para prestação de facto apenas têm uma fase, cujo montante se encontra fixado na tabela do anexo VI da presente portaria e deve ser pago pelo exequente, por via eletrónica, com a entrega do requerimento executivo.            
         
   
     
                         
                          
  Artigo 48.º Obrigações do agente de execução quanto à verba provisionada
                            
                           
                             
                               
                             
     1 - Sempre que o agente de execução receba a provisão, deve emitir recibo do qual constem as quantias recebidas e os atos a que as mesmas dizem respeito. 
  2 - Todas as importâncias devidas ao agente de execução a título de adiantamento de honorários e despesas são pagas com base em identificador único de pagamento emitido através do sistema informático de suporte à atividade dos agentes de execução, sendo as mesmas depositadas na conta-cliente do exequente e a operação de depósito obrigatoriamente registada no sistema informático de suporte à atividade dos agentes de execução.            
         
   
     
                         
                          
  Artigo 49.º Unidade de expressão dos valores
                            
                           
                             
                               
                             
     1 - Os montantes fixados pela presente portaria encontram-se expressos em unidades de conta processuais (UC), se o contrário não resultar da norma. 
  2 - A unidade de conta é fixada nos termos do disposto no artigo 22.º do Decreto-Lei n.º 34/2008, de 26 de fevereiro, alterado pela Lei n.º 43/2008, de 27 de agosto, pelo Decreto-Lei n.º 181/2008, de 28 de agosto, pelas Leis n.os 64-A/2008, de 31 de dezembro, e 3-B/2010, de 28 de abril, pelo Decreto-Lei n.º 52/2011, de 13 de abril, e pelas Leis n.os 7/2012, de 13 de fevereiro, e 66-B/2012, de 31 de dezembro.            
         
   
     
                         
                          
SUBSECÇÃO II 
  Honorários  Artigo 50.º Honorários do agente de execução
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto nos n.os 2 a 4, o agente de execução tem direito a ser remunerado pela tramitação dos processos, atos praticados ou procedimentos realizados de acordo com os valores fixados na tabela do anexo VII da presente portaria, os quais incluem a realização dos atos necessários com os limites nela previstos. 
  2 - Nos p','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rocessos executivos para pagamento de quantia certa em que não haja lugar a citação prévia do executado e se verifique após a consulta às bases de dados que não existem bens penhoráveis ou que o executado foi declarado insolvente, caso o exequente desista da instância no prazo de 10 dias contados da notificação do resultado das consultas apenas é devido ao agente de execução o pagamento de 0,75 UC. 
  3 - Quando o exequente requeira a realização de atos que ultrapassem os limites previstos nos pontos 1 e 2 da tabela do anexo VII da presente portaria, são devidos pelo exequente pela realização dos novos atos os seguinte valores: 
  a) 0,25 UC por citação ou notificação sob forma de citação por via postal, efetivamente concretizada; 
  b) 0,05 UC por notificação por via postal ou citação eletrónica; 
  c) 0,5 UC por ato externo concretizado (designadamente, penhora, citação, afixação de edital, apreensão de bem, assistência a abertura de propostas no tribunal); 
  d) 0,25 UC por ato externo frustrado. 
  4 - Nos processos executivos para pagamento de quantia certa, quando haja lugar à entrega coerciva de bem ao adquirente, o agente de execução tem direito ao pagamento de 1 UC, a suportar pelo adquirente, que poderá reclamar o seu reembolso ao executado. 
  5 - Nos processos executivos para pagamento de quantia certa, no termo do processo é devida ao agente de execução uma remuneração adicional, que varia em função: 
  a) Do valor recuperado ou garantido; 
  b) Do momento processual em que o montante foi recuperado ou garantido; 
  c) Da existência, ou não, de garantia real sobre os bens penhorados ou a penhorar. 
  6 - Para os efeitos do presente artigo, entende-se por: 
  a) Valor recuperado o valor do dinheiro restituído, entregue, o do produto da venda, o da adjudicação ou o dos rendimentos consignados, pelo agente de execução ao exequente ou pelo executado ou terceiro ao exequente; 
  b) Valor garantido o valor dos bens penhorados ou o da caução prestada pelo executado, ou por terceiro ao exequente, com o limite do montante dos créditos exequendos, bem como o valor a recuperar por via de acordo de pagamento em prestações ou de acordo global. 
  7 - O agente de execução tem ainda direito a receber dos credores reclamantes uma remuneração adicional pelos valores que foram recuperados pelo pagamento ou adjudicação a seu favor. 
  8 - Em caso de incumprimento do acordo de pagamento em prestações ou do acordo global, a comunicar pelo exequente, o agente de execução elabora a nota discriminativa de honorários e despesas atualizada tendo em consideração o valor efetivamente recuperado, afetando o excesso recebido a título de pagamento de honorários e despesas ao pagamento das quantias que venham a ser devidas, sem prejuízo de, no termo do processo, restituir ao exequente o saldo a que este tenha direito. 
  9 - O cálculo da remuneração adicional efetua-se nos termos previstos na tabela do anexo VIII da presente portaria, sem prejuízo do disposto nos n','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('úmeros seguintes. 
  10 - Nos casos em que, na sequência de diligência de penhora de bens móveis do executado seguida da sua citação seja recuperada ou garantida a totalidade dos créditos em dívida o agente de execução tem direito a uma remuneração adicional mínima de 1 UC, quando o valor da remuneração adicional apurada nos termos previstos na tabela do anexo VIII seja inferior a esse montante. 
  11 - O valor da remuneração adicional apurado nos termos da tabela do anexo VIII é reduzido a metade na parte que haja sido recuperada ou garantida sobre bens relativamente aos quais o exequente já dispusesse de garantia real prévia à execução. 
  12 - Nos processos executivos para pagamento de quantia certa em que haja lugar a citação prévia, se o executado efetuar o pagamento integral da quantia em dívida até ao termo do prazo para se opor à execução não há lugar ao pagamento de remuneração adicional. 
  13 - Havendo lugar à sustação da execução nos termos do artigo 794.º do Código de Processo Civil e recuperação de montantes que hajam de ser destinados ao exequente do processo sustado, o agente de execução do processo sustado e o agente de execução do processo onde a venda ocorre devem repartir entre si o valor da remuneração adicional, na proporção do trabalho por cada qual efetivamente realizado nos respetivos processos. 
  14 - Nos casos de delegação para a prática de ato determinado, e salvo acordo em contrário entre os agentes de execução, o agente de execução delegado tem direito ao pagamento, a efetuar pelo agente de execução delegante, de 0,75 UC por ato externo realizado. 
  15 - Havendo substituição do agente de execução, que não resulte de falta que lhe seja imputável ou de delegação total do processo, o agente de execução substituído e o substituto devem repartir entre si o valor da remuneração adicional, na proporção do trabalho por cada qual efetivamente realizado no processo. 
  16 - Em caso de conflito, entre os agentes de execução, na repartição do valor da remuneração adicional, a Câmara dos Solicitadores designa um árbitro para a resolução do mesmo.            
         
   
     
                         
                          
  Artigo 51.º Pagamento
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto nos números seguintes, os honorários referidos no artigo anterior são pagos ao agente de execução no termo do processo ou procedimento, ou quando seja celebrado entre as partes acordo de pagamento em prestações. 
  2 - Nas execuções para entrega de coisa certa e para prestação de facto, os honorários são pagos imediatamente antes da entrega da coisa devida ou da prestação do facto. 
  3 - Quando a entrega da coisa ou a prestação do facto não sejam realizados por facto não imputável ao agente de execução, apenas é devido o pagamento de 1 UC, a qual acresce ao montante da provisão inicialmente paga.  ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('          
         
   
     
                         
                          
  SUBSECÇÃO III 
  Despesas  Artigo 52.º 
Despesas do agente de execução
                            
                           
                             
                               
                             
     1 - O agente de execução tem direito a ser reembolsado das despesas necessárias à realização das diligências efetuadas no exercício das funções de agente de execução, desde que devidamente comprovadas. 
  2 - Excetuam-se do disposto no número anterior as despesas necessárias à realização das diligências efetuadas durante a fase 1 do processo executivo, bem como as despesas de deslocação que não observem o disposto no n.º 4. 
  3 - Podem ser cobradas despesas de deslocação, tendo por base os critérios estabelecidos no artigo 54.º, se o agente de execução designado pelo exequente praticar atos a mais de 50 km do tribunal da sua comarca e, cumulativamente: 
  a) O exequente for previamente informado, preferencialmente por via eletrónica: 
  i) Do custo provável da deslocação; 
  ii) De que, sendo o ato praticado por agente de execução da comarca em causa, não há lugar a pagamento de tais despesas; e 
  iii) De que as despesas de deslocação são da sua exclusiva responsabilidade, não podendo ser exigido ao executado o reembolso das mesmas; 
  b) O exequente aceitar expressamente a cobrança da deslocação. 
  4 - Para os efeitos do n.º 1, consideram-se despesas comprovadas as que sejam lançadas, de forma automática, pelo sistema informático de suporte à atividade dos agentes de execução na conta corrente do processo, nomeadamente as que resultem de registos de penhora eletrónica, expedição de correio, notificações eletrónicas, transferências e pagamentos eletrónicos.
  5 - As faturas das despesas relativas a comissões e serviços bancários são emitidas em nome do exequente, pela entidade que presta o serviço, mediante indicação do agente de execução efetuada através do sistema informático de suporte à respetiva atividade, no qual essas faturas devem ficar disponibilizadas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 45/2013, de 28 de Outubro   - Portaria n.º 239/2020, de 12 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto    - 2ª versão: Retificação n.º 45/2013, de 28 de Outubro   
     
                         
                          
SUBSECÇÃO IV 
  Caixa de compensações  Artigo 53.º Afetação de verbas
                            
                           
                             
                               
                             
     1 - Para os efeitos do disposto no n.º 1 do artigo 127.º do Estatuto da Câmara dos Solicitadores as receitas da caixa de compensações são constituídas por uma permilagem de 75 (75(por mil) do montante correspondente a 1 UC. 
  2 - A cobrança das verbas a afetar à caixa de compensações','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' efetua-se com o pagamento do montante correspondente à fase 1 referida na alínea a) do n.º 1 do artigo 47.º, sendo as mesmas deduzidas pela Câmara dos Solicitadores ao valor pago pelo exequente ao agente de execução. 
  3 - Os demais aspetos relativos à cobrança e gestão das verbas a afetar à caixa de compensações são definidos em regulamento da Câmara dos Solicitadores.            
         
   
     
                         
                          
  Artigo 54.º Compensação de deslocações
                            
                           
                             
                               
                             
     1 - O agente de execução tem direito a uma compensação pelas deslocações efetuadas para a realização de diligências que envolvam deslocações ao local, paga pela caixa de compensações, sempre que se verifiquem, cumulativamente, as seguintes condições: 
  a) O autor, requerente ou exequente não deva suportar as despesas pelas deslocações nos termos do disposto no n.º 3 do artigo 52.º; 
  b) O agente de execução tenha sido designado pela secretaria nos termos do artigo 720.º do Código de Processo Civil e a prática do ato envolva uma deslocação superior a 50 km e inferior a 400 km, calculadas as distâncias das viagens de ida e regresso pelo percurso mais curto entre o tribunal e a sede da junta da freguesia onde deva ser praticado o ato. 
  2 - O valor da compensação (C) devida pela caixa de compensações é calculada com base na seguinte fórmula: 
  C  (D x 2) - 50 x V 
  onde D corresponde à distância mais curta entre o tribunal da comarca do agente de execução e a sede da junta da freguesia onde deva ser praticado o ato e V corresponde ao valor devido por quilómetro. 
  3 - O valor devido por quilómetro é fixado pelo conselho geral da Câmara dos Solicitadores.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 45/2013, de 28 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Portaria n.º 282/2013, de 29 de Agosto   
     
                         
                          
  Artigo 55.º Verificação de distâncias
                            
                           
                             
                               
                             
     O agente de execução informa por via exclusivamente eletrónica e preferencialmente automática a Câmara dos Solicitadores sobre qual a distância percorrida, sem prejuízo de posterior revisão da mesma pela Câmara, nos termos de regulamento a aprovar pela Câmara dos Solicitadores.            
         
   
     
                         
                          
CAPÍTULO V 
  Acesso ao registo informático de execuções  Artigo 56.º Acesso direto através do sistema informático de suporte à atividade dos tribunais
                            
                           
                             
                               
                             
     1 - Os magistrados judi','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ciais e os magistrados do Ministério Público têm acesso direto ao registo informático de execuções através do sistema informático de suporte à atividade dos tribunais. 
  2 - Os agentes de execução acedem diretamente ao registo informático de execuções através do sistema informático de suporte à atividade dos agentes de execução. 
  3 - O acesso ao registo informático de execuções por pessoa capaz de exercer o mandato judicial efetua-se através do acesso à área reservada do sistema informático de suporte à atividade dos tribunais, de acordo com as instruções daí constantes.            
         
   
     
                         
                          
  Artigo 57.º Outras formas de acesso
                            
                           
                             
                               
                             
     O acesso ao registo informático de execuções por pessoa capaz de exercer o mandato judicial pode ser efetuado por certificado passado pela secretaria do tribunal nos termos dos n.os 2 a 5 do artigo 8.º do Decreto-Lei n.º 201/2003, de 10 de setembro.            
         
   
     
                         
                          
  Artigo 58.º Verificação e inserção de informação no registo informático de execuções
                            
                           
                             
                               
                             
     A inserção e atualização, pelo agente de execução, da informação constante do registo informático de execuções, efetua-se através do sistema informático de suporte à atividade do agente de execução, ficando a mesma disponível para consulta no sistema informático de suporte à atividade dos tribunais, com respeito pelas limitações à publicidade do processo constantes da alínea c) do n.º 2 do artigo 164.º do Código de Processo Civil.            
         
   
     
                         
                          
CAPÍTULO VI 
  Execuções promovidas por oficial de justiça  Artigo 59.º Desempenho das funções de agente de execução por oficial de justiça
                            
                           
                             
                               
                             
     1 - O disposto na presente portaria aplica-se às execuções em que caiba a oficial de justiça o desempenho das funções de agente de execução, com as devidas adaptações. 
  2 - Quando incumba a oficial de justiça a realização das diligências próprias da competência do agente de execução, compete ao escrivão de direito, titular da secção onde corre termos o processo de execução, realizar as mesmas. 
  3 - Nas faltas e impedimentos do escrivão de direito agente de execução aplica-se o regime da substituição previsto no Estatuto dos Funcionários da Justiça. 
  4 - O escrivão de direito agente de execução pode delegar a execução dos atos noutro oficial de justiça da mesma secção. 
  5 - Ao oficial de justiça agente de execução aplica-se o disposto ','702');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('no n.º 2 do artigo 118.º e nos artigos 127.º a 129.º do Código de Processo Civil, quanto a impedimentos e suspeições. 
  6 - As referências feitas na presente portaria ao sistema informático de suporte à atividade dos agentes de execução consideram-se feitas, nas execuções em que caiba a oficial de justiça o desempenho das funções de agente de execução, ao sistema informático de suporte à atividade dos tribunais. 
  7 - Não são aplicáveis ao oficial de justiça as disposições da presente portaria relativas a contas-clientes e a remuneração do agente de execução.            
         
   
     
                         
                          
CAPÍTULO VII 
  Disposições finais  Artigo 60.º Norma revogatória
                            
                           
                             
                               
                             
     São revogadas as seguintes portarias: 
  a) Portaria n.º 700/2003, de 31 de julho; 
  b)  Portaria n.º 946/2003, de 6 de setembro; 
  c)  Portaria n.º 331-B/2009, de 30 de março.            
         
   
     
                         
                          
  Artigo 61.º Norma transitória
                            
                           
                             
                               
                             
     Caso não tenha sido indicado um número de identificação bancária no requerimento executivo, o agente de execução solicita ao exequente a sua indicação no processo para efeitos de realização de pagamentos.            
         
   
     
                         
                          
  Artigo 62.º Aplicação no tempo
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no número seguinte, a presente portaria aplica-se aos processos pendentes à data da sua entrada em vigor. 
  2 - Os artigos 43.º a 55.º apenas se aplicam aos processos iniciados a partir da data de entrada em vigor da presente portaria, continuando a aplicar-se aos processos pendentes a essa data, em matéria de honorários e despesas dos agentes de execução pelo exercício das suas funções, o regime aplicável a 31 de agosto de 2013.            
         
   
     
                         
                          
  Artigo 63.º Entrada em vigor
                            
                           
                             
                               
                             
     A presente portaria entra em vigor no dia 1 de setembro de 2013. 
  
  A Ministra da Justiça, Paula Maria von Hafe Teixeira da Cruz, em 21 de agosto de 2013.            
         
   
     
                         
                          
  ANEXO I
                            
                           
                             
                               
                             
                 
         
